INSERT INTO public.englishchat_question_bank VALUES (1, 'ai-toeic-coca-bac40ef227e9d3e8', 'meeting', 'fill_blank', 'beginner', 'The manager wants to ____ a meeting this afternoon to discuss the new project.', '["hold", "talk", "stay", "wait"]', '[]', 'hold', '在商務英文中，「舉行會議」最常用的動詞搭配是 hold a meeting。其他選項如 talk (說話)、stay (停留)、wait (等待) 在此語境下不符合文法搭配或邏輯。', 'hold a meeting', '', '', '[]', 100, false, '2026-05-06 10:10:09.612975+08', '2026-05-07 08:31:36.56559+08');
INSERT INTO public.englishchat_question_bank VALUES (6, 'ai-toeic-coca-8795c67bf68b4d0e', 'meeting', 'reorder', 'advanced', 'Rearrange the following phrases to form a coherent sentence regarding a strategic decision in a business meeting.', '[]', '["is financially viable.", "budget constraints,", "re-evaluate whether", "Given the current", "proceeding with the expansion", "we need to"]', 'Given the current budget constraints, we need to re-evaluate whether proceeding with the expansion is financially viable.', '這句話使用了 ''Given the current...'' (鑒於目前的...) 作為句首片語來交代背景。''re-evaluate whether'' (重新評估是否) 是高階會議中討論策略調整的常見語塊。''financially viable'' (財務上可行) 為商務英語高階詞彙，指某項計畫在經濟層面上是否值得執行。', 'Given the current [noun phrase], [subject] + [verb] + whether [clause].', '', '', '[]', 100, false, '2026-05-06 10:10:47.440287+08', '2026-05-07 08:32:17.80206+08');
INSERT INTO public.englishchat_question_bank VALUES (7, 'ai-toeic-coca-eedc58ea3e06640c', 'meeting', 'fill_blank', 'beginner', 'The weekly team meeting will ____ at 10:00 AM in the conference room.', '["start", "starting", "started", "starts"]', '[]', 'start', '在助動詞 will 之後，必須接動詞原形（base form）。這句話的意思是「每週團隊會議將於上午 10:00 在會議室開始」。', 'will + [動詞原形]', '', '', '[]', 100, false, '2026-05-06 10:30:04.529379+08', '2026-05-07 08:31:36.56559+08');
INSERT INTO public.englishchat_question_bank VALUES (9, 'ai-toeic-coca-a7e77d2eeb9220c2', 'meeting', 'fill_blank', 'beginner', 'The meeting starts at 10:00, so please arrive ____.', '["early", "late", "slowly", "hardly"]', '[]', 'early', '這句話的意思是「會議在 10:00 開始，所以請早點到達」。early 表示「早地」，在此符合準時或提前到達的邏輯。late 是「晚地」，slowly 是「緩慢地」，hardly 是「幾乎不」，皆不符合句意。', 'arrive + adverb', '', '', '[]', 100, false, '2026-05-06 10:40:02.619988+08', '2026-05-07 08:31:36.56559+08');
INSERT INTO public.englishchat_question_bank VALUES (2, 'ai-toeic-coca-d1df329ec6c91305', 'meeting', 'fill_blank', 'intermediate', 'Due to a scheduling conflict, the department head has decided to ____ the weekly briefing until Thursday morning.', '["postpone", "cancel", "resume", "convene"]', '[]', 'postpone', '根據句意「由於行程衝突，部門主管決定將每週簡報____到週四早上」，空格後方有時間介系詞 ''until'' (直到)，表示將活動往後延期，因此選擇 ''postpone'' (延期) 最為合適。''cancel'' 為取消，''resume'' 為重新開始，''convene'' 為召集，皆不符合語境。', 'postpone + [something] + until/to + [time]', '', '', '[]', 100, false, '2026-05-06 10:10:14.790365+08', '2026-05-07 08:31:42.830556+08');
INSERT INTO public.englishchat_question_bank VALUES (8, 'ai-toeic-coca-9a66bd47b7cb430b', 'meeting', 'fill_blank', 'intermediate', 'Due to an unexpected scheduling conflict, we have no choice but to ____ the project update meeting until next Wednesday morning.', '["postpone", "cancel", "implement", "consult"]', '[]', 'postpone', '由於不可預見的行程衝突（scheduling conflict），我們別無選擇，只能將專案進度會議延期（postpone）至下週三早上。''postpone'' 是多益常考單字，意為「延期」，在商務情境中極為常見。其他選項：cancel（取消）、implement（執行/實施）、consult（諮詢）在語法或邏輯上與 ''until'' 的搭配不如 postpone 合適。', 'postpone + [event] + until + [time]', '', '', '[]', 100, false, '2026-05-06 10:30:11.554254+08', '2026-05-07 08:31:42.830556+08');
INSERT INTO public.englishchat_question_bank VALUES (3, 'ai-toeic-coca-637402f1f98d17a5', 'meeting', 'fill_blank', 'advanced', 'The final decision regarding the proposed merger has been ____ upon the board''s thorough review and approval of the revised financial projections.', '["contingent", "preliminary", "incidental", "subsequent"]', '[]', 'contingent', 'contingent upon 為商務英語中的常見片語，意為「視...而定」或「取決於...」。在此句中，表示合併的最終決定取決於董事會對財務預測的審核結果。其他選項：(B) preliminary 初步的；(C) incidental 附帶的；(D) subsequent 隨後的，語意皆不符。', 'be contingent upon/on something', '', '', '[]', 100, false, '2026-05-06 10:10:21.213232+08', '2026-05-07 08:31:49.193331+08');
INSERT INTO public.englishchat_question_bank VALUES (4, 'ai-toeic-coca-68a33259eee4f0af', 'meeting', 'reorder', 'beginner', 'Please put the following words in the correct order to form a sentence about the meeting schedule.', '[]', '["the", "meeting", "start", "at", "ten", "will"]', 'The meeting will start at ten.', '這句話描述會議開始的時間。主詞是 ''The meeting''，動詞使用未來式 ''will start''，後接介係詞 ''at'' 來引導具體時間 ''ten''。這是多益測驗中關於辦公室日常排程最基礎的句型。', 'Subject + will + base verb + at + time', '會議將在十點開始。', 'The meeting will start at ten.', '[]', 100, false, '2026-05-06 10:10:26.155198+08', '2026-05-07 08:32:00.260067+08');
INSERT INTO public.englishchat_question_bank VALUES (12, 'ai-toeic-coca-99f160bbc0c60408', 'meeting', 'reorder', 'beginner', 'Rearrange the following words to form a natural English sentence used at the beginning of a meeting.', '[]', '["now", "the meeting", "Let''s", "start"]', 'Let''s start the meeting now.', 'Let''s 是 Let us 的縮寫，用來提議或建議一起做某事，後面接原形動詞 start（開始）。the meeting（這場會議）是動詞的受詞，時間副詞 now（現在）通常放在句尾。', 'Let''s + 原形動詞', '', '', '[]', 100, false, '2026-05-06 10:40:26.688076+08', '2026-05-07 08:32:00.260067+08');
INSERT INTO public.englishchat_question_bank VALUES (16, 'ai-toeic-coca-a68cf20c1b461d2e', 'meeting', 'translation', 'intermediate', '', '[]', '[]', 'We need to push back the meeting until next Tuesday because several key members are unavailable then.', '這題考察職場會議中常見的表達方式。「延後」除了 postpone，在口語或商務對話中更常用 ''push back''。''Key members'' 指的是關鍵成員。''Unavailable'' 用來形容人沒空出席，比 ''don''t have time'' 更正式且常用於職場。', 'push back + [event] + until + [time]', '我們需要將會議延後到下週二，因為幾位關鍵成員那天無法出席。', 'We need to push back the meeting until next Tuesday because several key members are unavailable then.', '["push back (延後)", "key members (關鍵成員)", "unavailable (沒空/無法出席)"]', 100, false, '2026-05-06 10:41:02.299607+08', '2026-05-07 08:32:31.656846+08');
INSERT INTO public.englishchat_question_bank VALUES (17, 'ai-toeic-coca-5616f2cc9c100d01', 'meeting', 'translation', 'advanced', '', '[]', '[]', '', '這句話展示了高階商務會議中常用的專業表達方式。''In light of'' 意為「鑑於」或「考量到」，常用於引出決策的背景。''Market volatility'' 指市場波動，''maintain a competitive edge'' 是「保持競爭優勢」的道地用法，而 ''mitigate potential risks'' 則是「緩解潛在風險」的標準商務動詞搭配。這些詞彙在 COCA 語料庫中的商務語境下出現頻率極高。', 'In light of + [Noun Phrase], [Subject] + [Verb]...', '鑑於目前市場的波動性，我們必須重新評估我們的策略，以確保我們在競爭中保持領先地位，並有效緩解潛在風險。', 'In light of the current market volatility, we must re-evaluate our strategy to ensure we maintain a competitive edge and effectively mitigate potential risks.', '["In light of (鑑於/考量到)", "Maintain a competitive edge (保持競爭優勢)", "Mitigate potential risks (緩解潛在風險)"]', 100, false, '2026-05-06 10:41:12.048639+08', '2026-05-07 08:32:39.172645+08');
INSERT INTO public.englishchat_question_bank VALUES (18, 'ai-toeic-coca-f495d538cbe1c313', 'phone', 'fill_blank', 'beginner', 'I am busy right now. Can you ____ the phone for me?', '["answer", "open", "talk"]', '[]', 'answer', '在英文中，「接電話」的動詞固定使用 answer。雖然中文說「接」或「聽」電話，但英文不會像開門一樣用 open，也不會單獨用 talk 來表示接聽動作。', 'answer the phone', '', '', '[]', 100, false, '2026-05-06 10:41:20.255393+08', '2026-05-07 08:32:43.93193+08');
INSERT INTO public.englishchat_question_bank VALUES (11, 'ai-toeic-coca-1adf63c9a7953c88', 'meeting', 'fill_blank', 'advanced', 'During the quarterly review, the board members were unable to reach a ____ decision regarding the budget allocation, as several departments expressed concerns about potential resource shortages.', '["unanimous", "tentative", "redundant", "superficial"]', '[]', 'unanimous', 'unanimous 意為「全體一致的」。在正式會議情境中，reach a unanimous decision 是極為常見的專業搭配詞。句意為「在季度審查期間，由於多個部門對潛在資源短缺表示擔憂，董事會成員無法就預算分配達成一致決定」。其他選項：tentative (暫時性的)、redundant (多餘的)、superficial (表面的) 均不符合句意邏輯。', 'reach a unanimous decision', '', '', '[]', 100, false, '2026-05-06 10:40:17.35001+08', '2026-05-07 08:31:49.193331+08');
INSERT INTO public.englishchat_question_bank VALUES (14, 'ai-toeic-coca-209bfd9b1b08ed4e', 'meeting', 'reorder', 'advanced', 'Please arrange the following words and phrases to form a coherent sentence suitable for a high-level corporate meeting scenario.', '[]', '["everyone", "the core objectives", "To ensure", "is on the same page,", "we discussed earlier.", "let''s circle back to"]', 'To ensure everyone is on the same page, let''s circle back to the core objectives we discussed earlier.', '本句展現了進階商務會議中的協調技巧。''To ensure'' 引導目的狀語；''on the same page'' 為 COCA 高頻商務片語，意指「達成共識」；''circle back to'' 則是專業的表達方式，意指「稍後重新討論或回到某個話題」。', 'To ensure [Subject] [Verb], let''s circle back to [Noun Phrase].', '為了確保大家達成共識，讓我們重新回到剛才討論的核心目標。', 'To ensure everyone is on the same page, let''s circle back to the core objectives we discussed earlier.', '["be on the same page (達成共識/同步)", "circle back to (重新回到某話題)", "core objectives (核心目標)"]', 100, false, '2026-05-06 10:40:47.337401+08', '2026-05-07 08:32:17.80206+08');
INSERT INTO public.englishchat_question_bank VALUES (15, 'ai-toeic-coca-57bbf0d39622e82d', 'meeting', 'translation', 'beginner', '', '[]', '[]', 'We need to start the meeting now.', '這句話的主詞是 We (我們)，動詞使用 need to (需要) 來表達必要性，後方必須接原形動詞 start (開始)。meeting (會議) 是本題的核心單字。', 'Subject + need to + verb', '我們現在需要開始會議。', 'We need to start the meeting now.', '["句型提示：We need to + 原形動詞", "關鍵片語：start the meeting (開始會議)", "單字提示：now (現在)"]', 100, false, '2026-05-06 10:40:56.505218+08', '2026-05-07 08:32:23.792373+08');
INSERT INTO public.englishchat_question_bank VALUES (21, 'ai-toeic-coca-a4e17261c8012dd9', 'phone', 'reorder', 'beginner', 'Rearrange the words to make a correct sentence: (請等一下再回電給我。)', '[]', '["call", "later", "Please", "me", "back"]', 'Please call me back later.', '這是一個非常實用的電話用語。''call back'' 是「回電」的意思，受格（me）要放在 call 和 back 之間，''later'' 放在句尾表示「晚一點」。', 'Please call (someone) back later.', '請等一下再回電給我。', 'Please call me back later.', '["call back (回電)", "later (晚一點)"]', 100, false, '2026-05-06 10:41:42.347588+08', '2026-05-07 08:33:09.286491+08');
INSERT INTO public.englishchat_question_bank VALUES (27, 'ai-toeic-coca-239a0e872778cf01', 'restaurant', 'fill_blank', 'beginner', 'May I see the ____, please? I want to order dinner.', '["menu", "bill", "kitchen"]', '[]', 'menu', '在餐廳點餐前，通常會要求看「菜單」(menu)。選項 (B) bill 是帳單，通常在用餐後才看；選項 (C) kitchen 是廚房，不符合句意。', 'May I + 動詞原型...?', '', '', '[]', 100, false, '2026-05-06 10:42:27.264259+08', '2026-05-07 08:33:54.376873+08');
INSERT INTO public.englishchat_question_bank VALUES (28, 'ai-toeic-coca-8f7070048cf792f4', 'restaurant', 'fill_blank', 'intermediate', 'Due to the high volume of customers on weekends, we strongly recommend that you ____ a table in advance.', '["reserve", "reserved", "reservation", "reserving"]', '[]', 'reserve', '動詞 recommend (建議) 後接 that 子句時，子句中的動詞應使用原形動詞（此用法為省略了 should 的虛擬語氣）。此外，reserve a table 是餐廳情境中常見的慣用語，意為「預訂位置」。', 'recommend that + S + (should) + V', '', '', '[]', 100, false, '2026-05-06 10:42:34.699072+08', '2026-05-07 08:34:00.167952+08');
INSERT INTO public.englishchat_question_bank VALUES (39, 'ai-toeic-coca-9a3410f81dcbd11c', 'travel', 'reorder', 'beginner', 'Rearrange the words to form a correct sentence.', '[]', '["to", "I", "want", "go", "to the airport"]', 'I want to go to the airport.', '這題考查 ''want to + 動詞原型'' 的基本句型。''I''（我）是主詞，''want to go''（想要去）是動詞部分，最後加上目的地 ''to the airport''（去機場）。', 'want to + verb', '我想去機場。', '', '[]', 100, false, '2026-05-06 10:43:56.907904+08', '2026-05-07 08:35:29.592756+08');
INSERT INTO public.englishchat_question_bank VALUES (20, 'ai-toeic-coca-5f9d48694019c152', 'phone', 'fill_blank', 'advanced', 'Due to the persistent static on the line, the technician suggested that the client ____ the call to a landline to ensure a more stable connection for the conference.', '["divert", "defer", "discard", "detach"]', '[]', 'divert', '由於線路持續有雜訊（static），技術人員建議客戶將通話「轉向/轉接」（divert）至市話，以確保會議有更穩定的連線。在電信與商務語境中，divert a call 是指將來電轉接到另一個號碼或裝置。其餘選項：(B) defer 延期、(C) discard 丟棄、(D) detach 拆卸，皆不符合題意。', 'suggest that + S + (should) + base verb', '', '', '[]', 100, false, '2026-05-06 10:41:34.955917+08', '2026-05-07 08:32:58.617319+08');
INSERT INTO public.englishchat_question_bank VALUES (23, 'ai-toeic-coca-8f37b4390883a051', 'phone', 'reorder', 'advanced', 'Please rearrange the segments to form a professional sentence suitable for a business phone call scenario regarding a customer inquiry.', '[]', '["I''m afraid", "I''ll have to", "put you on hold", "while I consult with", "my supervisor", "regarding your request."]', 'I''m afraid I''ll have to put you on hold while I consult with my supervisor regarding your request.', '此句展示了商務電話中的專業應對技巧。''I''m afraid'' 用於委婉地告知對方不便的消息；''put someone on hold'' 是「請某人線上稍候」的標準道地用法；''consult with'' 表示「與...諮詢/討論」；''regarding'' 則是商務書信與對話中常用來替代 ''about'' 的正式介係詞，符合 TOEIC 高階語境。', 'I''m afraid + clause (polite refusal/delay) + while-clause (simultaneous action)', '', '', '[]', 100, false, '2026-05-06 10:41:58.304894+08', '2026-05-07 08:33:28.160777+08');
INSERT INTO public.englishchat_question_bank VALUES (24, 'ai-toeic-coca-d8eebb493c03be4e', 'phone', 'translation', 'beginner', '', '[]', '[]', 'Please wait, he is on the phone.', '本句前半段使用祈使句 ''Please wait'' 開頭。後半段主詞是單數的 He，因此 be 動詞型態使用 is。關鍵字 wait 是動詞，意為等待。', 'Please + V / be on the phone', '請等一下，他在講電話。', 'Please wait, he is on the phone.', '["句型：Please + 原形動詞 (祈使句)", "動詞片語：be on the phone (在通話中)", "單字：wait (等候)"]', 100, false, '2026-05-06 10:42:08.008759+08', '2026-05-07 08:33:35.164455+08');
INSERT INTO public.englishchat_question_bank VALUES (25, 'ai-toeic-coca-db168d1dd9d97d89', 'phone', 'translation', 'intermediate', '', '[]', '[]', 'I''m sorry, Mr. Henderson is currently on another line. Would you like to leave a message or call back later?', '這題測驗職場常見的電話用語。''on another line'' 表示正在通話中。''leave a message'' 是留言，''call back'' 是回電。''Would you like to...'' 是常用於客氣詢問對方意願的句型，符合 TOEIC 聽力與口說部分的商務情境。', 'Would you like to + V', '抱歉，Henderson 先生目前正在接聽另一通電話。您想要留言還是稍後再撥？', 'I''m sorry, Mr. Henderson is currently on another line. Would you like to leave a message or call back later?', '["on another line (正在通話中)", "leave a message (留言)", "call back (回電)"]', 100, false, '2026-05-06 10:42:13.97409+08', '2026-05-07 08:33:42.819228+08');
INSERT INTO public.englishchat_question_bank VALUES (31, 'ai-toeic-coca-24524ce5f438f7a2', 'restaurant', 'reorder', 'intermediate', '請將下列單字或片語重組為一個正確的句子，以表達在餐廳訂位的需求。', '[]', '["I''d like to", "book a table", "for four", "at seven o''clock", "tonight"]', 'I''d like to book a table for four at seven o''clock tonight.', '此句型使用 ''I''d like to'' (I would like to) 表示委婉且禮貌的請求。''book a table'' 是餐廳常用的訂位動詞詞組。後接人數 ''for four'' 與具體時間 ''at seven o''clock tonight''。這是多益情境中極為常見的實用對話。', 'I''d like to + V (book a table) + for [人數] + at [時間]', '我想預訂今晚七點四個人的位置。', 'I''d like to book a table for four at seven o''clock tonight.', '["I''d like to + V", "book a table", "for [number of people]"]', 100, false, '2026-05-06 10:42:58.337047+08', '2026-05-07 08:34:24.494078+08');
INSERT INTO public.englishchat_question_bank VALUES (32, 'ai-toeic-coca-a8e67b60da5106bc', 'restaurant', 'reorder', 'advanced', 'Please rearrange the following words to form a formal sentence regarding reservation changes.', '[]', '["Should you", "wish to", "amend your", "reservation,", "please notify", "us at least", "twenty-four hours", "in advance", "to avoid", "a cancellation fee."]', 'Should you wish to amend your reservation, please notify us at least twenty-four hours in advance to avoid a cancellation fee.', '這是一個正式的條件句用法。「Should you wish to...」是「If you should wish to...」的倒裝省略，常用於正式商務或服務情境中。「Amend」意為「修改」，在高級英文中比「change」更為正式。「In advance」表示「提前」，「cancellation fee」則是「取消手續費」。', 'Should + Subject + Verb (Inversion for conditional sentences)', '若您希望修改預約，請至少提前 24 小時通知我們，以避免產生取消手續費。', 'Should you wish to amend your reservation, please notify us at least twenty-four hours in advance to avoid a cancellation fee.', '["Should you wish to (倒裝句型)", "amend (修改)", "in advance (提前)"]', 100, false, '2026-05-06 10:43:04.975421+08', '2026-05-07 08:34:36.95806+08');
INSERT INTO public.englishchat_question_bank VALUES (33, 'ai-toeic-coca-4f66d96189a3be18', 'restaurant', 'translation', 'beginner', '', '[]', '[]', 'I want to book a table for two tonight.', '主詞是 ''I'' (我)，動詞使用 ''want to book'' 表示『想要預訂』。關鍵字 ''table for two'' 是指『兩人的桌位』，時間副詞 ''tonight'' (今晚) 通常放在句尾。', 'I want to + [動詞]', '我今晚想要預訂一個兩人位。', 'I want to book a table for two tonight.', '["句型：I want to + 動詞 (我想要...)", "動詞片語：book a table (預訂桌位)", "單字：tonight (今晚)"]', 100, false, '2026-05-06 10:43:13.245444+08', '2026-05-07 08:34:43.326419+08');
INSERT INTO public.englishchat_question_bank VALUES (34, 'ai-toeic-coca-fe47e7b77d4dd867', 'restaurant', 'translation', 'intermediate', '', '[]', '[]', '', '此句型常用於餐廳訂位。''would like to'' 是比 ''want to'' 更禮貌的表達方式，符合多益商務與日常社交情境。''make a reservation for [人數]'' 是標準的訂位片語，也可以簡化為 ''book a table for''。在提及特定時間時，介系詞使用 ''at''。', 'would like to + make a reservation for [number]', '我們想預約今天晚上七點四個人的位子。', 'We would like to make a reservation for four at 7 p.m. tonight.', '["would like to (想要/希望能...)", "make a reservation (預約)", "for [number] (幾位)"]', 100, false, '2026-05-06 10:43:18.83186+08', '2026-05-07 08:34:49.792094+08');
INSERT INTO public.englishchat_question_bank VALUES (35, 'ai-toeic-coca-9621226016db3ab7', 'restaurant', 'translation', 'advanced', '', '[]', '[]', '', '此題測驗進階商務餐飲情境的表達方式。''Given'' 作為介係詞，常用於句首表示『考慮到...』或『鑑於...』；''accommodate'' 在餐飲與服務業情境中，除了提供住宿，更常用於表示『配合、設法滿足（特殊需求或限制）』；''dietary restrictions'' 是多益高階字彙，指『飲食限制』（如過敏、素食等）。', 'Given the significance of..., [Subject] must ensure that... accommodate [something].', '考慮到這次晚宴的重要性，我們必須確保餐廳能夠配合幾位重要客戶的特殊飲食限制。', 'Given the significance of this dinner, we must ensure that the restaurant can accommodate the specific dietary restrictions of several key clients.', '["Given the significance of... (考慮到...的重要性)", "accommodate dietary restrictions (配合飲食限制)", "key clients (重要客戶)"]', 100, false, '2026-05-06 10:43:24.592319+08', '2026-05-07 08:35:00.952432+08');
INSERT INTO public.englishchat_question_bank VALUES (36, 'ai-toeic-coca-6ca4548dddd0a235', 'travel', 'fill_blank', 'beginner', 'I need to ____ a hotel room for my trip next week.', '["book", "read", "speak", "wait"]', '[]', 'book', '在旅遊情境中，book 當動詞使用時，意思是「預訂」。常見用法包括 book a hotel (預訂飯店) 或 book a ticket (訂票)。', 'book + 物品 (預訂...)', '我需要為下週的旅行預訂一間飯店房間。', '', '[]', 100, false, '2026-05-06 10:43:31.416168+08', '2026-05-07 08:35:06.364967+08');
INSERT INTO public.englishchat_question_bank VALUES (38, 'ai-toeic-coca-aed462f7610b20d0', 'travel', 'fill_blank', 'advanced', 'In light of the unforeseen circumstances surrounding the flight delays, the hotel management agreed to ____ the late check-in fees for all affected passengers.', '["waive", "forfeit", "revoke", "rebate"]', '[]', 'waive', 'waive 意為「放棄（權利、要求、要求支付的費用等）」。在多益與商務英語中，waive a fee（免除費用）是極為常見的高階用法。其餘選項：forfeit（因違規而喪失或被沒收）、revoke（正式撤銷執照或法令）、rebate（退還部分已付出的款項）皆不符合此處『主動免除費用』的語境。', 'waive a fee / waive the requirement', '', '', '[]', 100, false, '2026-05-06 10:43:47.680428+08', '2026-05-07 08:35:19.918906+08');
INSERT INTO public.englishchat_question_bank VALUES (30, 'ai-toeic-coca-38fd9735eea12f32', 'restaurant', 'reorder', 'beginner', 'Please put the words in the correct order to ask for a table at a restaurant.', '[]', '["would like", "I", "for two", "a table"]', 'I would like a table for two.', '這句話在餐廳情境中非常實用，用來客氣地表達「我想要一個兩人的位子」。''would like'' 是 ''want'' 的禮貌用法，適合對服務生使用。''a table for two'' 是固定用法，指兩人的桌位。', 'I would like + [something].', '', '', '[]', 100, false, '2026-05-06 10:42:51.516678+08', '2026-05-07 08:34:19.139372+08');
INSERT INTO public.englishchat_question_bank VALUES (37, 'ai-toeic-coca-69cd97c0442040f1', 'travel', 'fill_blank', 'intermediate', 'Due to a sudden change in the tour schedule, the travel agency had to ____ the itinerary to ensure all participants could visit the museum.', '["modify", "predict", "reserve", "depart"]', '[]', 'modify', '根據句意，旅遊行程因為行程變動而需要「修改」。''modify'' 意為修改、調整；''predict'' 為預測；''reserve'' 為預約；''depart'' 為出發。在 TOEIC 旅遊情境中，modify an itinerary (修改行程) 是非常道地且常見的用法。', 'have to + V (必須做某事)', '', '', '[]', 100, false, '2026-05-06 10:43:39.399407+08', '2026-05-07 08:35:12.139827+08');
INSERT INTO public.englishchat_question_bank VALUES (44, 'ai-toeic-coca-384487e11f6c8f4e', 'travel', 'translation', 'advanced', '', '[]', '[]', '', '此題測驗進階旅遊情境下的正式用語。''In light of'' 是高頻率的正式片語，意為『鑒於』。''Compensation'' (補償) 與 ''complimentary'' (免費提供的) 是多益測驗中關於旅遊與服務業的常見核心單字。''Accommodation'' 則是指住宿設施。', 'In light of [noun phrase], [subject] + [verb]...', '鑑於最近的航班延誤，航空公司將向受影響的乘客提供補償，包括免費住宿和餐飲券。', 'In light of the recent flight delays, the airline will provide compensation to affected passengers, including complimentary accommodation and meal vouchers.', '["In light of (鑑於)", "Compensation (補償)", "Complimentary accommodation (免費住宿)"]', 100, false, '2026-05-06 10:44:36.952997+08', '2026-05-07 08:36:13.302031+08');
INSERT INTO public.englishchat_question_bank VALUES (45, 'ai-toeic-coca-78ec8b4233ad47fe', 'shopping', 'fill_blank', 'beginner', 'I like this blue shirt. How ____ is it?', '["many", "much", "long"]', '[]', 'much', '在購物情境中，詢問物品的「價錢」固定使用 ''How much''。''How many'' 是詢問「數量」，''How long'' 是詢問「長度」或「時間」。', 'How much is + [物品]?', '', '', '[]', 100, false, '2026-05-06 10:44:44.083163+08', '2026-05-07 08:36:22.402139+08');
INSERT INTO public.englishchat_question_bank VALUES (46, 'ai-toeic-coca-02e347b8506cdd20', 'shopping', 'fill_blank', 'intermediate', 'Customers who are not satisfied with their purchase can return the item within 30 days, provided it is still in its original ____.', '["condition", "position", "situation", "location"]', '[]', 'condition', '這題考查名詞的慣用語搭配。在購物與退貨情境中，「in original condition」是一個非常常見的片語，意指「處於原始狀態（未損壞、未使用的狀態）」。句中的 provided 作為連接詞，表示「只要.../前提是...」。其餘選項：(B) position（位置）、(C) situation（情況）、(D) location（地點）皆不符合描述商品狀態的語境。', 'in original condition', '', '', '[]', 100, false, '2026-05-06 10:44:51.198883+08', '2026-05-07 08:36:27.978317+08');
INSERT INTO public.englishchat_question_bank VALUES (47, 'ai-toeic-coca-6c8c43c11281a977', 'shopping', 'fill_blank', 'advanced', 'The recent downturn in the economy has led many consumers to scale back on ____ spending, resulting in a significant drop in luxury retail sales.', '["discretionary", "mandatory", "subsidiary", "preliminary"]', '[]', 'discretionary', 'discretionary spending 指的是「可支配支出」或「非必要支出」，通常指消費者在支付完房租、稅金及生活必需品後所剩餘的資金。在經濟不景氣時，這類開支通常會最先被縮減。其餘選項：(B) mandatory (強制的)、(C) subsidiary (附屬的)、(D) preliminary (初步的)，語意皆與「消費支出」的情境不符。', 'discretionary spending (可支配支出 / 非必要開支)', '', '', '[]', 100, false, '2026-05-06 10:45:01.3221+08', '2026-05-07 08:36:35.09014+08');
INSERT INTO public.englishchat_question_bank VALUES (48, 'ai-toeic-coca-3ec4b89bc6abfea4', 'shopping', 'reorder', 'beginner', 'Please reorder the words to form a sentence: (我想要買這件襯衫。)', '[]', '["want", "this shirt", "I", "to buy"]', 'I want to buy this shirt', '本題考查「want to + 原形動詞」的基礎句型，意為「想要做某事」。在購物情境中，''I want to buy''（我想要買）後方接上受詞 ''this shirt''（這件襯衫）即可組成完整的句子。', 'want to + verb', '', '', '[]', 100, false, '2026-05-06 10:45:11.566518+08', '2026-05-07 08:36:41.852271+08');
INSERT INTO public.englishchat_question_bank VALUES (49, 'ai-toeic-coca-8e86d31c328f6626', 'shopping', 'reorder', 'intermediate', 'Rearrange the following segments to form a natural sentence about a store''s return policy.', '[]', '["a full refund", "if you bring", "within thirty days", "You can get", "the receipt"]', 'You can get a full refund if you bring the receipt within thirty days.', '這題練習購物常見的退款政策說明。''get a full refund'' 是「獲得全額退款」；''bring the receipt'' 是「攜帶收據」；''within thirty days'' 則是「在三十天之內」。', 'You can get [something] if you [do something] [timeframe].', '如果你在三十天內帶著收據，就可以得到全額退款。', 'You can get a full refund if you bring the receipt within thirty days.', '["get a full refund", "bring the receipt", "within thirty days"]', 100, false, '2026-05-06 10:45:17.582815+08', '2026-05-07 08:36:47.074546+08');
INSERT INTO public.englishchat_question_bank VALUES (60, 'ai-toeic-coca-65f25bb48ca6733f', 'school', 'translation', 'beginner', '', '[]', '[]', 'I go to school at 8:00 every morning.', '這句話的主詞是 ''I''（我），動詞使用現在簡單式 ''go''。''go to school'' 是表示『上學』的常用短語。介係詞 ''at'' 用於具體的時間點（8:00），而 ''every morning'' 則是表示頻率的時間副詞。', 'Subject + Verb + Place + Time', '我每天早上八點去學校。', 'I go to school at 8:00 every morning.', '["主詞 + 動詞 + 地點 + 時間", "go to school (上學)", "at + 時間點 (在...幾點)"]', 100, false, '2026-05-06 10:46:53.275733+08', '2026-05-07 08:38:10.266779+08');
INSERT INTO public.englishchat_question_bank VALUES (42, 'ai-toeic-coca-44b0f020c16fa33e', 'travel', 'translation', 'beginner', '', '[]', '[]', 'I want to book a hotel room.', '主詞是第一人稱 ''I''，動詞使用現在式 ''want'' 表達意願，後面接 ''to'' 引導的不定詞 ''book''（預訂）。關鍵字 ''hotel'' 指飯店，''room'' 指房間。', 'I want to + [verb]', '我想要預訂一間飯店房間。', 'I want to book a hotel room.', '["句型提示：I want to + 動詞", "動詞片語：book a room (預訂房間)", "單字提示：hotel (飯店)"]', 100, false, '2026-05-06 10:44:24.888742+08', '2026-05-07 08:35:57.583145+08');
INSERT INTO public.englishchat_question_bank VALUES (43, 'ai-toeic-coca-86b2a30577687a74', 'travel', 'translation', 'intermediate', '', '[]', '[]', '', '這題考查 ''due to'' (由於) 的用法，以及多益常見的旅遊詞彙 ''adjust our itinerary'' (調整行程) 和 ''book a hotel'' (預訂飯店)。''Due to'' 後接名詞短語，是正式且實用的因果表達方式。''Had to'' 表示過去不得不做的義務。', 'Due to + [Noun Phrase], [Subject] + [Verb]...', '由於航班延誤，我們不得不調整行程，並在機場附近預訂了一間飯店。', 'Due to the flight delay, we had to adjust our itinerary and book a hotel near the airport.', '["due to (由於)", "adjust the itinerary (調整行程)", "book a hotel (預訂飯店)"]', 100, false, '2026-05-06 10:44:30.538446+08', '2026-05-07 08:36:03.194087+08');
INSERT INTO public.englishchat_question_bank VALUES (52, 'ai-toeic-coca-604c75fe57aea7b4', 'shopping', 'translation', 'intermediate', '', '[]', '[]', 'If you are not satisfied with the product, we will provide a full refund as long as you return it within 30 days and show your receipt.', '這題測驗條件句與購物退貨相關詞彙。''be satisfied with'' 表示對...滿意；''as long as'' 是常用的條件連接詞，意為「只要...」；''full refund'' 是多益常見的「全額退款」。', 'as long as + condition', '如果你對這項產品不滿意，只要你在 30 天內退貨並出示收據，我們將提供全額退款。', 'If you are not satisfied with the product, we will provide a full refund as long as you return it within 30 days and show your receipt.', '["be satisfied with...", "as long as...", "full refund", "within 30 days"]', 100, false, '2026-05-06 10:45:55.265633+08', '2026-05-07 08:37:09.306987+08');
INSERT INTO public.englishchat_question_bank VALUES (54, 'ai-toeic-coca-522d8ed67a81c3be', 'school', 'fill_blank', 'beginner', 'Students, please ____ your books to page 15.', '["open", "listen", "speak", "walk"]', '[]', 'open', '這是一個課堂上的常用指令。當老師要求學生翻開書本到特定頁碼時，動詞應選用「open」（打開）。「Open your books to page...」是學校情境中極高頻的初級句型。', 'Open your books to page [number]', '', '', '[]', 100, false, '2026-05-06 10:46:09.320098+08', '2026-05-07 08:37:24.211136+08');
INSERT INTO public.englishchat_question_bank VALUES (55, 'ai-toeic-coca-382a6d2917c3707a', 'school', 'fill_blank', 'intermediate', 'Students are required to ____ their final assignments through the online portal by the end of the week.', '["submit", "admit", "permit", "omit"]', '[]', 'submit', '此題考查動詞搭配。在學校情境中，『繳交』作業最常使用的動詞是 submit。其餘選項：admit (承認)、permit (允許)、omit (省略) 皆不符合句意。此用法在 COCA 語料庫中於學術與辦公環境極為常見。', 'be required to + base verb', '', '', '[]', 100, false, '2026-05-06 10:46:14.237359+08', '2026-05-07 08:37:31.647875+08');
INSERT INTO public.englishchat_question_bank VALUES (57, 'ai-toeic-coca-a8af4daa096332b5', 'school', 'reorder', 'beginner', '請將下列單字重組為正確的句子：我今天有一堂數學課。', '[]', '["have", "a", "today", "I", "math class"]', 'I have a math class today.', '這是一個基礎的 SVO 句型。主詞 I 放在句首，動詞 have 表示「有」，受詞是 a math class (一堂數學課)，時間副詞 today 放在句尾。', 'Subject + have + Object + Time', '', '', '[]', 100, false, '2026-05-06 10:46:29.907041+08', '2026-05-07 08:37:48.814712+08');
INSERT INTO public.englishchat_question_bank VALUES (58, 'ai-toeic-coca-a02baf0ba6539721', 'school', 'reorder', 'intermediate', 'Please arrange the following words to form a grammatically correct sentence regarding school administration.', '[]', '["The registrar''s office", "is", "responsible", "for", "processing", "student enrollment applications"]', 'The registrar''s office is responsible for processing student enrollment applications.', '此句考查「be responsible for + V-ing/Noun」（負責...）的用法。The registrar''s office（註冊組）作為主詞，搭配動詞 is 與形容詞片語 responsible for。由於 for 是介系詞，後方接動名詞 processing（處理），最後加上受詞 student enrollment applications（學生入學申請）。', 'Subject + be responsible for + V-ing', '', '', '[]', 100, false, '2026-05-06 10:46:36.049459+08', '2026-05-07 08:37:54.386281+08');
INSERT INTO public.englishchat_question_bank VALUES (99, 'ai-toeic-coca-64e1cfaf1db3b08a', 'meeting', 'fill_blank', 'beginner', 'The meeting starts ____ 10:00 a.m.', '["at", "on", "in"]', '[]', 'at', '在英文中，表達「在幾點鐘」要使用介係詞 at。on 通常用於特定的日期或星期，in 則用於月份、季節或較長的時間段（如 in the morning）。', 'at + 確切時間點', '', '', '[]', 100, false, '2026-05-06 10:52:29.662693+08', '2026-05-07 08:31:36.56559+08');
INSERT INTO public.englishchat_question_bank VALUES (51, 'ai-toeic-coca-e9e0325416ea5828', 'shopping', 'translation', 'beginner', '', '[]', '[]', '', '這句話的主詞是 ''I'' (我)，動詞使用 ''want to'' (想要) 後接原形動詞 ''buy'' (買)。形容詞 ''new'' (新的) 用來修飾名詞 ''shirt'' (襯衫)。', 'I want to + [verb]', '我想買一件新襯衫。', 'I want to buy a new shirt.', '["句型：I want to + 原形動詞", "片語：want to buy (想要買)", "單字：shirt (襯衫)"]', 100, false, '2026-05-06 10:45:48.084694+08', '2026-05-07 08:37:00.59255+08');
INSERT INTO public.englishchat_question_bank VALUES (56, 'ai-toeic-coca-0d1069804d8c29de', 'school', 'fill_blank', 'advanced', 'The university''s new policy of allowing students to design their own interdisciplinary majors is intended to foster an environment that is ____ to creative thinking and innovation.', '["conducive", "detrimental", "indifferent", "susceptible"]', '[]', 'conducive', '這題考查形容詞搭配。''conducive to'' 是常見的高階用法，意為「有助於...的」或「對...有利的」。根據句意，大學允許學生設計跨學科主修是為了營造一個「有助於」創意與創新的環境。其他選項：(B) detrimental (有害的)、(C) indifferent (漠不關心的)、(D) susceptible (易受影響的)，語意皆不符。', 'be conducive to + N/Ving (對...有助益)', '', '', '[]', 100, false, '2026-05-06 10:46:20.576005+08', '2026-05-07 08:37:40.583484+08');
INSERT INTO public.englishchat_question_bank VALUES (65, 'ai-toeic-coca-16c4e7acef4404a9', 'fitness', 'fill_blank', 'advanced', 'Despite the initial enthusiasm of new members, maintaining long-term adherence to a fitness program often requires a ____ approach that balances high-intensity training with adequate recovery periods.', '["holistic", "stagnant", "precarious", "redundant"]', '[]', 'holistic', 'holistic 意為「整體的、全盤的」。在健身與健康語境中，holistic approach 指的是考慮到訓練、營養、心理與恢復等各方面的綜合性方法。其餘選項：stagnant (停滯的) 指發展緩慢或不流動、precarious (不穩定的/危險的) 指情況堪憂、redundant (多餘的) 指重複且不必要的，皆不符合句意。', 'maintaining adherence to ... requires a [adjective] approach', '', '', '[]', 100, false, '2026-05-06 10:47:24.055525+08', '2026-05-07 08:38:38.589945+08');
INSERT INTO public.englishchat_question_bank VALUES (66, 'ai-toeic-coca-18b8adbebb6be54a', 'fitness', 'reorder', 'beginner', 'Please reorder the words to form a correct sentence: 我每天去健身房。', '[]', '["every day", "go to", "I", "the gym"]', 'I go to the gym every day.', '本題考查基礎句型『主詞 + 動詞 + 地點 + 時間』。I 是主詞，go to（去...）是動詞，the gym 是地點，every day（每天）是時間副詞，通常放在句尾。', 'Subject + Verb + Place + Time', '', '', '[]', 100, false, '2026-05-06 10:47:30.214068+08', '2026-05-07 08:38:45.658008+08');
INSERT INTO public.englishchat_question_bank VALUES (67, 'ai-toeic-coca-04a41c1b23ae2c19', 'fitness', 'reorder', 'intermediate', 'Please arrange the following segments to form a complete and logical sentence commonly used by fitness professionals when advising clients:', '[]', '["to achieve", "it is essential", "your fitness goals,", "to maintain", "a consistent workout routine"]', 'To achieve your fitness goals, it is essential to maintain a consistent workout routine.', '這句話的意思是「為了達成你的健身目標，維持規律的運動習慣是至關重要的」。句首使用 ''To + 原型動詞'' 表達目的。主句使用了 ''it is essential to...'' (做某事是必要的) 的虛主詞句型。''consistent'' (規律的、一貫的) 與 ''routine'' (例行公事、習慣) 是健身與多益測驗中極為常見的實用詞彙。', 'To + [Verb], it is essential to + [Verb]...', '', '', '[]', 100, false, '2026-05-06 10:47:37.47524+08', '2026-05-07 08:38:51.566794+08');
INSERT INTO public.englishchat_question_bank VALUES (69, 'ai-toeic-coca-6b09e96bf1a2610a', 'fitness', 'translation', 'beginner', '', '[]', '[]', 'I go to the gym every morning.', '這句話的主詞是 I，動詞使用現在簡單式 go 來表示規律的習慣。關鍵字 gym 指的是「健身房」，前面通常會加上定冠詞 the。', 'Subject + Verb + Place + Time', '我每天早上都去健身房。', 'I go to the gym every morning.', '["句型提示：主詞 + 動詞 + 地點 + 時間", "關鍵片語：go to the gym (去健身房)", "時間提示：every morning (每天早上)"]', 100, false, '2026-05-06 10:47:51.693334+08', '2026-05-07 08:39:08.388163+08');
INSERT INTO public.englishchat_question_bank VALUES (70, 'ai-toeic-coca-b7437cd264a66fb7', 'fitness', 'translation', 'intermediate', '', '[]', '[]', '', '這句話使用了常見的健身相關表達方式。''Stay in shape'' 是 COCA 中極為常見的片語，表示保持健康或良好的體態。''At least'' 用來表示頻率的最低限度。''Focus on'' 則是指將注意力集中在特定的運動項目（如重量訓練 weight training）上。', 'To + V (目的), subject + frequency + focus on + noun', '為了保持體態，我通常每週去健身房至少三次，並專注於重量訓練。', 'To stay in shape, I usually go to the gym at least three times a week and focus on weight training.', '["stay in shape", "at least", "focus on"]', 100, false, '2026-05-06 10:47:58.657738+08', '2026-05-07 08:39:14.464004+08');
INSERT INTO public.englishchat_question_bank VALUES (63, 'ai-toeic-coca-55627f3e3d3ae69c', 'fitness', 'fill_blank', 'beginner', 'I ____ to the gym three times a week to stay healthy.', '["go", "goes", "going"]', '[]', 'go', '本題考查現在簡單式的動詞用法。當主詞為第一人稱 I 時，動詞應使用原形 go。句意為「我每週去健身房三次以保持健康」。', 'Subject + go to + place', '', '', '[]', 100, false, '2026-05-06 10:47:10.969682+08', '2026-05-07 08:38:28.147366+08');
INSERT INTO public.englishchat_question_bank VALUES (64, 'ai-toeic-coca-dad6857514c67045', 'fitness', 'fill_blank', 'intermediate', 'To achieve the best results from your workout routine, it is essential to remain ____ and follow your trainer''s advice.', '["consistent", "persistent", "resistant", "distant"]', '[]', 'consistent', '這題考查形容詞的用法。''consistent'' 意為「持之以恆的、規律的」，在健身情境中常用來描述保持運動習慣。''persistent'' 雖有堅持之意，但多用於描述克服阻礙或執著；''resistant'' 是「抵抗的」；''distant'' 是「遙遠的」。句意為：『為了讓健身成效達到最佳，保持持之以恆並聽從教練的建議是非常重要的。』', 'remain + adjective', '', '', '[]', 100, false, '2026-05-06 10:47:17.387855+08', '2026-05-07 08:38:33.149852+08');
INSERT INTO public.englishchat_question_bank VALUES (74, 'ai-toeic-coca-2be14d0ca2670252', 'hospital', 'fill_blank', 'advanced', 'In order to ensure patient safety and ____ the risk of post-operative complications, the hospital has implemented a rigorous screening protocol for all surgical candidates.', '["mitigate", "exacerbate", "deviate", "facilitate"]', '[]', 'mitigate', '此題考查動詞詞彙的精確用法。句意為「為了確保病人安全並『減輕』手術後併發症的風險，醫院針對所有手術候選人實施了嚴格的篩選流程」。在醫學與商務情境中，mitigate the risk 是極為常見的搭配詞，意為減輕或緩和風險。(B) exacerbate 意為「惡化」、(C) deviate 意為「偏離」、(D) facilitate 意為「促進」，皆不符合句意邏輯。', 'mitigate the risk of something', '', '', '[]', 100, false, '2026-05-06 10:48:24.64593+08', '2026-05-07 08:39:42.381846+08');
INSERT INTO public.englishchat_question_bank VALUES (75, 'ai-toeic-coca-1faf8ac4449b8a26', 'hospital', 'reorder', 'beginner', 'Please put the words in the correct order to form a sentence you might say at a hospital reception.', '[]', '["see", "I", "doctor", "a", "to", "need"]', 'I need to see a doctor.', '這句話的意思是「我需要看醫生」。在醫院櫃檯掛號或求診時非常實用。句型結構為「主詞 (I) + 動詞 (need) + 不定詞 (to see) + 受詞 (a doctor)」。', 'I need to + V (動詞原形)', '', '', '[]', 100, false, '2026-05-06 10:48:32.871648+08', '2026-05-07 08:39:52.43698+08');
INSERT INTO public.englishchat_question_bank VALUES (76, 'ai-toeic-coca-04e79a4a4c7fac93', 'hospital', 'reorder', 'intermediate', 'Rearrange the following words to form a common instruction given at a hospital reception desk.', '[]', '["the medical history form", "before", "you see", "the doctor", "Please fill out"]', 'Please fill out the medical history form before you see the doctor.', '此題測驗醫院情境中的常用祈使句。''fill out'' 是填寫表格的標準用法，''medical history form'' 指病歷表。句型結構為 ''Please + 動詞短語'' 加上 ''before'' 引導的時間子句，說明在某動作之前需完成的程序。', 'Please fill out [noun phrase] before [clause].', '', '', '[]', 100, false, '2026-05-06 10:48:42.140659+08', '2026-05-07 08:39:57.817469+08');
INSERT INTO public.englishchat_question_bank VALUES (77, 'ai-toeic-coca-226271b6c53d94b5', 'hospital', 'reorder', 'advanced', 'Rearrange the segments provided to form a professional sentence regarding hospital administrative standards:', '[]', '["The hospital''s", "newly implemented protocol", "ensures that", "all patient records", "are strictly maintained", "in accordance with", "federal privacy regulations"]', 'The hospital''s newly implemented protocol ensures that all patient records are strictly maintained in accordance with federal privacy regulations.', '本題測驗進階行政與醫療英文用法。''Newly implemented protocol'' 指『新實施的協定/流程』；''ensures that'' 引導名詞子句，說明協定的內容；''in accordance with'' 是進階商務與法律英文中極為常見的片語，意為『符合』或『根據（法規、契約）』。此句型常用於描述機構如何遵循政府規定。', 'Subject (NP) + ensures that + Noun Clause + Prepositional Phrase (in accordance with...)', '醫院新實施的協定確保所有病人紀錄皆嚴格依照聯邦隱私法規保存。', 'The hospital''s newly implemented protocol ensures that all patient records are strictly maintained in accordance with federal privacy regulations.', '["newly implemented (新實施的)", "ensure that + clause (確保...)", "in accordance with (依照；符合)"]', 100, false, '2026-05-06 10:48:54.388165+08', '2026-05-07 08:40:05.187277+08');
INSERT INTO public.englishchat_question_bank VALUES (78, 'ai-toeic-coca-069371c1ab3f47d8', 'hospital', 'translation', 'beginner', '', '[]', '[]', 'I need to see a doctor.', '這句話的主詞是 I（我），搭配現在式動詞 need（需要）。在英文中，「需要做某事」的句型是 need to 加上原形動詞。關鍵片語 see a doctor 是表達「看醫生」最自然且常見的高頻用法。', 'S + need to + V', '我需要看醫生。', 'I need to see a doctor.', '["句型：I need to + 原形動詞", "動詞片語：see a doctor (看醫生)", "單字：need (需要)"]', 100, false, '2026-05-06 10:49:01.856777+08', '2026-05-07 08:40:12.760458+08');
INSERT INTO public.englishchat_question_bank VALUES (79, 'ai-toeic-coca-0faca6c56e8fa8eb', 'hospital', 'translation', 'intermediate', '', '[]', '[]', 'Please check in at the reception desk before proceeding to the outpatient department.', '在醫院情境中，「掛號或報到」常用 check in；「櫃檯」為 reception desk；「門診部」則是 outpatient department。片語 proceed to 則表示「前往某處」，常用於正式指示中。', 'Please check in at [location] before proceeding to [destination].', '請在前往門診部之前，先到櫃檯辦理掛號手續。', 'Please check in at the reception desk before proceeding to the outpatient department.', '["check in (辦理報到/掛號)", "reception desk (服務台/櫃檯)", "outpatient department (門診部)"]', 100, false, '2026-05-06 10:49:08.191412+08', '2026-05-07 08:40:18.309708+08');
INSERT INTO public.englishchat_question_bank VALUES (100, 'ai-toeic-coca-4628039035e25001', 'meeting', 'fill_blank', 'intermediate', 'Due to an unexpected scheduling conflict, the department head decided to ____ the project update meeting until next Thursday.', '["postpone", "cancel", "conduct", "attend"]', '[]', 'postpone', '此題考查動詞用法。根據句意「由於意外的時程衝突，部門主管決定將專案更新會議『延期』到下週四」，postpone 表示「延期」，在商務情境中常與 until（直到...）連用。其他選項：cancel（取消）、conduct（執行/主持）、attend（參加）在此語境下與 until 的搭配較不合邏輯。', 'postpone something until + 時間', '', '', '[]', 100, false, '2026-05-06 10:52:36.185835+08', '2026-05-07 08:31:42.830556+08');
INSERT INTO public.englishchat_question_bank VALUES (72, 'ai-toeic-coca-1eb1621340f66b13', 'hospital', 'fill_blank', 'beginner', 'Please wait here. The ____ will see you in a few minutes.', '["doctor", "banker", "driver"]', '[]', 'doctor', '這句話的意思是「請在此稍候。醫生幾分鐘後會為您看診」。在醫院（hospital）的情境中，負責看診的人是 doctor（醫生）。', 'The [person] will see you. (某人將會見你/為你看診)', '', '', '[]', 100, false, '2026-05-06 10:48:13.42026+08', '2026-05-07 08:39:29.568416+08');
INSERT INTO public.englishchat_question_bank VALUES (73, 'ai-toeic-coca-680ab1eed25b0484', 'hospital', 'fill_blank', 'intermediate', 'Patients are required to ____ at the reception desk upon arrival to confirm their scheduled appointments.', '["check in", "check out", "sign up", "drop off"]', '[]', 'check in', 'check in (辦理報到/登記) 是醫院或診所櫃檯最常見的用語。句意為：病患抵達時須在接待櫃檯辦理報到，以確認預約。其他選項：check out (辦理退房/結帳)、sign up (報名/註冊)、drop off (放下/送到某處) 皆不符合此處語境。', 'be required to + V (被要求做某事)', '', '', '[]', 100, false, '2026-05-06 10:48:18.762426+08', '2026-05-07 08:39:34.640493+08');
INSERT INTO public.englishchat_question_bank VALUES (82, 'ai-toeic-coca-e467280ec92b802a', 'weather', 'fill_blank', 'intermediate', 'Due to the ____ weather conditions, the outdoor corporate team-building event has been rescheduled to next Friday.', '["adverse", "diverse", "inverse", "reverse"]', '[]', 'adverse', 'adverse 意為「不利的」或「有害的」。在多益與日常商務英文中，adverse weather conditions（不利的天候狀況）是一個極為常見的固定搭配，常用於說明因天氣不佳而導致的行程變更。其餘選項：diverse（多樣的）、inverse（相反的）、reverse（反轉的）皆不符合此處語意。', 'Due to + adjective + weather conditions', '', '', '[]', 100, false, '2026-05-06 10:49:31.556546+08', '2026-05-07 08:40:40.351341+08');
INSERT INTO public.englishchat_question_bank VALUES (84, 'ai-toeic-coca-0fbb462912a8ab43', 'weather', 'reorder', 'beginner', 'Please reorder the words to form a sentence about the weather forecast:', '[]', '["It", "will", "be", "rainy", "this afternoon."]', 'It will be rainy this afternoon.', '這題測驗如何描述天氣預測。句型結構為「It will be + 天氣形容詞」，最後加上時間副詞「this afternoon」（今天下午）。rainy 是形容詞，表示下雨的。', 'It will be + [weather adjective]', '', '', '[]', 100, false, '2026-05-06 10:49:54.371545+08', '2026-05-07 08:40:54.202548+08');
INSERT INTO public.englishchat_question_bank VALUES (85, 'ai-toeic-coca-8f9d9296362424c5', 'weather', 'reorder', 'intermediate', 'Rearrange the following segments to form a logical sentence about a change in plans due to weather conditions.', '[]', '["Due to", "the unpredictable weather,", "the outdoor concert", "has been", "moved indoors."]', 'Due to the unpredictable weather, the outdoor concert has been moved indoors.', '這句話的意思是「由於天氣變幻莫測，戶外音樂會已改到室內舉行」。''Due to'' 是多益常考的介係詞片語，表示「由於」；''unpredictable'' 是形容詞，意為「難以預測的」；''has been moved'' 則是現在完成式的被動語態，用來描述已經完成的變更動作。', 'Due to + [Noun Phrase], [Subject] + [Verb Phrase].', '由於天氣變幻莫測，戶外音樂會已改到室內舉行。', 'Due to the unpredictable weather, the outdoor concert has been moved indoors.', '["due to (由於)", "unpredictable weather (難以預測的天氣)", "moved indoors (移至室內)"]', 100, false, '2026-05-06 10:50:00.950127+08', '2026-05-07 08:41:02.318879+08');
INSERT INTO public.englishchat_question_bank VALUES (86, 'ai-toeic-coca-03783aeed546a6f5', 'weather', 'reorder', 'advanced', 'Please reorder the following fragments to form a grammatically correct and professional sentence regarding a weather-related schedule update.', '[]', '["forecasted", "Given", "weather conditions", "the inclement", "but to postpone", "for this weekend", "we have no choice", "indefinitely", "the outdoor retreat"]', 'Given the inclement weather conditions forecasted for this weekend, we have no choice but to postpone the outdoor retreat indefinitely.', '這題測驗高階商務英語與氣象相關表達。''Given'' 在句首作為介系詞，意為「鑑於」或「考慮到」。''Inclement weather'' 是多益常考的高階字彙，專指惡劣的天氣（如狂風暴雨）。''Have no choice but to'' 是一個常見的固定搭配，意為「別無選擇只能...」。''Indefinitely'' 則表示「無限期地」。', 'Given + [Noun Phrase], [Subject] + have no choice but to + [Verb]', '', '', '[]', 100, false, '2026-05-06 10:50:10.687972+08', '2026-05-07 08:41:14.205221+08');
INSERT INTO public.englishchat_question_bank VALUES (87, 'ai-toeic-coca-7d06d621dfa8cf87', 'weather', 'translation', 'beginner', '', '[]', '[]', 'It is going to rain this afternoon.', '主詞使用 It 代表天氣。動詞型態採用 is going to 表示即將發生的預測。關鍵字 rain 在此作為動詞使用，表示「下雨」。', 'It is going to + [verb]', '今天下午會下雨。', 'It is going to rain this afternoon.', '["句型提示：It is going to + [動詞] (表示即將發生的事)", "關鍵動詞：rain (下雨)", "時間提示：this afternoon (今天下午)"]', 100, false, '2026-05-06 10:50:21.368808+08', '2026-05-07 08:41:19.800544+08');
INSERT INTO public.englishchat_question_bank VALUES (88, 'ai-toeic-coca-9b72d94969280ce6', 'weather', 'translation', 'intermediate', '', '[]', '[]', 'Since the weather forecast calls for thunderstorms, we have decided to postpone the outdoor event until next week.', '此句使用了 ''Since'' 引導原因子句。''Weather forecast'' 指天氣預報，''calls for'' 在氣象情境下常用於預報顯示某種天氣。''Postpone'' 是多益常見單字，意為延期，常與 ''until'' 連用。雷陣雨的英文是 ''thunderstorms''。', 'Since + [Reason], [Result]', '由於天氣預報說會有雷陣雨，我們決定把戶外活動延期到下週。', 'Since the weather forecast calls for thunderstorms, we have decided to postpone the outdoor event until next week.', '["Since (由於)", "weather forecast (天氣預報)", "postpone (延期)"]', 100, false, '2026-05-06 10:50:27.894705+08', '2026-05-07 08:41:25.137898+08');
INSERT INTO public.englishchat_question_bank VALUES (10, 'ai-toeic-coca-5a505628c6142a21', 'meeting', 'fill_blank', 'intermediate', 'After a long discussion, the team was finally able to reach a ____ on the marketing strategy for the upcoming product launch.', '["consensus", "contract", "connection", "contribution"]', '[]', 'consensus', '題意為「經過長時間討論後，團隊終於在行銷策略上達成共識」。在商務會議中，reach a consensus 是一個非常道地且常見的用法，意指「達成共識」。其餘選項：contract (合約)、connection (連接/關係)、contribution (貢獻) 放入空格後語意皆不通順。', 'reach a consensus (on something)', '', '', '[]', 100, false, '2026-05-06 10:40:11.133716+08', '2026-05-07 08:31:42.830556+08');
INSERT INTO public.englishchat_question_bank VALUES (81, 'ai-toeic-coca-eb1e12db71e04b29', 'weather', 'fill_blank', 'beginner', 'It is very ____ outside, so please take your umbrella with you.', '["sunny", "rainy", "hot"]', '[]', 'rainy', '根據後半句「take your umbrella」(帶傘)，可以推論外面正在下雨，因此選擇最符合情境的形容詞「rainy」(下雨的)。', 'It is + weather adjective + outside.', '外面雨下很大，所以請記得帶傘。', '', '[]', 100, false, '2026-05-06 10:49:24.778796+08', '2026-05-07 08:40:34.264153+08');
INSERT INTO public.englishchat_question_bank VALUES (83, 'ai-toeic-coca-3d12bc427cb3af88', 'weather', 'fill_blank', 'advanced', 'Due to the ____ weather conditions forecasted for the upcoming weekend, the logistics department has decided to suspend all maritime shipments until further notice.', '["inclement", "serene", "stagnant", "negligible"]', '[]', 'inclement', 'inclement 指的是「天氣惡劣的」，常用於正式或商務場合（如：inclement weather）。其餘選項：serene (寧靜的)、stagnant (停滯的/不流動的)、negligible (微不足道的/可忽略的) 皆不符合描述惡劣天氣導致物流暫停的語境。', 'Due to + [Adjective] + weather conditions', '', '', '[]', 100, false, '2026-05-06 10:49:39.224764+08', '2026-05-07 08:40:46.605802+08');
INSERT INTO public.englishchat_question_bank VALUES (91, 'ai-toeic-coca-739aa29d46a60ac1', 'self_intro', 'fill_blank', 'intermediate', 'I have been with the marketing department for three years, and I currently ____ the team responsible for digital campaigns.', '["lead", "leading", "leads", "led"]', '[]', 'lead', '此題測驗現在式動詞的用法。句中副詞 ''currently''（目前）提示應使用現在式來描述現狀，主詞為 ''I''，故動詞應使用原形 ''lead''。這是在職場自我介紹中說明目前職位與職責的常見表達方式。', 'I currently lead the team responsible for...', '', '', '[]', 100, false, '2026-05-06 10:50:48.63916+08', '2026-05-07 08:41:44.379563+08');
INSERT INTO public.englishchat_question_bank VALUES (93, 'ai-toeic-coca-79d4690182b57e76', 'self_intro', 'reorder', 'beginner', 'Please reorder the words to introduce your workplace.', '[]', '["I", "work", "in", "the", "sales team"]', 'I work in the sales team', '這句話的意思是「我在銷售團隊工作」。在自我介紹時，常用「I work in + 部門」的句型來介紹自己的工作單位。''sales team'' 是指銷售團隊。', 'I work in + [department]', '我在銷售團隊工作。', 'I work in the sales team', '["work in (在...工作)", "sales team (銷售團隊)"]', 100, false, '2026-05-06 10:51:09.767858+08', '2026-05-07 08:41:59.187844+08');
INSERT INTO public.englishchat_question_bank VALUES (94, 'ai-toeic-coca-871ee32a4a48ca92', 'self_intro', 'reorder', 'intermediate', 'Please rearrange the following words to form a natural sentence for a professional self-introduction:', '[]', '["in the marketing field", "I have", "for the past", "been working", "six years"]', 'I have been working in the marketing field for the past six years.', '此句使用現在完成進行式 (have been working) 來描述從過去持續至今的工作經驗，是面試或自我介紹時常用的時態。''For the past'' 是商務英語中非常道地的用法，用來指稱『在過去的這段時間內』。', 'Subject + have been + V-ing + for (duration)', '', '', '[]', 100, false, '2026-05-06 10:51:19.923967+08', '2026-05-07 08:42:06.360354+08');
INSERT INTO public.englishchat_question_bank VALUES (97, 'ai-toeic-coca-39e390900b3b98b2', 'self_intro', 'translation', 'intermediate', '', '[]', '[]', 'I am honored to join the team, and I look forward to working closely with all of you on future projects.', '這是在職場自我介紹中非常實用且正式的表達方式。''be honored to'' 表示「很榮幸能...」，''look forward to'' 後面必須接動名詞 (V-ing)，''work closely with'' 則是「與...密切合作」的常見搭配詞。', 'I look forward to + V-ing', '我很榮幸能加入這個團隊，我期待能在未來的專案中與各位密切合作。', 'I am honored to join the team, and I look forward to working closely with all of you on future projects.', '["be honored to + V", "look forward to + V-ing", "work closely with someone"]', 100, false, '2026-05-06 10:51:48.784143+08', '2026-05-07 08:42:26.933582+08');
INSERT INTO public.englishchat_question_bank VALUES (98, 'ai-toeic-coca-64b59b7594a30247', 'self_intro', 'translation', 'advanced', '', '[]', '[]', '', '這句話展現了高階職場自介的專業度。''Throughout my career'' 是描述職涯經歷的常見開場。''Dedicated to'' 後接動名詞 (V-ing)，表示致力於某事。''Streamlining'' (簡化/提升效率) 是 TOEIC 高頻商業單字，常用於描述流程優化。''Thrive in dynamic environments'' 則常用於描述個人適應力強，能在多變的工作環境中表現優異。', 'Throughout my career, I have been dedicated to [V-ing] and [V-ing] in [adjective] environments.', '在我的職業生涯中，我一直致力於提升跨部門的溝通效率，並在充滿活力的工作環境中茁壯成長。', 'Throughout my career, I have been dedicated to streamlining cross-departmental communication and thriving in dynamic work environments.', '["Throughout my career (在我的職涯中)", "be dedicated to + V-ing (致力於...)", "streamline (簡化/提高效率)", "thrive in (在...中茁壯/成功)"]', 100, false, '2026-05-06 10:51:55.930964+08', '2026-05-07 08:42:33.777184+08');
INSERT INTO public.englishchat_question_bank VALUES (90, 'ai-toeic-coca-30a781c777a329e3', 'self_intro', 'fill_blank', 'beginner', 'Hello, my name is David. I ____ in the sales department.', '["work", "working", "works"]', '[]', 'work', '在現在簡單式中，當主詞是第一人稱單數 I 時，動詞需使用原形。''work in'' 後面接部門名稱，是自我介紹時常用的表達方式。', 'I work in [department]', '', '', '[]', 100, false, '2026-05-06 10:50:43.467551+08', '2026-05-07 08:41:39.633428+08');
INSERT INTO public.englishchat_question_bank VALUES (92, 'ai-toeic-coca-cb59e17bad7d5408', 'self_intro', 'fill_blank', 'advanced', 'Throughout my career in public relations, I have consistently ____ myself as a versatile communicator capable of navigating high-pressure crisis situations with poise.', '["distinguished", "relinquished", "extinguished", "diminished"]', '[]', 'distinguished', '本題考查動詞詞彙與固定搭配。''distinguish oneself as...'' 意為「使自己脫穎而出」或「表現傑出」，是專業自我介紹中強調個人優勢的進階用法。句中 ''versatile'' (多才多藝的/多功能的) 與 ''poise'' (泰然自若) 亦為進階職場詞彙。其他選項：(B) relinquish (放棄)、(C) extinguish (熄滅)、(D) diminish (減少)，語意皆不符合情境。', 'distinguish oneself as + [身分/角色]', '', '', '[]', 100, false, '2026-05-06 10:50:59.91063+08', '2026-05-07 08:41:50.687328+08');
INSERT INTO public.englishchat_question_bank VALUES (96, 'ai-toeic-coca-896adb64c1b8521e', 'self_intro', 'translation', 'beginner', '', '[]', '[]', 'Nice to meet you. I am from Taiwan and I work at a trading company.', '這句話由兩個簡單句組成。第一句使用常用的問候語「Nice to meet you」。第二句的主詞是「I」，動詞分別為「am」與「work」。表達「來自某地」使用「be from」，表達「在某處工作」使用「work at」。關鍵字「trading company」意為「貿易公司」。', 'Nice to meet you. / I am from... / I work at...', '很高興見到你。我來自台灣，目前在一家貿易公司工作。', 'Nice to meet you. I am from Taiwan and I work at a trading company.', '["句型：Nice to meet you. (很高興見到你)", "動詞片語：work at... (在...工作)", "單字：trading company (貿易公司)"]', 100, false, '2026-05-06 10:51:42.47731+08', '2026-05-07 08:42:20.930332+08');
INSERT INTO public.englishchat_question_bank VALUES (102, 'ai-toeic-coca-4f1da5fe755a8738', 'meeting', 'reorder', 'beginner', 'Please put the words in the correct order to make a sentence.', '[]', '["need", "a meeting", "to have", "We"]', 'We need to have a meeting.', '這句話使用了「主詞 (We) + 動詞 (need) + 不定詞 (to have) + 受詞 (a meeting)」的結構。''have a meeting'' 是常用的開會表達方式。', 'Subject + need + to + V', '我們需要開個會。', 'We need to have a meeting.', '["We (我們)", "need to (需要...)", "have a meeting (開會)"]', 100, false, '2026-05-06 10:52:52.076411+08', '2026-05-07 08:32:00.260067+08');
INSERT INTO public.englishchat_question_bank VALUES (103, 'ai-toeic-coca-19b86042087f789b', 'meeting', 'reorder', 'intermediate', 'Rearrange the following words to form a professional instruction for an upcoming business meeting.', '[]', '["the agenda", "before", "to review", "Please", "the meeting starts", "make sure"]', 'Please make sure to review the agenda before the meeting starts.', '這句話的意思是「請務必在會議開始前查看議程」。''make sure to'' 是職場中非常實用的片語，意為「務必」或「確保」，後面接原形動詞。''agenda'' 是多益常見單字，指「會議議程」。''before'' 在此引導時間子句，描述在某事發生之前。', 'Please make sure to + base verb', '', '', '[]', 100, false, '2026-05-06 10:53:02.970591+08', '2026-05-07 08:32:07.866271+08');
INSERT INTO public.englishchat_question_bank VALUES (104, 'ai-toeic-coca-1672694a2b99d136', 'meeting', 'reorder', 'advanced', 'Rearrange the following segments to form a coherent sentence regarding a pre-meeting strategy:', '[]', '["before the stakeholders arrive.", "the discrepancies", "we need to address", "in the budget projections", "To ensure full alignment,"]', 'To ensure full alignment, we need to address the discrepancies in the budget projections before the stakeholders arrive.', '此句使用了不定詞片語「To ensure...」開頭表示目的。''address the discrepancies''（處理差異/不一致）是商務會議中常見的高階表達，''alignment''（對齊/共識）與 ''stakeholders''（利益相關者）皆為 TOEIC 高階詞彙。邏輯順序為：目的（To ensure...）+ 主句（we need to address...）+ 對象（the discrepancies...）+ 範圍（in the budget projections）+ 時間（before...）。', 'To ensure [noun], [subject] + [verb] + [object] + [prepositional phrase] + [time clause].', '', '', '[]', 100, false, '2026-05-06 10:53:11.832636+08', '2026-05-07 08:32:17.80206+08');
INSERT INTO public.englishchat_question_bank VALUES (105, 'ai-toeic-coca-601310a1779cf265', 'meeting', 'translation', 'beginner', '', '[]', '[]', 'We have a meeting at 2:00 p.m.', '這句話的主詞是 We (我們)，動詞使用 have (有/舉行)。時間介系詞使用 at 來接具體的時間點。meeting (會議) 是初級生活與職場常用單字。', 'Subject + have a meeting + at [time]', '我們在下午兩點有一個會議。', 'We have a meeting at 2:00 p.m.', '["句型：主詞 + have a meeting", "動詞片語：have a meeting (開會)", "文法提示：具體時間前使用介系詞 at"]', 100, false, '2026-05-06 10:53:18.919405+08', '2026-05-07 08:32:23.792373+08');
INSERT INTO public.englishchat_question_bank VALUES (106, 'ai-toeic-coca-bc207db8c3a42bf0', 'meeting', 'translation', 'intermediate', '', '[]', '[]', 'Before we wrap up the meeting, let''s quickly go over the action items for next week.', '這句話常用於會議結束前。''wrap up'' 意為結束、收尾，是商務英語中極為常見的片語；''go over'' 意為檢視或逐一檢查；''action items'' 則是指會議後需要執行的『待辦事項』。這類表達方式在多益聽力與閱讀測驗的辦公室情境中出現頻率極高。', 'Before we [verb phrase], let''s [verb phrase].', '在我們結束會議之前，讓我們快速檢視一下下週的待辦事項。', 'Before we wrap up the meeting, let''s quickly go over the action items for next week.', '["wrap up (結束/收尾)", "go over (檢視/複習)", "action items (待辦事項)"]', 100, false, '2026-05-06 10:53:25.270995+08', '2026-05-07 08:32:31.656846+08');
INSERT INTO public.englishchat_question_bank VALUES (107, 'ai-toeic-coca-7fc21e65f532576e', 'meeting', 'translation', 'advanced', '', '[]', '[]', 'Given the current budgetary constraints, it is imperative that we reach a consensus across departments before finalizing the quarterly marketing strategy.', '這句話展現了高階商務會議中常見的表達方式。「Given the...」引導出前提背景，「budgetary constraints」是比「budget limit」更正式的預算限制表達法。「It is imperative that...」後面接虛擬語氣（即省略 should 的原形動詞），用於強調其極端重要性與必要性。「Reach a consensus」則是「達成共識」的標準商務用法。', 'Given [Noun Phrase], it is imperative that [Subject] [Base Verb]...', '鑑於目前的預算限制，我們必須在敲定季度行銷策略之前，先在不同部門間達成共識。', 'Given the current budgetary constraints, it is imperative that we reach a consensus across departments before finalizing the quarterly marketing strategy.', '["Given the current budgetary constraints (鑑於目前的預算限制)", "It is imperative that... (……是勢在必行的/至關重要的)", "Reach a consensus (達成共識)"]', 100, false, '2026-05-06 10:53:32.097697+08', '2026-05-07 08:32:39.172645+08');
INSERT INTO public.englishchat_question_bank VALUES (108, 'ai-toeic-coca-24ad0c30c7b1b697', 'phone', 'fill_blank', 'beginner', 'Hello, this is John. Can I ____ to Mary, please?', '["speak", "tell", "say"]', '[]', 'speak', '在電話中，想要請某人接聽或與某人通話時，最常用的習慣用法是「speak to + 人」。tell 通常接「人 + 內容」，say 則是接「說話內容」，在此情境下不適用。', 'Can I speak to...?', '', '', '[]', 100, false, '2026-05-06 10:53:37.766495+08', '2026-05-07 08:32:43.93193+08');
INSERT INTO public.englishchat_question_bank VALUES (110, 'ai-toeic-coca-748d496fdceccdba', 'phone', 'fill_blank', 'advanced', 'Despite our efforts to stabilize the connection, the ____ signal in the basement forced us to move the conference call to the main lobby.', '["flickering", "intermittent", "staggering", "fluctuating"]', '[]', 'intermittent', 'intermittent 意為「斷斷續續的」，在電信與科技情境中常用來形容訊號不穩定或時斷時續。其他選項：flickering (閃爍的，多用於燈光或螢幕)；staggering (令人驚愕的，多形容數量或金額)；fluctuating (波動的，多用於價格或溫度的起伏)。在描述通訊訊號不佳時，intermittent 是最專業且道地的用法。', 'Despite + noun phrase, the + adjective + signal...', '', '', '[]', 100, false, '2026-05-06 10:54:01.131264+08', '2026-05-07 08:32:58.617319+08');
INSERT INTO public.englishchat_question_bank VALUES (111, 'ai-toeic-coca-e1566c0ade5cdb3d', 'phone', 'reorder', 'beginner', 'Put the words in the correct order to make a polite request: (請將單字排列成正確的句子：)', '[]', '["me", "call", "later", "Please", "back"]', 'Please call me back later.', '這是一句非常實用的電話用語。''call someone back'' 意思為『回電給某人』。當受格是代名詞（如 me）時，通常放在 call 和 back 之間。''later'' 是副詞，表示『稍後』。', 'Please + call + someone + back + (time).', '請稍後回電給我。', 'Please call me back later.', '["call back (回電)", "later (稍後)"]', 100, false, '2026-05-06 10:54:09.267986+08', '2026-05-07 08:33:09.286491+08');
INSERT INTO public.englishchat_question_bank VALUES (112, 'ai-toeic-coca-3642a0add7fb4e81', 'phone', 'reorder', 'intermediate', 'Rearrange the words to form a professional sentence used when calling an office.', '[]', '["is available", "to see if", "I''m calling", "a call", "Mr. Harrison", "right now", "to take"]', 'I''m calling to see if Mr. Harrison is available to take a call right now.', '這句話常用於商務電話，意為「我打電話是想確認 Harrison 先生現在是否方便接聽電話」。''I''m calling to...'' 是表達通話目的的標準開場；''available to take a call'' 是形容某人方便接電話的道地表達方式。', 'I''m calling to see if + [Subject] + is available to...', '我打電話是想確認 Harrison 先生現在是否方便接聽電話。', '', '[]', 100, false, '2026-05-06 10:54:17.249918+08', '2026-05-07 08:33:17.70239+08');
INSERT INTO public.englishchat_question_bank VALUES (113, 'ai-toeic-coca-3fd6047de92f7752', 'phone', 'reorder', 'advanced', 'Rearrange the following phrases to form a formal instruction for handling technical phone issues:', '[]', '["In the event of", "a persistent connection issue,", "please reach out to", "our dedicated support line", "for immediate assistance."]', 'In the event of a persistent connection issue, please reach out to our dedicated support line for immediate assistance.', '此句型展現了高級商務英語的專業度。''In the event of'' 是比 ''if'' 更正式的用法，用於引導可能發生的情況；''persistent'' 指持續存在且令人困擾的問題；''reach out to'' 是職場中極為常見的聯繫用語；''dedicated'' 在此指專門設立的服務專線。', 'In the event of [Noun Phrase], please reach out to [Contact] for [Purpose].', '如果連線問題持續發生，請聯繫我們的專屬支援專線以獲取即時協助。', 'In the event of a persistent connection issue, please reach out to our dedicated support line for immediate assistance.', '["In the event of (在...的情況下/萬一)", "Reach out to (與...聯繫)", "Dedicated line (專線)"]', 100, false, '2026-05-06 10:54:32.661696+08', '2026-05-07 08:33:28.160777+08');
INSERT INTO public.englishchat_question_bank VALUES (114, 'ai-toeic-coca-aa1145050b22cdd4', 'phone', 'translation', 'beginner', '', '[]', '[]', 'Please call me in ten minutes.', '這句話使用祈使句開頭（Please + 動詞原形），動詞 call 是「打電話」的意思。介系詞 in 在時間表達法中表示「在...時間之後」。主詞 You 被省略，直接以動詞原形開頭表示請求。', 'Please + 動詞原形...', '請在十分鐘後打電話給我。', 'Please call me in ten minutes.', '["祈使句：Please + 動詞原形", "call someone：打電話給某人", "in + 時間：在...時間之後"]', 100, false, '2026-05-06 10:54:42.027082+08', '2026-05-07 08:33:35.164455+08');
INSERT INTO public.englishchat_question_bank VALUES (115, 'ai-toeic-coca-623a0ee956f4bd0a', 'phone', 'translation', 'intermediate', '', '[]', '[]', 'Please feel free to call us back if you need further assistance.', '這句話在商務電話溝通中非常常見。''feel free to'' 表示『儘管.../隨時...』，常用於邀請對方採取行動；''further assistance'' 是『進一步的協助』，是 TOEIC 聽力與閱讀的高頻詞彙；''call back'' 則是指『回電』。', 'Please feel free to + 原形動詞', '如果您需要進一步的協助，請隨時回電給我們。', 'Please feel free to call us back if you need further assistance.', '["feel free to (儘管/隨時...)", "further assistance (進一步協助)", "call back (回電)"]', 100, false, '2026-05-06 10:54:49.835788+08', '2026-05-07 08:33:42.819228+08');
INSERT INTO public.englishchat_question_bank VALUES (116, 'ai-toeic-coca-72e8ed32e1979c94', 'phone', 'translation', 'advanced', '', '[]', '[]', '', '這句話展現了職場中常見的專業應對技巧。''tied up'' 是表示『忙得不可開交』的道地說法，在 COCA 語料庫中常用於描述公務繁忙。''I would appreciate it if...'' 是一個非常正式且禮貌的請求句型，在商務通訊中極為常見。''get back to someone'' 是職場電話或郵件中常用的片語，表示『再聯繫』或『回電』。''at my earliest convenience'' 則是商務場合中表達『在方便時儘快』的專業用語。', 'I would appreciate it if + clause / get back to someone', '由於目前我正忙於處理一項緊急的客戶投訴，如果您能透過電子郵件將詳細資訊傳送給我，我將不勝感激，或者我可以在稍後方便時回電給您。', 'As I am currently tied up with an urgent customer complaint, I would appreciate it if you could email me the details, or I can get back to you at my earliest convenience.', '["be tied up with (忙於處理...)", "I would appreciate it if... (如果您能...我將不勝感激)", "get back to someone (回電/回覆某人)", "at one''s earliest convenience (在某人方便時)"]', 100, false, '2026-05-06 10:54:57.716626+08', '2026-05-07 08:33:49.123445+08');
INSERT INTO public.englishchat_question_bank VALUES (117, 'ai-toeic-coca-c083ecfd2c8305d3', 'restaurant', 'fill_blank', 'beginner', 'I want to ____ a table for two people tonight.', '["book", "cook", "look"]', '[]', 'book', '在餐廳情境中，book 當動詞使用時表示「預約」或「預訂」。其他選項：cook（烹飪）、look（看）不符合語意。', 'want to + 原型動詞 (想要做某事)', '我今晚想要預訂兩個人的位子。', '', '[]', 100, false, '2026-05-06 10:55:03.130691+08', '2026-05-07 08:33:54.376873+08');
INSERT INTO public.englishchat_question_bank VALUES (118, 'ai-toeic-coca-c9ce32a161253654', 'restaurant', 'fill_blank', 'intermediate', 'Due to the high volume of customers on weekends, we strongly recommend making a reservation in ____ to ensure a table.', '["advance", "progress", "person", "total"]', '[]', 'advance', '片語 ''in advance'' 意為「事先、提前」，在餐廳訂位或商務情境中非常常見。句意為：由於週末客流量大，我們強烈建議事先預約以確保有位子。其他選項：(B) progress 進展、(C) person 親自（in person）、(D) total 總計，皆不符合此處語意。', 'in advance (phr.) 事先；提前', '', '', '[]', 100, false, '2026-05-06 10:55:07.888093+08', '2026-05-07 08:34:00.167952+08');
INSERT INTO public.englishchat_question_bank VALUES (119, 'ai-toeic-coca-b98a8fd3bd71a843', 'restaurant', 'fill_blank', 'advanced', 'To maintain the highest standards of service during peak hours, the restaurant manager requested that all staff members ____ from taking personal calls while on duty.', '["refrain", "abstain", "prohibit", "exclude"]', '[]', 'refrain', 'refrain from (doing) something 是一個正式且常見的用法，意指「克制、避免做某事」。在此情境中，經理要求員工在值勤期間避免接聽私人電話。abstain 通常用於投票棄權或戒除菸酒；prohibit 是「禁止」且主詞通常為法規或權威機構；exclude 是「排除」。此外，本句使用了 subjunctive mood（虛擬語氣），在 requested that 之後的動詞應使用原形動詞。', 'refrain from + V-ing/Noun', '', '', '[]', 100, false, '2026-05-06 10:55:18.221975+08', '2026-05-07 08:34:07.838197+08');
INSERT INTO public.englishchat_question_bank VALUES (120, 'ai-toeic-coca-35b111a3354b6d9d', 'restaurant', 'reorder', 'beginner', '請重組句子：我想找兩人的位子。', '[]', '["a table", "I would", "for two", "like"]', 'I would like a table for two.', 'I would like 是在餐廳點餐或要求位子時非常禮貌的說法，比 I want 更有禮貌。a table for two 指的是兩人的座位。', 'I would like + 名詞 (n.)', '', '', '[]', 100, false, '2026-05-06 10:55:25.431438+08', '2026-05-07 08:34:19.139372+08');
INSERT INTO public.englishchat_question_bank VALUES (121, 'ai-toeic-coca-f3e1b5439c5b8bea', 'restaurant', 'reorder', 'intermediate', '請將下列單字或片語重組成正確的句子，以表達「我們有四個人的位子，預約大名是 Miller」。', '[]', '["under the name", "We have", "Miller.", "a reservation", "for four"]', 'We have a reservation for four under the name Miller.', '這是在餐廳報到時最實用的句型之一。''have a reservation'' 代表「有預約」，''for + 數字'' 用來表示用餐人數，而 ''under the name'' 則用來指明預約時所登記的姓名。', 'have a reservation for [number] under the name [name]', '我們有四個人的位子，預約大名是 Miller。', 'We have a reservation for four under the name Miller.', '[]', 100, false, '2026-05-06 10:55:32.674828+08', '2026-05-07 08:34:24.494078+08');
INSERT INTO public.englishchat_question_bank VALUES (122, 'ai-toeic-coca-e9dd3b23c0ec50e1', 'restaurant', 'reorder', 'advanced', 'Reorder the words to form a formal request from a restaurant manager to a guest regarding a reservation.', '[]', '["We would", "appreciate it", "if you could", "inform us", "in advance", "should there be", "any changes"]', 'We would appreciate it if you could inform us in advance should there be any changes', '此句型為多益高階常見的正式表達方式。「We would appreciate it if...」用於禮貌地提出請求。後方的「should there be any changes」是虛擬語氣「if there should be any changes」的倒裝（省略 if 並將 should 提前），常用於正式商務或服務情境，表示「萬一發生...」。''in advance'' 則是常見片語，表示「事先」。', 'We would appreciate it if ... should there be ...', '', '', '[]', 100, false, '2026-05-06 10:55:42.94515+08', '2026-05-07 08:34:36.95806+08');
INSERT INTO public.englishchat_question_bank VALUES (123, 'ai-toeic-coca-9eda59d452bb9e62', 'restaurant', 'translation', 'beginner', '請將下列句子翻譯成英文：我想要一個兩人的位置，謝謝。', '[]', '[]', 'I would like a table for two, please.', '這句話的主詞是 I (我)，動詞使用 would like (想要) 來表達禮貌的請求，這在餐廳情境比 want 更正式且客氣。關鍵字 table (桌子/位置) 是用餐時最基礎的單字。', 'I would like + noun', '我想要一個兩人的位置，謝謝。', 'I would like a table for two, please.', '["句型提示：I would like + 名詞 (表示禮貌的想要)", "關鍵片語：a table for two (兩人的桌位)", "文法提示：句尾加上 please 可以增加禮貌語氣"]', 100, false, '2026-05-06 10:55:51.761818+08', '2026-05-07 08:34:43.326419+08');
INSERT INTO public.englishchat_question_bank VALUES (124, 'ai-toeic-coca-09c272a1e7a73162', 'restaurant', 'translation', 'intermediate', '', '[]', '[]', 'We would like to make a reservation for a party of six at 7:00 PM this Friday.', '這句話是餐廳訂位的標準說法。''make a reservation'' 是商務與日常生活中最常用的「預約」表達方式；''a party of [數字]'' 則是用來描述「幾位用餐者」的道地用法。時間點前使用介系詞 ''at''。', 'make a reservation for a party of [number]', '我們想預約這星期五晚上七點，六個人的位置。', 'We would like to make a reservation for a party of six at 7:00 PM this Friday.', '["make a reservation (預約)", "a party of six (六位)", "at 7:00 PM (在七點)"]', 100, false, '2026-05-06 10:55:57.641974+08', '2026-05-07 08:34:49.792094+08');
INSERT INTO public.englishchat_question_bank VALUES (126, 'ai-toeic-coca-2b8eb8504740ad0e', 'travel', 'fill_blank', 'beginner', 'I want to ____ a hotel room for my trip next week.', '["book", "talk", "open"]', '[]', 'book', '在旅遊與生活英文中，''book'' 除了當作『書本』，也常作為動詞表示『預訂』。''book a room'' 是預訂房間的固定用法。', 'want to + 原形動詞 (表達意願)', '', '', '[]', 100, false, '2026-05-06 10:56:12.820538+08', '2026-05-07 08:35:06.364967+08');
INSERT INTO public.englishchat_question_bank VALUES (127, 'ai-toeic-coca-a44e87ff4ad1cbfa', 'travel', 'fill_blank', 'intermediate', 'Due to unexpected maintenance on the aircraft, the departure for Flight BA204 has been ____ by at least two hours.', '["delayed", "confirmed", "boarded", "arrived"]', '[]', 'delayed', '根據句意，由於飛機發生非預期的維修問題（unexpected maintenance），BA204 航班的起飛時間被「延誤」了至少兩小時。選項 (A) delayed 表示延誤，最符合語境。其他選項：(B) confirmed 確認、(C) boarded 登機、(D) arrived 到達，皆不符合邏輯。', 'has been + past participle (passive voice)', '', '', '[]', 100, false, '2026-05-06 10:56:18.970688+08', '2026-05-07 08:35:12.139827+08');
INSERT INTO public.englishchat_question_bank VALUES (128, 'ai-toeic-coca-17d5eb3df5a95140', 'travel', 'fill_blank', 'advanced', 'To ensure a seamless transition between international flights, the travel agency recommended that the executive ____ a buffer of at least three hours for customs clearance and terminal transfers.', '["allot", "allots", "allotted", "allotting"]', '[]', 'allot', '此題考點為虛擬語氣（Subjunctive Mood）。在 recommend（建議）、suggest（提議）、insist（堅持）等表示要求或建議的動詞後，其 that 子句的動詞應使用「原形動詞」，因為在語法上省略了助動詞 should。allot 意為「分配、撥出（時間、金錢等）」，在 COCA 與商務情境中常用於行程規劃。seamless 指「無縫的、順暢的」，buffer 則指「緩衝時間」。', 'recommend that + subject + (should) + base verb', '', '', '[]', 100, false, '2026-05-06 10:56:27.120949+08', '2026-05-07 08:35:19.918906+08');
INSERT INTO public.englishchat_question_bank VALUES (129, 'ai-toeic-coca-d26b950759096198', 'travel', 'reorder', 'beginner', 'Please reorder the words to form a correct sentence: (我想去日本。)', '[]', '["to", "want", "I", "go", "to Japan"]', 'I want to go to Japan.', '本題考查基礎句型「want to + 原形動詞」。I 是主詞，want 是動詞，後接 to go (去)，最後加上目的地 to Japan。這是旅遊時表達意願最常用的句子之一。', 'S + want to + V', '我想去日本。', 'I want to go to Japan.', '["want to + 原形動詞", "go to + 地點"]', 100, false, '2026-05-06 10:56:38.453232+08', '2026-05-07 08:35:29.592756+08');
INSERT INTO public.englishchat_question_bank VALUES (130, 'ai-toeic-coca-fc2e5fe5545575e1', 'travel', 'reorder', 'intermediate', 'Arrange the following phrases to form a natural English sentence regarding travel preparations.', '[]', '["before departure", "your flight details", "at least 24 hours", "to confirm", "Please make sure"]', 'Please make sure to confirm your flight details at least 24 hours before departure.', '這句話的意思是「請確保在出發前至少 24 小時確認您的航班詳情」。''make sure to'' 後接原形動詞，表示「確保去做某事」；''at least'' 是「至少」的意思；''before departure'' 則是常見的旅遊用語，指「出發前」。', 'Make sure to + verb ... at least [time] before [event]', '', '', '[]', 100, false, '2026-05-06 10:56:45.237772+08', '2026-05-07 08:35:40.240712+08');
INSERT INTO public.englishchat_question_bank VALUES (131, 'ai-toeic-coca-748e3b8832997b4f', 'travel', 'reorder', 'advanced', 'Please rearrange the words below to form a coherent sentence regarding an unexpected flight update frequently encountered in advanced travel contexts.', '[]', '["Hardly", "had", "the passengers", "settled", "into their seats", "when", "the captain", "announced", "a mandatory deplaning."]', 'Hardly had the passengers settled into their seats when the captain announced a mandatory deplaning.', '此句型使用了進階的否定倒裝結構「Hardly + had + 主詞 + 過去分詞... when + 主詞 + 過去式...」，表示「一...就...」。''Deplaning'' 是航空專業用語，意指「下飛機」。這種倒裝句型常用於多益高階閱讀或聽力中，用來強調事件發生的緊湊與突然。', 'Negative Inversion (Hardly had + S + Vpp... when...)', '', '', '[]', 100, false, '2026-05-06 10:56:54.880054+08', '2026-05-07 08:35:49.768315+08');
INSERT INTO public.englishchat_question_bank VALUES (41, 'ai-toeic-coca-11abb4a17b382ced', 'travel', 'reorder', 'advanced', 'Rearrange the following segments to form a grammatically correct sentence regarding travel contingencies:', '[]', '["arise that", "necessitate a change", "Should any", "in your travel itinerary", "unforeseen circumstances"]', 'Should any unforeseen circumstances arise that necessitate a change in your travel itinerary', '此句型使用了倒裝句（Inversion），原句為「If any unforeseen circumstances should arise...」。在正式的旅遊合約或商務文書中，將 ''Should'' 置於句首來代替 ''If'' 是非常道地的進階用法。''Unforeseen circumstances'' 意為「不可預見的情況」，而 ''necessitate'' 動詞則表示「使...成為必要」，常用於描述因突發狀況導致的行程變更。', 'Should + Subject + Base Verb (Inversion for conditional ''If'')', '若發生任何導致您旅遊行程必須變動的意外情況...', 'Should any unforeseen circumstances arise that necessitate a change in your travel itinerary', '["Inversion with ''Should''", "unforeseen circumstances", "necessitate a change"]', 100, false, '2026-05-06 10:44:15.881646+08', '2026-05-07 08:35:49.768315+08');
INSERT INTO public.englishchat_question_bank VALUES (132, 'ai-toeic-coca-20bf8784fbb4a010', 'travel', 'translation', 'beginner', '', '[]', '[]', '', '這句話的主詞是 ''I''（我）。動詞使用 ''want to''（想要）接上原形動詞 ''take''（搭乘）。關鍵字 ''airport''（機場）在英文中通常指特定的目的地，因此前面會加上 ''the''。', 'I want to + [動詞原形]', '我想要搭計程車去機場。', 'I want to take a taxi to the airport.', '["句型：I want to + 動詞 (我想要...)", "動詞片語：take a taxi (搭計程車)", "單字：airport (機場)"]', 100, false, '2026-05-06 10:57:00.7668+08', '2026-05-07 08:35:57.583145+08');
INSERT INTO public.englishchat_question_bank VALUES (134, 'ai-toeic-coca-ad431a8be04475a6', 'travel', 'translation', 'advanced', '', '[]', '[]', '', '本題考查進階商務旅行情境。''Tight schedule''（行程緊湊）是 COCA 高頻用法；''carve out time''（擠出時間）常用於表達在忙碌中特意安排；''maintain rapport with''（與...維持良好關係）與 ''stakeholders''（利益相關者）均為 TOEIC 高階商務詞彙，能精準描述商務互動。', 'Despite [Noun Phrase], [Subject] managed to [Verb]...', '儘管行程表很緊湊，我們還是設法騰出時間參訪了當地的分公司，以維持與關鍵利益相關者的良好關係。', 'Despite our tight schedule, we managed to carve out some time to visit the local branch in order to maintain rapport with key stakeholders.', '["tight schedule (緊湊的行程)", "carve out time (擠出時間)", "maintain rapport (維持和諧/良好關係)", "stakeholders (利益相關者)"]', 100, false, '2026-05-06 10:57:17.195101+08', '2026-05-07 08:36:13.302031+08');
INSERT INTO public.englishchat_question_bank VALUES (135, 'ai-toeic-coca-0e1eeed2a7c6ee32', 'shopping', 'fill_blank', 'beginner', 'I like this blue hat. How much does it ____?', '["cost", "pay", "buy", "sell"]', '[]', 'cost', '詢問物品價格時，最常用的句型是 ''How much does it cost?''。在 does 助動詞之後，動詞 cost 必須使用原形。其他選項：pay (付錢)、buy (購買)、sell (賣) 在此語法結構下不符合詢問價格的語意。', 'How much does + 主詞 + cost?', '', '', '[]', 100, false, '2026-05-06 10:57:23.600782+08', '2026-05-07 08:36:22.402139+08');
INSERT INTO public.englishchat_question_bank VALUES (136, 'ai-toeic-coca-3124516dd8de76b2', 'shopping', 'fill_blank', 'intermediate', 'If the item you purchased is defective, you are entitled to a full ____ within thirty days of the purchase date.', '["refund", "receipt", "budget", "bargain"]', '[]', 'refund', '句意為「如果您購買的商品有瑕疵，您有權在購買日起三十天內獲得全額退款」。''refund'' (退款) 是購物情境中最常見的詞彙之一。''receipt'' 為收據，''budget'' 為預算，''bargain'' 為特價商品，皆不符合句意。', 'be entitled to + noun (有權獲得.../符合...的資格)', '', '', '[]', 100, false, '2026-05-06 10:57:29.251042+08', '2026-05-07 08:36:27.978317+08');
INSERT INTO public.englishchat_question_bank VALUES (137, 'ai-toeic-coca-39539283dfe9cf7e', 'shopping', 'fill_blank', 'advanced', 'To reward our most frequent shoppers, the premium membership tier offers ____ benefits that are not available to standard account holders.', '["exclusive", "redundant", "superficial", "tentative"]', '[]', 'exclusive', '此題考查形容詞辨析。根據句意，高端會員級別提供的是一般帳戶持有人「無法享有」的福利，因此應選擇 ''exclusive''（專屬的、獨有的）。其他選項：''redundant''（多餘的）、''superficial''（表面的）、''tentative''（暫定的）皆不符合商業購物情境中的邏輯。', 'To reward [Target Group], [Subject] offers [Adjective] benefits...', '', '', '[]', 100, false, '2026-05-06 10:57:36.537626+08', '2026-05-07 08:36:35.09014+08');
INSERT INTO public.englishchat_question_bank VALUES (138, 'ai-toeic-coca-e8ea5bfc5489cd31', 'shopping', 'reorder', 'beginner', 'Please reorder the words to form a sentence: 我想買這件襯衫。', '[]', '["want", "this shirt", "I", "to buy"]', 'I want to buy this shirt.', '這題練習基礎的『want to + 動詞』句型。在購物情境中，表達「想要做某事」時，主詞 I 後面接 want to，再加上動詞原形 buy，最後加上想買的東西 this shirt。', 'Subject + want + to + Verb', '', '', '[]', 100, false, '2026-05-06 10:57:44.916566+08', '2026-05-07 08:36:41.852271+08');
INSERT INTO public.englishchat_question_bank VALUES (139, 'ai-toeic-coca-13395d05dbbbaec4', 'shopping', 'reorder', 'intermediate', 'Please arrange the following words to form a logical sentence regarding the store''s return policy.', '[]', '["a full refund", "if you", "within thirty days", "You can get", "bring the receipt"]', 'You can get a full refund if you bring the receipt within thirty days.', '這題練習購物常見的退換貨政策表達。''You can get a full refund'' 為主要句型，表示『你可以獲得全額退款』。''if you bring the receipt'' 提供了條件『如果你帶收據』，最後加上時間範圍 ''within thirty days''（在三十天內）。', 'You can get + [noun phrase] + if + [condition]', '如果你在三十天內帶發票來，就可以獲得全額退款。', 'You can get a full refund if you bring the receipt within thirty days.', '["full refund (全額退款)", "receipt (收據/發票)", "within (在...之內)"]', 100, false, '2026-05-06 10:57:50.879746+08', '2026-05-07 08:36:47.074546+08');
INSERT INTO public.englishchat_question_bank VALUES (140, 'ai-toeic-coca-84803d35b989acde', 'shopping', 'reorder', 'advanced', 'To ensure high quality, the procurement manager decided __________ to maintain the brand''s reputation for excellence.', '[]', '["to source", "the boutique''s", "exclusive inventory", "from reputable", "overseas distributors"]', 'to source the boutique''s exclusive inventory from reputable overseas distributors', '本題考查進階商務採購用語。''source'' 在此作為動詞，意為「採購」或「尋找貨源」，常用結構為 ''source something from...''。''exclusive inventory'' 指的是「獨家庫存或商品」，''reputable overseas distributors'' 則是「信譽良好的海外分銷商」。整句意思為：為了確保高品質，採購經理決定從信譽良好的海外分銷商採購精品店的獨家商品，以維持品牌卓越的聲譽。', 'source + object + from + supplier', '', '', '[]', 100, false, '2026-05-06 10:58:04.350958+08', '2026-05-07 08:36:53.798032+08');
INSERT INTO public.englishchat_question_bank VALUES (141, 'ai-toeic-coca-17400102794f1140', 'shopping', 'translation', 'beginner', '', '[]', '[]', 'I want to buy this blue shirt.', '這句話的主詞是 I (我)，動詞型態使用 want to 後接原形動詞 buy。關鍵單字 shirt (襯衫) 前面加上顏色形容詞 blue。', 'I want to + 原形動詞', '我想買這件藍色的襯衫。', 'I want to buy this blue shirt.', '["句型提示：I want to + 原形動詞 (表示想要...)", "關鍵動詞片語：want to buy (想要買)", "單字提示：blue shirt (藍色襯衫)"]', 100, false, '2026-05-06 10:58:13.567217+08', '2026-05-07 08:37:00.59255+08');
INSERT INTO public.englishchat_question_bank VALUES (144, 'ai-toeic-coca-9d843f30b17f2d43', 'school', 'fill_blank', 'beginner', 'The students go to the school ____ to read and borrow books.', '["library", "kitchen", "bank"]', '[]', 'library', '這題考查與學校環境相關的基礎單字。根據句意「學生去學校的____閱讀與借書」，最符合邏輯的場所是 library（圖書館）。', 'go to the [place]', '', '', '[]', 100, false, '2026-05-06 10:58:40.007536+08', '2026-05-07 08:37:24.211136+08');
INSERT INTO public.englishchat_question_bank VALUES (145, 'ai-toeic-coca-fed4dce6dd3af554', 'school', 'fill_blank', 'intermediate', 'The university administration has decided to ____ the new attendance policy until the beginning of the next semester to allow students more time to adjust.', '["implement", "enroll", "graduate", "submit"]', '[]', 'implement', '此題考查動詞詞義。''implement'' 意為「實施、執行」，常用於政策 (policy) 或計畫 (plan) 的推行。句意為：『大學行政部門決定將新的出勤規定延後至下學期開始再實施，以便讓學生有更多時間調整。』其他選項：enroll (註冊/招收)、graduate (畢業)、submit (提交) 均不符合句意語境。', 'implement a policy', '', '', '[]', 100, false, '2026-05-06 10:58:46.371898+08', '2026-05-07 08:37:31.647875+08');
INSERT INTO public.englishchat_question_bank VALUES (146, 'ai-toeic-coca-7cf5ab91422b807c', 'school', 'fill_blank', 'advanced', 'After a thorough review of the applicant''s disciplinary record, the admissions committee decided to ____ the offer of admission, citing a violation of the university''s code of conduct.', '["rescind", "defer", "endorse", "uphold"]', '[]', 'rescind', '動詞 rescind 意為「撤回、廢除（法律、決定或協議）」，在學術或正式行政語境中常用於撤回錄取通知或合約。其餘選項：(B) defer 指「推遲、延期」，(C) endorse 指「公開支持、背書」，(D) uphold 指「維護、維持（原判或決定）」，皆不符合「因違反行為準則而取消錄取」的句意。', 'rescind an offer / rescind a policy', '', '', '[]', 100, false, '2026-05-06 10:58:54.143371+08', '2026-05-07 08:37:40.583484+08');
INSERT INTO public.englishchat_question_bank VALUES (147, 'ai-toeic-coca-ccdd43fe155dee75', 'school', 'reorder', 'beginner', 'Please reorder the following words to form a correct sentence about the school.', '[]', '["The library", "is", "next to", "the classroom."]', 'The library is next to the classroom.', '這題考查描述位置的常用句型。''next to'' 是初級英文中非常高頻的介係詞片語，意思是「在...旁邊」。句子結構為主詞 (The library) + be 動詞 (is) + 地點 (next to the classroom)。', 'Subject + is + next to + Place', '', '', '[]', 100, false, '2026-05-06 10:59:02.306558+08', '2026-05-07 08:37:48.814712+08');
INSERT INTO public.englishchat_question_bank VALUES (148, 'ai-toeic-coca-f2362f2f000eebeb', 'school', 'reorder', 'intermediate', 'Rearrange the words to form a natural sentence regarding a school deadline.', '[]', '["hand in", "by the end of", "your assignment", "to", "Please make sure", "the week"]', 'Please make sure to hand in your assignment by the end of the week.', '這句話的意思是「請務必在週末前交出你的作業」。''Make sure to'' 後接原形動詞，表示『確保/務必做某事』；''hand in'' 是校園與職場常見的片語，意為『繳交』；''by the end of'' 則是用來表達截止期限的常用用法，在多益測驗中非常頻繁出現。', 'Make sure to + base verb / hand in / by the end of', '請務必在週末前交出你的作業。', 'Please make sure to hand in your assignment by the end of the week.', '["Make sure to...", "hand in (submit)", "by the end of..."]', 100, false, '2026-05-06 10:59:08.658303+08', '2026-05-07 08:37:54.386281+08');
INSERT INTO public.englishchat_question_bank VALUES (150, 'ai-toeic-coca-2de337ee6711daab', 'school', 'translation', 'beginner', '', '[]', '[]', '', '這句話的主詞是 I（我），動詞使用 have 表示「有」或「上」課。數學課是 math class。在英文中，表達具體的時間點（例如九點）時，必須在數字前面加上介係詞 at。', 'I have a ... class at ...', '我九點有一堂數學課。', 'I have a math class at nine.', '["句型：I have + 課程名稱", "動詞片語：have a class (有一堂課)", "文法提示：時間點前面使用介係詞 at"]', 100, false, '2026-05-06 10:59:22.984834+08', '2026-05-07 08:38:10.266779+08');
INSERT INTO public.englishchat_question_bank VALUES (151, 'ai-toeic-coca-ea17bff1145d3f64', 'school', 'translation', 'intermediate', '', '[]', '[]', 'In order to meet the graduation requirements, you must submit your internship report to the administrative office by Friday.', '這題測驗如何表達目的與必備條件。''In order to'' 用來表示目的；''meet the requirements'' 是常見的商務與學術搭配詞，意為「符合要求」；''submit'' 意為「提交」；''by Friday'' 表示「在週五之前（含週五）」。', 'In order to + [verb phrase], [subject] + [verb]...', '為了符合畢業資格，你必須在週五前向行政辦公室提交實習報告。', 'In order to meet the graduation requirements, you must submit your internship report to the administrative office by Friday.', '["In order to...", "meet the requirements", "submit ... to ...", "by Friday"]', 100, false, '2026-05-06 10:59:28.776122+08', '2026-05-07 08:38:16.113344+08');
INSERT INTO public.englishchat_question_bank VALUES (62, 'ai-toeic-coca-66e0dabddcc36f58', 'school', 'translation', 'advanced', '', '[]', '[]', '', '本題測試與學術規範相關的高階表達方式。''Academic integrity''（學術誠信）是校園環境中的核心概念。片語 ''of paramount importance'' 等同於 ''extremely important''，常用於正式公文中。''Disciplinary action'' 指的是紀律處分，而 ''expulsion'' 則是學術環境中最嚴重的處分（退學）。這些用法在 COCA 學術語料中頻率極高，符合 TOEIC 進階閱讀與寫作情境。', 'Since [Subject] is of [Adjective] importance, [Clause].', '由於學術誠信在我們學校至關重要，任何形式的抄襲都將導致立即的紀律處分，甚至可能遭到退學。', 'Since academic integrity is of paramount importance at our institution, any form of plagiarism will result in immediate disciplinary action and potentially even expulsion.', '["academic integrity (學術誠信)", "of paramount importance (至關重要)", "disciplinary action (紀律處分)", "expulsion (開除/退學)"]', 100, false, '2026-05-06 10:47:06.282396+08', '2026-05-07 08:38:23.233251+08');
INSERT INTO public.englishchat_question_bank VALUES (153, 'ai-toeic-coca-aab97b0b01f972c4', 'fitness', 'fill_blank', 'beginner', 'I usually ____ to the gym before work to stay fit.', '["go", "goes", "going"]', '[]', 'go', '在現在簡單式中，當主詞為第一人稱 I 時，動詞應使用原形。這句話描述的是一種規律的日常習慣。', 'Subject (I/You/We/They) + verb (base form)', '', '', '[]', 100, false, '2026-05-06 10:59:41.281973+08', '2026-05-07 08:38:28.147366+08');
INSERT INTO public.englishchat_question_bank VALUES (154, 'ai-toeic-coca-6c141f1ec26c5932', 'fitness', 'fill_blank', 'intermediate', 'Regular exercise not only helps with weight management but also significantly ____ your energy levels throughout the work day.', '["boosts", "reduces", "consumes", "prevents"]', '[]', 'boosts', '此題考查動詞詞彙。根據句意，規律運動除了體重管理外，還能顯著『提升』工作期間的能量水平。''Boost'' 在 COCA 語料庫中常用於提升能量、信心或表現。其他選項：(B) 減少、(C) 消耗、(D) 預防，皆不符合句意。', 'not only A but also B (不僅A而且B)', '', '', '[]', 100, false, '2026-05-06 10:59:48.964197+08', '2026-05-07 08:38:33.149852+08');
INSERT INTO public.englishchat_question_bank VALUES (155, 'ai-toeic-coca-97ae909e35cba73d', 'fitness', 'fill_blank', 'advanced', 'To ensure long-term fitness gains, it is crucial to ____ a variety of training modalities into your routine to prevent physical plateaus and maintain motivation.', '["incorporate", "alleviate", "fabricate", "fluctuate"]', '[]', 'incorporate', '此題考查動詞詞彙。''incorporate'' 意為「併入、納入」，在健身語境中常用於將不同的訓練方式（modalities）納入計畫中。''alleviate'' 為減輕（如減輕痛苦），''fabricate'' 為捏造，''fluctuate'' 為波動，均不符合語意。''Plateau'' 在此指健身中常見的進度停滯期（高原期）。', 'incorporate A into B (將 A 納入 B)', '', '', '[]', 100, false, '2026-05-06 10:59:55.581151+08', '2026-05-07 08:38:38.589945+08');
INSERT INTO public.englishchat_question_bank VALUES (156, 'ai-toeic-coca-7650bc95d70d7d5b', 'fitness', 'reorder', 'beginner', 'Reorder the words to make a sentence: 我每天去健身房。', '[]', '["go", "every day", "I", "the gym", "to"]', 'I go to the gym every day.', '這題練習基礎的主動詞結構。主詞是 I，動詞是 go，去某個地方使用片語 go to。the gym 是健身房，every day 是表示頻率的時間副詞，通常放在句尾。', 'Subject + Verb + to + Place + Frequency', '', '', '[]', 100, false, '2026-05-06 11:00:05.440745+08', '2026-05-07 08:38:45.658008+08');
INSERT INTO public.englishchat_question_bank VALUES (157, 'ai-toeic-coca-e5d4f163e9574bb2', 'fitness', 'reorder', 'intermediate', 'Rearrange the words to form a professional sentence about personal training services.', '[]', '["The personal trainer", "will help you", "develop", "a customized workout plan", "tailored to", "your goals"]', 'The personal trainer will help you develop a customized workout plan tailored to your goals.', '這句話描述了健身教練的服務內容。''help someone (to) do something'' 為常用句型，此處省略了 to。''customized workout plan'' 意為『量身訂製的健身計畫』，而 ''tailored to'' 是一個常見的片語，表示『針對...而設計/調整』，用於修飾前面的計畫。', 'help + object + verb (bare infinitive) / past participle as post-modifier', '', '', '[]', 100, false, '2026-05-06 11:00:20.694265+08', '2026-05-07 08:38:51.566794+08');
INSERT INTO public.englishchat_question_bank VALUES (159, 'ai-toeic-coca-3ddb24d5cf19631c', 'fitness', 'translation', 'beginner', '', '[]', '[]', '', '這句話的主詞是 ''I''（我），動詞使用簡單現在式 ''go'' 來表示日常生活習慣。關鍵字 ''gym'' 是健身房，前面通常會加定冠詞 ''the''。', 'S + V + Frequency', '我一個星期去三次健身房。', 'I go to the gym three times a week.', '["句型：主詞 + 動詞 + 地點 + 頻率副詞", "動詞片語：go to the gym (去健身房)", "頻率提示：... times a week (一週...次)"]', 100, false, '2026-05-06 11:00:37.967403+08', '2026-05-07 08:39:08.388163+08');
INSERT INTO public.englishchat_question_bank VALUES (162, 'ai-toeic-coca-750c4d6442a69398', 'hospital', 'fill_blank', 'beginner', 'Please wait here. The ____ will see you soon.', '["doctor", "kitchen", "ticket"]', '[]', 'doctor', '在醫院的情境中，醫護人員會請病人在位子上稍候，並告知「醫生」（doctor）很快就會來診治。這是在診所或醫院非常常見的對話。', 'The [person] will see you soon.', '', '', '[]', 100, false, '2026-05-06 11:01:01.008127+08', '2026-05-07 08:39:29.568416+08');
INSERT INTO public.englishchat_question_bank VALUES (163, 'ai-toeic-coca-a9689a73bf3624c4', 'hospital', 'fill_blank', 'intermediate', 'Patients are requested to ____ at the reception desk at least fifteen minutes before their scheduled appointment.', '["check in", "look up", "take over", "fill out"]', '[]', 'check in', '此題考查動詞片語。根據句意「病患被要求在預定預約時間前至少 15 分鐘到接待櫃檯報到」，''check in'' 意為『辦理報到/登記』，最符合醫療預約情境。其他選項：''look up'' (查閱)、''take over'' (接管)、''fill out'' (填寫，通常接表格)。', 'be requested to + V (被要求做某事)', '', '', '[]', 100, false, '2026-05-06 11:01:06.361562+08', '2026-05-07 08:39:34.640493+08');
INSERT INTO public.englishchat_question_bank VALUES (164, 'ai-toeic-coca-1efc374e32061089', 'hospital', 'fill_blank', 'advanced', 'Following the complex orthopedic surgery, the patient was moved to the rehabilitation wing to undergo intensive physical therapy, as the attending physician deemed it _______ to their long-term recovery.', '["detrimental", "conducive", "incidental", "precarious"]', '[]', 'conducive', '句意為：『在複雜的骨科手術後，患者被移至康復病房進行密集的物理治療，因為主治醫師認為這對其長期康復有助益。』選項 (A) detrimental 意為「有害的」；(B) conducive 意為「有助於...的」，常與介系詞 to 連用，符合語境；(C) incidental 意為「附帶的、次要的」；(D) precarious 意為「不穩定的、危險的」。', 'be conducive to + N/Ving', '', '', '[]', 100, false, '2026-05-06 11:01:13.468256+08', '2026-05-07 08:39:42.381846+08');
INSERT INTO public.englishchat_question_bank VALUES (165, 'ai-toeic-coca-d205e2c606e64a26', 'hospital', 'reorder', 'beginner', '請重組單字，完成這句在醫院診間常聽到的話：', '[]', '["wait", "the", "doctor", "Please", "for"]', 'Please wait for the doctor.', '這是一句在醫院櫃檯或診間常見的祈使句。Please 置於句首表示禮貌；wait for 是固定片語，表示「等候某人」。', 'Please + 動詞 (wait) + for + 名詞 (the doctor).', '', '', '[]', 100, false, '2026-05-06 11:01:21.941559+08', '2026-05-07 08:39:52.43698+08');
INSERT INTO public.englishchat_question_bank VALUES (167, 'ai-toeic-coca-e91deafee081910f', 'hospital', 'reorder', 'advanced', 'Rearrange the following segments to form a coherent sentence describing a hospital''s technological upgrade:', '[]', '["streamline administrative workflows", "The hospital''s newly implemented", "clinical errors", "is designed to", "and mitigate the risk of", "electronic health record system"]', 'The hospital''s newly implemented electronic health record system is designed to streamline administrative workflows and mitigate the risk of clinical errors', '這句話描述了醫院新實施的電子健康紀錄系統（EHR），其目的是為了簡化行政流程並降低臨床錯誤的風險。''streamline'' 是多益高階常用詞，意為「簡化、使效率化」；''mitigate'' 意為「減輕、緩解」。整句結構為：主詞（系統）+ be designed to（旨在...）+ 動詞原形（簡化與降低）。', 'Subject + be designed to + V1 + and + V2', '', '', '[]', 100, false, '2026-05-06 11:01:35.86575+08', '2026-05-07 08:40:05.187277+08');
INSERT INTO public.englishchat_question_bank VALUES (168, 'ai-toeic-coca-da9f661b67cff450', 'hospital', 'translation', 'beginner', '', '[]', '[]', 'I need to see a doctor today.', '這句話的主詞是 I (我)，動詞型態使用 need (需要) 後接 to 與原形動詞 see。關鍵用字是 see a doctor，這是英文中表達「看醫生」最自然且常見的用法。', 'I need to + 原形動詞', '我今天需要看醫生。', 'I need to see a doctor today.', '["句型：I need to + 原形動詞 (我需要...)", "動詞片語：see a doctor (看醫生)", "時間單字：today (今天)"]', 100, false, '2026-05-06 11:01:43.276884+08', '2026-05-07 08:40:12.760458+08');
INSERT INTO public.englishchat_question_bank VALUES (171, 'ai-toeic-coca-812ff7c98aab569b', 'weather', 'fill_blank', 'beginner', 'It is very ____ today, so please take an umbrella with you.', '["rainy", "sunny", "hot"]', '[]', 'rainy', '根據後半句「take an umbrella」(帶把傘)，可以推論天氣是「下雨的」(rainy)。sunny 是晴朗的，hot 是炎熱的，皆不符合語意。', 'It is + [天氣形容詞] + today.', '', '', '[]', 100, false, '2026-05-06 11:02:01.08222+08', '2026-05-07 08:40:34.264153+08');
INSERT INTO public.englishchat_question_bank VALUES (172, 'ai-toeic-coca-3316a08d8911abd9', 'weather', 'fill_blank', 'intermediate', 'Due to ____ weather conditions, the outdoor marketing event has been moved to the indoor conference hall.', '["adverse", "diverse", "reverse", "converse"]', '[]', 'adverse', '題意為「由於不利的天氣條件，戶外行銷活動已移至室內會議廳」。''adverse weather conditions'' 是多益考試與商務新聞中極常見的固定搭配，意指「不利的天氣」或「惡劣的天氣」。其他選項：(B) diverse 多樣的、(C) reverse 相反的、(D) converse 相反的，均不符合語境。', 'due to adverse weather conditions (由於不利/惡劣的天氣條件)', '', '', '[]', 100, false, '2026-05-06 11:02:11.560641+08', '2026-05-07 08:40:40.351341+08');
INSERT INTO public.englishchat_question_bank VALUES (173, 'ai-toeic-coca-ee8be32861dfcc03', 'weather', 'fill_blank', 'advanced', 'Due to the ____ weather conditions forecasted for the weekend, the outdoor corporate gala has been rescheduled to a later date to ensure the safety of all attendees.', '["inclement", "stagnant", "temperate", "whimsical"]', '[]', 'inclement', 'inclement weather 是一個常見的正式用法，意指「惡劣的天氣」，常用於商務公告、航空運輸或活動異動的情境中。選項 (B) stagnant 指（水、空氣或經濟）停滯不前的；(C) temperate 指氣候溫和的；(D) whimsical 指反覆無常或異想天開的。根據語境，因為天氣「惡劣」才需要重新安排活動，故 (A) 為最佳答案。', 'Due to the inclement weather conditions', '', '', '[]', 100, false, '2026-05-06 11:02:17.971565+08', '2026-05-07 08:40:46.605802+08');
INSERT INTO public.englishchat_question_bank VALUES (174, 'ai-toeic-coca-c78821099acfe1fc', 'weather', 'reorder', 'beginner', 'Rearrange the words to form a correct sentence about the weather forecast.', '[]', '["rain.", "going", "to", "is", "It"]', 'It is going to rain.', '這句話使用了 ''be going to'' 句型來預測即將發生的天氣。在英文中，描述天氣時通常使用 ''It'' 作為虛主詞。', 'It is going to + [動詞]', '', '', '[]', 100, false, '2026-05-06 11:02:27.212755+08', '2026-05-07 08:40:54.202548+08');
INSERT INTO public.englishchat_question_bank VALUES (175, 'ai-toeic-coca-60a6d471a1508a10', 'weather', 'reorder', 'intermediate', 'Rearrange the following words to form a correct sentence: (根據天氣預報，今天晚些時候降雨的機率很高。)', '[]', '["According to", "the weather report,", "there is", "a high chance", "of rain", "later today."]', 'According to the weather report, there is a high chance of rain later today.', '本題練習如何描述天氣預報。''According to'' 意為『根據』，常用於引述消息來源。''a high chance of'' 意為『很有可能』，是多益職場情境中常見的機率表達方式。''later today'' 則是常見的時間副詞片語。', 'According to [source], there is a high chance of [noun].', '根據天氣預報，今天晚些時候降雨的機率很高。', 'According to the weather report, there is a high chance of rain later today.', '[]', 100, false, '2026-05-06 11:02:36.241267+08', '2026-05-07 08:41:02.318879+08');
INSERT INTO public.englishchat_question_bank VALUES (176, 'ai-toeic-coca-738635f99a397337', 'weather', 'reorder', 'advanced', 'Rearrange the following segments to form a logical sentence regarding a change in company plans due to severe weather.', '[]', '["Given", "the inclement weather conditions,", "we have", "decided to postpone", "the outdoor corporate retreat", "until further notice."]', 'Given the inclement weather conditions, we have decided to postpone the outdoor corporate retreat until further notice.', '本題測試進階商務氣象與行政用語。''Given'' 在句首作為介系詞，表示「鑒於」或「考量到」。''Inclement weather'' 是 COCA 高頻正式用法，意指惡劣或嚴酷的天氣。''Until further notice'' 是多益常見片語，表示「在另行通知前」。整句結構為：考慮到惡劣的天氣狀況，我們已決定推遲戶外員工旅遊，直到另行通知。', 'Given + Noun Phrase (Reason), Subject + Verb (Result)', '', '', '[]', 100, false, '2026-05-06 11:02:43.282765+08', '2026-05-07 08:41:14.205221+08');
INSERT INTO public.englishchat_question_bank VALUES (101, 'ai-toeic-coca-2c25e3af61a43a11', 'meeting', 'fill_blank', 'advanced', 'Given the current market volatility, the final approval of the strategic merger is ____ upon the board''s review of the revised financial projections next quarter.', '["contingent", "incidental", "redundant", "susceptible"]', '[]', 'contingent', '此題考查進階商務字彙搭配。''contingent upon'' 意為「視...而定」或「取決於...」，常用於正式會議、合約或專案核准情境。其他選項：(B) incidental 附帶的、(C) redundant 多餘的/被裁員的、(D) susceptible 易受影響的，皆不符合此處關於「核准條件」的句意。', 'be contingent upon something', '', '', '[]', 100, false, '2026-05-06 10:52:45.901099+08', '2026-05-07 08:31:49.193331+08');
INSERT INTO public.englishchat_question_bank VALUES (192, 'ai-toeic-coca-7fb51559e4b6d920', 'meeting', 'reorder', 'beginner', 'Rearrange the words to form a correct sentence about a meeting.', '[]', '["the meeting", "need", "to start", "We"]', 'We need to start the meeting.', '這句話的意思是「我們需要開始會議」。句型結構為主詞 (We) + 動詞 (need to start) + 受詞 (the meeting)。在英文中，need to 後面要接原形動詞。', 'Subject + need to + verb', '我們需要開始會議。', 'We need to start the meeting.', '["need to (需要...)", "start (開始)", "meeting (會議)"]', 100, true, '2026-05-07 08:32:00.200606+08', '2026-05-07 08:32:00.200606+08');
INSERT INTO public.englishchat_question_bank VALUES (179, 'ai-toeic-coca-6a10c6cd9926a80b', 'weather', 'translation', 'advanced', '', '[]', '[]', 'Given the severe weather warnings issued by the meteorological bureau, we have decided to postpone the outdoor corporate retreat until further notice to ensure the safety of all participants.', '此題測驗進階天氣與商務詞彙的結合。''Given'' 在句首表示「鑑於」或「考慮到」；''severe weather warnings'' 是氣象局常用的嚴酷天氣警報用語；''until further notice'' 則是商務英文中極為常見的片語，表示「直到另行通知」。', 'Given + Noun Phrase, Subject + Verb...', '鑑於氣象局發布的嚴酷天氣警報，我們已決定推遲戶外企業員工旅遊，直到另行通知，以確保所有參與者的安全。', 'Given the severe weather warnings issued by the meteorological bureau, we have decided to postpone the outdoor corporate retreat until further notice to ensure the safety of all participants.', '["Given the severe weather warnings (鑑於嚴酷天氣警報)", "postpone... until further notice (延期...直到另行通知)", "ensure the safety of (確保...的安全)"]', 100, false, '2026-05-06 11:03:16.37678+08', '2026-05-07 08:41:31.690139+08');
INSERT INTO public.englishchat_question_bank VALUES (180, 'ai-toeic-coca-1e1acba37d1b14e0', 'self_intro', 'fill_blank', 'beginner', 'Hi, my name is David. I ____ for a large tech company in Taipei.', '["work", "working", "works"]', '[]', 'work', '當主詞為第一人稱 I 時，簡單現在式的動詞需使用原形。''work for'' 是自我介紹時說明任職單位的常見用法。', 'I work for + [公司名稱/產業]', '', '', '[]', 100, false, '2026-05-06 11:03:23.979862+08', '2026-05-07 08:41:39.633428+08');
INSERT INTO public.englishchat_question_bank VALUES (181, 'ai-toeic-coca-8e7e33da1b896980', 'self_intro', 'fill_blank', 'intermediate', 'I have an extensive ____ in customer service, which has helped me develop strong communication and problem-solving skills.', '["background", "collection", "attachment", "provision"]', '[]', 'background', '在自我介紹中，''background'' 常與 ''in + 領域'' 連用，表示在某個領域的背景或資歷。''extensive background'' 是商務英文中常見的搭配詞，意指「豐富的資歷背景」。其他選項如 collection (收藏)、attachment (附件)、provision (提供) 皆不符合語境。', 'have an extensive background in [field]', '', '', '[]', 100, false, '2026-05-06 11:03:32.648039+08', '2026-05-07 08:41:44.379563+08');
INSERT INTO public.englishchat_question_bank VALUES (182, 'ai-toeic-coca-2b2ae79d118a49e2', 'self_intro', 'fill_blank', 'advanced', 'Over the past five years, I have consistently ____ my expertise in data analytics to drive informed decision-making and optimize marketing ROI for my previous employers.', '["leveraged", "lingered", "liberated", "liquidated"]', '[]', 'leveraged', 'leveraged (槓桿利用、充分利用) 在商務英語中常用於描述利用既有的技能或資源來達成目標。其餘選項：lingered (逗留)、liberated (解放)、liquidated (清算/變現) 均不符合商務自我介紹的語境。', 'leverage one''s expertise to + verb', '', '', '[]', 100, false, '2026-05-06 11:03:40.900494+08', '2026-05-07 08:41:50.687328+08');
INSERT INTO public.englishchat_question_bank VALUES (183, 'ai-toeic-coca-6185537ac2417061', 'self_intro', 'reorder', 'beginner', 'Please put the words in the correct order to introduce your department.', '[]', '["work", "sales department", "in the", "I"]', 'I work in the sales department.', '這是在自我介紹中說明工作部門的常用句型。''I work in...'' 後面接具體的部門名稱，例如 ''the sales department''（業務部）。', 'I work in + [department]', '我在業務部工作。', '', '[]', 100, false, '2026-05-06 11:03:49.548346+08', '2026-05-07 08:41:59.187844+08');
INSERT INTO public.englishchat_question_bank VALUES (184, 'ai-toeic-coca-c2855fc68d397e22', 'self_intro', 'reorder', 'intermediate', 'Rearrange the following words to create a natural sentence for a self-introduction.', '[]', '["as a", "marketing specialist", "I have been", "for over", "working", "five years"]', 'I have been working as a marketing specialist for over five years.', '此句使用現在完成進行式 (have been + V-ing) 來描述從過去持續到現在的工作經歷。''work as + 職位'' 是介紹職業的標準用法，而 ''for over'' 常用於強調超過某段時間，符合多益商務情境中的專業自我介紹。', 'I have been working as [position] for [duration].', '請重組單字：我擔任行銷專員已經超過五年了。', 'I have been working as a marketing specialist for over five years.', '["Present Perfect Continuous", "work as + job title", "for over + time period"]', 100, false, '2026-05-06 11:03:57.61201+08', '2026-05-07 08:42:06.360354+08');
INSERT INTO public.englishchat_question_bank VALUES (189, 'ai-toeic-coca-4d9ab9acaa6c41ea', 'meeting', 'fill_blank', 'beginner', 'The meeting starts ____ 10:00 a.m. today.', '["at", "on", "in", "to"]', '[]', 'at', '在英文中，表示「具體的時間點」（如幾點幾分）時，習慣使用介係詞 at。', 'at + 具體時間點', '', '', '[]', 100, true, '2026-05-07 08:31:36.497698+08', '2026-05-07 08:31:36.497698+08');
INSERT INTO public.englishchat_question_bank VALUES (190, 'ai-toeic-coca-f92748f29439883f', 'meeting', 'fill_blank', 'intermediate', 'Since we have covered all the items on the agenda, I suggest we ____ the meeting early today.', '["adjourn", "conduct", "consult", "convene"]', '[]', 'adjourn', 'adjourn 意為「使中止、休會」，在商務英語中常用於會議結束或暫停。句意為「既然我們已經討論完議程上的所有項目，我建議我們今天提早結束會議」。其餘選項：(B) conduct 為「進行/實施」、(C) consult 為「諮詢」、(D) convene 為「召集/集合」，皆不符合此處結束會議的語境。', 'Since + [clause], I suggest (that) [subject] + [base verb]...', '', '', '[]', 100, true, '2026-05-07 08:31:42.779642+08', '2026-05-07 08:31:42.779642+08');
INSERT INTO public.englishchat_question_bank VALUES (191, 'ai-toeic-coca-986ca5f4e3ad58c5', 'meeting', 'fill_blank', 'advanced', 'Before we adjourn today''s strategy session, I would like to ____ the importance of adhering to the revised budget constraints to ensure our long-term fiscal health.', '["reiterate", "speculate", "fluctuate", "alleviate"]', '[]', 'reiterate', '動詞 reiterate 意為「重申」或「反覆說明」，在 COCA 語料庫中常用於正式商務或學術場合以強調某個核心觀點。選項 (B) speculate 為「推測」、(C) fluctuate 為「波動」、(D) alleviate 為「減輕/緩解」，皆不符合此處語境。此外，adhere to 意為「遵守」，亦為多益高階常見片語。', 'I would like to reiterate the importance of [noun/gerund]...', '', '', '[]', 100, true, '2026-05-07 08:31:49.143054+08', '2026-05-07 08:31:49.143054+08');
INSERT INTO public.englishchat_question_bank VALUES (186, 'ai-toeic-coca-ea68709980bdd4de', 'self_intro', 'translation', 'beginner', '', '[]', '[]', 'I work at a technology company.', '本句主詞為 I，動詞使用現在式 work 表示目前的職業狀態。關鍵字 technology company 意為科技公司，在公司前通常使用介系詞 at 或 for。', 'I work at + [place].', '我在一家科技公司工作。', 'I work at a technology company.', '["句型提示：I work at + 機構", "關鍵動詞片語：work at (在...工作)", "單字提示：technology (科技)"]', 100, false, '2026-05-06 11:04:17.802651+08', '2026-05-07 08:42:20.930332+08');
INSERT INTO public.englishchat_question_bank VALUES (187, 'ai-toeic-coca-b5b4d83652bcdcd1', 'self_intro', 'translation', 'intermediate', '', '[]', '[]', 'I''m honored to join the team. I''ve been working in the marketing field for the past five years, specializing in social media strategy.', '這題測驗專業自我介紹的常見表達方式。''I''m honored to...'' 是加入新團隊時常用的禮貌開場；''I''ve been working in... for...'' 使用現在完成進行式強調工作經驗從過去持續至今；''specializing in'' 則是用來精確描述個人專業領域的道地用法，符合 COCA 中對於職業描述的常用語句。', 'I''ve been working in [field] for [period], specializing in [area].', '我很榮幸能加入團隊。我過去五年都在行銷領域工作，專攻社群媒體策略。', 'I''m honored to join the team. I''ve been working in the marketing field for the past five years, specializing in social media strategy.', '["I''m honored to + V (很榮幸能...)", "I''ve been working in... for [time] (我過去...以來一直在...領域工作)", "specializing in... (專攻/專長於...)"]', 100, false, '2026-05-06 11:04:25.306016+08', '2026-05-07 08:42:26.933582+08');
INSERT INTO public.englishchat_question_bank VALUES (188, 'ai-toeic-coca-fdb0a600515ef89c', 'self_intro', 'translation', 'advanced', '', '[]', '[]', 'Over the past decade, I have consistently honed my expertise in strategic management and successfully spearheaded cross-functional teams to navigate complex market challenges.', '此句展現了進階的自我介紹技巧，使用了 ''hone one''s expertise'' (磨練專業) 與 ''spearhead'' (帶領/擔任先鋒) 等高階動詞。''Cross-functional'' 指的是跨部門或跨領域，是多益職場情境中常見的專業術語。''Navigate'' 在此用於描述應對複雜情況，比單純的 ''deal with'' 或 ''solve'' 更具專業感且更符合 COCA 高階商務用法。', 'Over the past [time period], I have [adverb] [verb-ed] ... and [verb-ed] ...', '在過去的十年中，我不斷磨練自己在策略管理方面的專業知識，並成功帶領跨國團隊應對複雜的市場挑戰。', 'Over the past decade, I have consistently honed my expertise in strategic management and successfully spearheaded cross-functional teams to navigate complex market challenges.', '["hone one''s expertise (磨練專業知識)", "spearhead (領軍/帶頭)", "navigate complex challenges (應對複雜挑戰)"]', 100, false, '2026-05-06 11:04:32.118129+08', '2026-05-07 08:42:33.777184+08');
INSERT INTO public.englishchat_question_bank VALUES (193, 'ai-toeic-coca-e5b9586ddf783f1f', 'meeting', 'reorder', 'intermediate', 'Please arrange the following words to form a logical sentence about a business meeting procedure.', '[]', '["the budget proposal", "concludes.", "to go over", "before the meeting", "We need"]', 'We need to go over the budget proposal before the meeting concludes.', '這句話的意思是「我們需要在會議結束前仔細審查預算提案」。''go over'' 是商務英語中非常實用的片語，意為「仔細檢查」或「複習」；''conclude'' 則常用於正式場合表示「結束」或「進入尾聲」。', 'We need to + [verb] + [object] + before + [clause]', '', '', '[]', 100, true, '2026-05-07 08:32:07.810516+08', '2026-05-07 08:32:07.810516+08');
INSERT INTO public.englishchat_question_bank VALUES (13, 'ai-toeic-coca-388b535798b8ca3d', 'meeting', 'reorder', 'intermediate', 'Rearrange the words to form a polite business inquiry regarding meeting attendance.', '[]', '["Could you", "please let me know", "if you can", "make it to", "the meeting", "tomorrow?"]', 'Could you please let me know if you can make it to the meeting tomorrow?', '這題測驗如何禮貌地詢問對方是否能出席會議。''Could you please let me know'' 是商務溝通中常用的請求句型。''make it to'' 是一個口語且實用的片語，在 COCA 中常用於表示『出席』或『參加』某個活動。''if'' 在此引導名詞子句，表示『是否』。', 'Could you please let me know if + S + V', '你能不能讓我知道你明天是否能出席會議？', 'Could you please let me know if you can make it to the meeting tomorrow?', '["Could you please let me know...", "make it to the meeting", "if (是否)"]', 100, false, '2026-05-06 10:40:36.582234+08', '2026-05-07 08:32:07.866271+08');
INSERT INTO public.englishchat_question_bank VALUES (5, 'ai-toeic-coca-29028df43df630c3', 'meeting', 'reorder', 'intermediate', 'Rearrange the words to form a professional sentence explaining a schedule change.', '[]', '["push back", "the meeting", "we have to", "until next Tuesday", "I''m afraid"]', 'I''m afraid we have to push back the meeting until next Tuesday.', '這句話常用於商務會議中，當行程有變動需要延期時使用。''I''m afraid'' 在此作為委婉的開場白，表示遺憾或抱歉。''push back'' 是職場中非常道地的片語，意指『延後』。''until'' 用來接延後到的具體時間點。整句意思為：『恐怕我們必須將會議延後到下週二。』', 'I''m afraid + clause (subject + push back + event + until + time)', '請重組句子：恐怕我們必須將會議延後到下週二。', 'I''m afraid we have to push back the meeting until next Tuesday.', '[]', 100, false, '2026-05-06 10:10:32.375378+08', '2026-05-07 08:32:07.866271+08');
INSERT INTO public.englishchat_question_bank VALUES (194, 'ai-toeic-coca-1fef67813a5b17d1', 'meeting', 'reorder', 'advanced', 'Rearrange the fragments to form a grammatically correct sentence often heard in executive board meetings regarding strategic alignment.', '[]', '["It is", "imperative", "that we", "reach a consensus", "before the", "fiscal year", "concludes"]', 'It is imperative that we reach a consensus before the fiscal year concludes', '本題考查商務會議中常見的高階句型。''It is imperative that...'' 後方接虛擬語氣，表示『……是迫切且至關重要的』，that 子句中的動詞應使用原形（此處 reach 前省略了 should）。''reach a consensus'' 是商務英文中『達成共識』的標準用法；''fiscal year'' 意為『財政年度』或『會計年度』，而 concludes 則用於描述時間段的結束。', 'It is imperative that + Subject + (should) + Base Verb', '', '', '[]', 100, true, '2026-05-07 08:32:17.746671+08', '2026-05-07 08:32:17.746671+08');
INSERT INTO public.englishchat_question_bank VALUES (195, 'ai-toeic-coca-e16a622aeb326ebd', 'meeting', 'translation', 'beginner', '', '[]', '[]', '', '這句話的主詞是 We (我們)，動詞使用 have (有)。在表達具體的時間點時，前面要加上介係詞 at。Meeting 是常用單字，意思是『會議』。', 'We have a meeting at [time].', '我們在上午十點有一個會議。', 'We have a meeting at 10:00 a.m.', '["句型：We have + 名詞 (我們有...)", "片語：at 10:00 (在十點鐘)", "單字：meeting (會議)"]', 100, true, '2026-05-07 08:32:23.743307+08', '2026-05-07 08:32:23.743307+08');
INSERT INTO public.englishchat_question_bank VALUES (196, 'ai-toeic-coca-0aaa458f1e175512', 'meeting', 'translation', 'intermediate', '', '[]', '[]', 'Due to a scheduling conflict, we need to postpone the meeting until next Wednesday at 2:00 p.m.', '這題考查商務會議中常見的「延期」表達方式。''Due to'' 表示原因，''scheduling conflict'' 是 COCA 常見的商務用語，指行程重疊或衝突。''Postpone'' 意為延後，常用於正式場合，後接 ''until'' 指引延後到的具體時間點。', 'Due to [reason], [subject] need to [verb] the meeting until [time].', '由於行程衝突，我們需要將會議延後到下週三下午兩點。', 'Due to a scheduling conflict, we need to postpone the meeting until next Wednesday at 2:00 p.m.', '["due to (由於)", "scheduling conflict (行程衝突)", "postpone (延後)"]', 100, true, '2026-05-07 08:32:31.607817+08', '2026-05-07 08:32:31.607817+08');
INSERT INTO public.englishchat_question_bank VALUES (197, 'ai-toeic-coca-dd27d2d77508d996', 'meeting', 'translation', 'advanced', '', '[]', '[]', '', '本題運用了多個高級商務英語常見詞彙與句型。「Given the unforeseen circumstances」意為「鑑於不可預見的情況」，是正式書面或會議中常用的開場白；「reach a consensus on...」表示「就...達成共識」，比單純的 agree 更具正式感；「contingency plan」指「應變計畫」或「備案」；「adjourn」則是正式會議用語，指「休會」或「延期」。', 'Given + [Noun Phrase], [Subject] + reach a consensus on + [Noun Phrase] + before [Clause].', '鑑於不可預見的情況，我們在休會之前需要就應變計畫達成共識。', 'Given the unforeseen circumstances, we need to reach a consensus on the contingency plan before we can adjourn the meeting.', '["Given the unforeseen circumstances (鑑於不可預見的情況)", "reach a consensus on (就...達成共識)", "contingency plan (應變計畫/備案)", "adjourn the meeting (休會/結束會議)"]', 100, true, '2026-05-07 08:32:39.122237+08', '2026-05-07 08:32:39.122237+08');
INSERT INTO public.englishchat_question_bank VALUES (198, 'ai-toeic-coca-26964842d59f49c2', 'phone', 'fill_blank', 'beginner', 'The phone is ringing in the office. Can you please ____ it?', '["answer", "talk", "listen", "open"]', '[]', 'answer', '在英文中，表達「接電話」最常用的動詞是 answer。當電話響起 (ring) 時，我們會說 answer the phone。', 'answer the phone', '', '', '[]', 100, true, '2026-05-07 08:32:43.883029+08', '2026-05-07 08:32:43.883029+08');
INSERT INTO public.englishchat_question_bank VALUES (199, 'ai-toeic-coca-e42b5827c5d526db', 'phone', 'fill_blank', 'intermediate', 'I''ve been trying to ____ to the technical support department all morning, but I keep getting a busy signal.', '["get through", "put through", "hang up", "call back"]', '[]', 'get through', 'get through (to someone/somewhere) 是一個常見的電話用語，意指「撥通電話」或「成功與某人取得聯繫」。在此句中，說話者表示整個早上都試著撥通技術支援部門的電話，但一直聽到忙線音。其他選項：put through (轉接電話)、hang up (掛斷)、call back (回電) 在此句意下較不符合邏輯。', 'get through to + [someone/department]', '', '', '[]', 100, true, '2026-05-07 08:32:50.521393+08', '2026-05-07 08:32:50.521393+08');
INSERT INTO public.englishchat_question_bank VALUES (109, 'ai-toeic-coca-483133a1edc7c011', 'phone', 'fill_blank', 'intermediate', 'If you are unable to reach Mr. Henderson by phone, please ____ a message with his assistant.', '["take", "leave", "give", "keep"]', '[]', 'leave', '在商務英語中，撥打電話者「留言」的固定搭配是 ''leave a message''。相對地，接聽電話的人幫忙紀錄留言則使用 ''take a message''。根據語境，說話者是在建議對方留言，故選 leave。', 'leave a message (with someone)', '', '', '[]', 100, false, '2026-05-06 10:53:46.562904+08', '2026-05-07 08:32:50.569781+08');
INSERT INTO public.englishchat_question_bank VALUES (19, 'ai-toeic-coca-22ba130864c6b2c7', 'phone', 'fill_blank', 'intermediate', 'If the line is busy, please ____ a message after the beep and we will get back to you as soon as possible.', '["leave", "give", "send", "keep"]', '[]', 'leave', '在電話英語中，''leave a message'' 是最道地的固定搭配，表示「留言」。雖然 send a message 常用於傳送簡訊，但在撥打電話遇到語音信箱時，標準用法是 leave。', 'leave a message (留言)', '', '', '[]', 100, false, '2026-05-06 10:41:27.632876+08', '2026-05-07 08:32:50.569781+08');
INSERT INTO public.englishchat_question_bank VALUES (200, 'ai-toeic-coca-63ee04ef557ec1ad', 'phone', 'fill_blank', 'advanced', 'Due to the high volume of inquiries regarding the recent software update, the customer service department has been ____ with calls all morning.', '["inundated", "alleviated", "scrutinized", "requisitioned"]', '[]', 'inundated', 'inundated 意為「使應接不暇、淹沒」，在商務英語中常用於形容某部門收到大量的訊息、信件或電話（be inundated with sth）。根據句意，因為軟體更新引發大量詢問，客服部門整個早上都忙得不可開交。其餘選項：(B) alleviated 減輕、(C) scrutinized 審查、(D) requisitioned 徵用，均不符合此處語境。', 'be inundated with something', '', '', '[]', 100, true, '2026-05-07 08:32:58.569596+08', '2026-05-07 08:32:58.569596+08');
INSERT INTO public.englishchat_question_bank VALUES (201, 'ai-toeic-coca-156010952eb20665', 'phone', 'reorder', 'beginner', 'Rearrange the words to make a polite request on the phone.', '[]', '["later", "call", "me", "Please", "back"]', 'Please call me back later.', '這句話的意思是「請晚點再回電給我」。''Please'' 置於句首表示禮貌，''call back'' 是打電話時常用的動詞片語，意思是「回電」，中間通常會放入受格（如 me）。', 'Please + call (someone) back + 時間副詞', '', '', '[]', 100, true, '2026-05-07 08:33:09.238459+08', '2026-05-07 08:33:09.238459+08');
INSERT INTO public.englishchat_question_bank VALUES (202, 'ai-toeic-coca-b45cd8710cd0e5e4', 'phone', 'reorder', 'intermediate', 'Rearrange the words below to form a professional request for a phone conversation.', '[]', '["Please", "let me know", "if", "you are", "available", "to discuss", "the contract details"]', 'Please let me know if you are available to discuss the contract details.', '本題考查商務電話預約的常用句型。「Please let me know if...」意為「請讓我知道是否...」，後接子句。「available to + 原形動詞」表示「有空做某事」。這是在安排商務通話或確認對方行程時，非常道地且專業的表達方式。', 'Please let me know if + subject + is/are available to + verb', '請讓我知道您是否有空討論合約細節。', 'Please let me know if you are available to discuss the contract details.', '["Please let me know if...", "available to discuss", "contract details"]', 100, true, '2026-05-07 08:33:17.653729+08', '2026-05-07 08:33:17.653729+08');
INSERT INTO public.englishchat_question_bank VALUES (22, 'ai-toeic-coca-8db47b75649bcb0e', 'phone', 'reorder', 'intermediate', 'Arrange the words to form a polite request for a callback in a business setting.', '[]', '["Could you", "please", "have him", "call me back", "as soon as", "he returns?"]', 'Could you please have him call me back as soon as he returns?', '這是一個標準的商務電話請求句型。「Could you please...」用於禮貌地提出請求；「have someone do something」是使役動詞用法，表示「請某人做某事」，後接原形動詞；「as soon as」引導時間副詞子句，表示「一...就...」。此句型在多益聽力 Part 3 (對話) 中非常常見。', 'Could you please have [someone] [verb] as soon as [clause]?', '可以請他在回來後儘快回電給我嗎？', 'Could you please have him call me back as soon as he returns?', '["have someone do something (請某人做某事)", "as soon as (一...就...)", "call someone back (回電)"]', 100, false, '2026-05-06 10:41:49.405226+08', '2026-05-07 08:33:17.70239+08');
INSERT INTO public.englishchat_question_bank VALUES (203, 'ai-toeic-coca-18f64aa7341bfa94', 'phone', 'reorder', 'advanced', 'To address the connectivity issues you''ve been experiencing with your mobile device, please arrange the following phrases to form a coherent instruction:', '[]', '["the factory reset", "before proceeding with", "no information is lost", "that you", "back up your data", "We recommend", "to ensure"]', 'We recommend that you back up your data before proceeding with the factory reset to ensure no information is lost', '此題測驗高級商用英文中常見的建議句型「recommend that + 主詞 + (should) + 原形動詞」。此外，「before proceeding with」是專業語境中表達「在繼續執行……之前」的道地用法。動詞片語「back up」（備份）與名詞「factory reset」（原廠重設）皆為電信與科技領域的高頻詞彙。最後由「to ensure」引導目的狀語從句，說明備份的目的是確保資訊不遺失。', 'recommend that + S + (should) V ... before proceeding with + N/Ving', '', '', '[]', 100, true, '2026-05-07 08:33:28.110759+08', '2026-05-07 08:33:28.110759+08');
INSERT INTO public.englishchat_question_bank VALUES (204, 'ai-toeic-coca-362056b4c42cc3ea', 'phone', 'translation', 'beginner', '', '[]', '[]', 'Please call me back in ten minutes.', '本句為祈使句，省略主詞 You，動詞使用原形 call。片語 ''call (someone) back'' 意為回電。介係詞 ''in'' 搭配時間長度（ten minutes）表示從現在起一段時間之後。', 'Please + V + back', '請在十分鐘後回電給我。', 'Please call me back in ten minutes.', '["祈使句：Please + 動詞原形", "回電：call back", "在...時間之後：in + 時間"]', 100, true, '2026-05-07 08:33:35.115911+08', '2026-05-07 08:33:35.115911+08');
INSERT INTO public.englishchat_question_bank VALUES (205, 'ai-toeic-coca-f1248acf50a34346', 'phone', 'translation', 'intermediate', '', '[]', '[]', 'Could you please put me through to the marketing manager? I have an urgent matter to discuss regarding the new product launch.', '在商務電話中，「put someone through to...」是「將電話轉接給某人」的標準用法，比「transfer」更常用於口語。此外，「regarding」是商務英文中表示「關於」的高頻介系詞，「urgent matter」則用來強調事情的緊急性。', 'put someone through to / regarding / urgent matter', '請幫我轉接給行銷經理。我有一件關於新產品發布的緊急事項要討論。', 'Could you please put me through to the marketing manager? I have an urgent matter to discuss regarding the new product launch.', '["put someone through to (將電話轉接給...)", "regarding (關於 / 有關...)", "urgent matter (緊急事項)"]', 100, true, '2026-05-07 08:33:42.769528+08', '2026-05-07 08:33:42.769528+08');
INSERT INTO public.englishchat_question_bank VALUES (206, 'ai-toeic-coca-11479fe1e08b6e1e', 'phone', 'translation', 'advanced', '', '[]', '[]', 'Given the unstable connection, should we be cut off during the call, I will immediately dial your extension to get back in touch with you.', '此句型使用了進階的虛擬語氣倒裝句「should we be cut off」，表示「萬一我們斷線了」，這在正式商務溝通中非常常見。此外，「extension」在多益情境中指「分機」，而「get back in touch with」則是「重新聯繫」的道地用法。使用「Given...」開頭來表示「考量到...」也是高階寫作的常用技巧。', 'Should + Subject + Verb (Inverted Conditional) / phrasal verb ''cut off''', '考慮到連線品質不穩定，萬一我們在通話中斷線，我會立刻撥打你的分機重新與你聯繫。', 'Given the unstable connection, should we be cut off during the call, I will immediately dial your extension to get back in touch with you.', '["Should we be cut off (萬一斷線/倒裝句)", "Dial one''s extension (撥打分機)", "Get back in touch with someone (與某人重新聯繫)"]', 100, true, '2026-05-07 08:33:49.075396+08', '2026-05-07 08:33:49.075396+08');
INSERT INTO public.englishchat_question_bank VALUES (215, 'ai-toeic-coca-c0d753aaac1208a9', 'restaurant', 'translation', 'advanced', '', '[]', '[]', '', '這句話展現了高階商務餐飲情境下的禮貌請求。''Given'' 在此作介係詞，表示『考慮到...』；''party'' 在餐飲情境中指的是『團體/一行人』；''prix-fixe menu'' 是法語借詞，在高級餐廳中常用來指『固定價格的套餐』；''tailored for'' 則表示『為...量身打造』，符合商務專業用語。', 'Given [Noun Phrase], would it be possible to [Verb]?', '考慮到我們團體的人數以及部分成員的特殊飲食限制，我們是否可以請求一份為今晚商務晚宴量身定制的套餐菜單？', 'Given the size of our party and the specific dietary restrictions of some members, would it be possible to request a customized prix-fixe menu tailored for tonight''s business dinner?', '["Given the size of our party (考慮到我們一行人的人數)", "dietary restrictions (飲食限制)", "prix-fixe menu (固定價格套餐)", "tailored for (為...量身定制)"]', 100, true, '2026-05-07 08:35:00.904923+08', '2026-05-07 08:35:00.904923+08');
INSERT INTO public.englishchat_question_bank VALUES (26, 'ai-toeic-coca-3ff5f24c05c3ebfa', 'phone', 'translation', 'advanced', '', '[]', '[]', 'If you encounter any technical issues during the conference call, please do not hesitate to reach out to our dedicated support line for immediate assistance.', '這句話展示了高階商務英語的標準用法。''Encounter'' (遇到) 比 ''have'' 或 ''meet'' 更正式；''do not hesitate to'' 是商務書信與通話中的常見禮貌用語，意為『請儘管...』；''reach out to'' 在現代商務語境中廣泛取代 ''contact''；''dedicated support line'' 指的是專門處理特定問題的支援專線；''immediate assistance'' 則常用於強調服務的效率。', 'If + S + V, please do not hesitate to + V...', '如果您在視訊會議期間遇到任何技術問題，請隨時撥打我們的專屬支援專線以獲取即時協助。', 'If you encounter any technical issues during the conference call, please do not hesitate to reach out to our dedicated support line for immediate assistance.', '["encounter (v.) 遭遇/遇到", "do not hesitate to (phr.) 請儘管.../毫不猶豫地...", "reach out to (phr.) 聯繫/聯絡", "dedicated line (n.) 專線", "immediate assistance (n.) 即時協助"]', 100, false, '2026-05-06 10:42:19.954715+08', '2026-05-07 08:33:49.123445+08');
INSERT INTO public.englishchat_question_bank VALUES (207, 'ai-toeic-coca-a9892e133f088400', 'restaurant', 'fill_blank', 'beginner', 'I would like to ____ a table for two people at 7:00 p.m.', '["book", "eat", "buy"]', '[]', 'book', '在餐廳情境中，''book a table'' 表示『預訂位子』。選項 (A) book 在此作為動詞，意為預訂；(B) eat 是吃；(C) buy 是買。根據句意，預訂位子最符合情境。', 'book a table (預訂位子)', '', '', '[]', 100, true, '2026-05-07 08:33:54.328613+08', '2026-05-07 08:33:54.328613+08');
INSERT INTO public.englishchat_question_bank VALUES (208, 'ai-toeic-coca-9f336a299dde053c', 'restaurant', 'fill_blank', 'intermediate', 'Due to the high volume of customers on weekends, we strongly recommend that you ____ a table at least two days in advance.', '["reserve", "reserved", "reservation", "reserving"]', '[]', 'reserve', '這題考查動詞用法。在動詞 recommend（建議）後接的 that 子句中，受詞子句的動詞必須使用原形（此為虛擬語氣用法，省略了 should）。此外，''reserve a table'' 是餐廳情境中極為常見的搭配詞，意為『預訂位子』。', 'recommend that + subject + (should) + base verb', '', '', '[]', 100, true, '2026-05-07 08:34:00.119912+08', '2026-05-07 08:34:00.119912+08');
INSERT INTO public.englishchat_question_bank VALUES (209, 'ai-toeic-coca-4797b026001ba76d', 'restaurant', 'fill_blank', 'advanced', 'Given the high volume of reservations this weekend, the head chef has requested that all kitchen staff ____ their shifts early to ensure adequate preparation for the dinner service.', '["commence", "commenced", "commencing", "to commence"]', '[]', 'commence', '此題考查虛擬語氣（Subjunctive Mood）。在表示建議、要求、命令或必要的動詞（如 request, suggest, insist, demand）後接 that 子句時，子句中的動詞應使用原形動詞（即省略了 should）。''commence'' 是正式用語，意指『開始』，符合多益高級商務與餐飲管理情境。其餘選項不符合此語法結構。', 'Subject + request/suggest/insist + that + Subject + (should) + Base Verb', '', '', '[]', 100, true, '2026-05-07 08:34:07.787646+08', '2026-05-07 08:34:07.787646+08');
INSERT INTO public.englishchat_question_bank VALUES (29, 'ai-toeic-coca-c94230a9959c3583', 'restaurant', 'fill_blank', 'advanced', 'Given the restaurant''s commitment to quality, the executive chef emphasized that the final selection of appetizers is ____ upon the freshness of seasonal ingredients available at the local market.', '["contingent", "incidental", "subsequent", "preliminary"]', '[]', 'contingent', '這題考查形容詞片語搭配。''be contingent upon'' 意為「視...而定」或「取決於」，是 TOEIC 高階詞彙與商務英文中的常見用法。句意為：鑑於餐廳對品質的承諾，行政主廚強調，前菜的最終選擇取決於當地市場供應的季節性食材新鮮度。(B) incidental 意為「附帶的/次要的」、(C) subsequent 意為「隨後的」、(D) preliminary 意為「初步的」，皆不符合此處表達條件關係的語境。', 'be contingent upon something', '', '', '[]', 100, false, '2026-05-06 10:42:43.907567+08', '2026-05-07 08:34:07.838197+08');
INSERT INTO public.englishchat_question_bank VALUES (210, 'ai-toeic-coca-81c9aa07fb1f746f', 'restaurant', 'reorder', 'beginner', 'Put the words in the correct order to ask for a seat at a restaurant.', '[]', '["Can", "we", "have", "a table", "for two?"]', 'Can we have a table for two?', '「Can we have a table for two?」意思是「我們可以要一個兩人的位置嗎？」。這是去餐廳時非常實用且禮貌的開場白，用來詢問是否有空位。', 'Can we have + [noun]?', '', '', '[]', 100, true, '2026-05-07 08:34:19.091846+08', '2026-05-07 08:34:19.091846+08');
INSERT INTO public.englishchat_question_bank VALUES (211, 'ai-toeic-coca-96d1a67ee75faf36', 'restaurant', 'reorder', 'intermediate', 'Please arrange the words to form a polite sentence used when calling a restaurant to make a reservation.', '[]', '["a table", "at seven tonight", "for four people", "I would like", "to book"]', 'I would like to book a table for four people at seven tonight.', '這句話是餐廳訂位的標準句型。''I would like to'' 是比 ''I want to'' 更禮貌的表達方式；''book a table'' 是常見的訂位動詞搭配；接著先接人數 ''for four people''，再接時間 ''at seven tonight''。', 'I would like to + verb (book/reserve) + a table + for [number] + at [time]', '', '', '[]', 100, true, '2026-05-07 08:34:24.446365+08', '2026-05-07 08:34:24.446365+08');
INSERT INTO public.englishchat_question_bank VALUES (212, 'ai-toeic-coca-e494ba06e66d6228', 'restaurant', 'reorder', 'advanced', 'Rearrange the following phrases to form a professional dining advisory often found on upscale restaurant websites.', '[]', '["making a reservation", "Given", "of patrons,", "the high volume", "well in advance", "we strongly recommend"]', 'Given the high volume of patrons, we strongly recommend making a reservation well in advance.', '本題測驗介係詞 ''Given'' 的用法，意為『考慮到』或『鑒於』，常置於句首引導原因。''High volume of patrons'' 是餐飲與服務業常用於描述『客流量大』的專業說法。此外，''recommend'' 後方習慣接動名詞 (making)，而 ''well in advance'' (提早許多) 則是多益高難度題目中常見的時間副詞片語。', 'Given + [Noun Phrase], [Subject] + recommend + [V-ing] + [Adverbial Phrase].', '考慮到龐大的客流量，我們強烈建議您提早預約。', '', '[]', 100, true, '2026-05-07 08:34:36.908123+08', '2026-05-07 08:34:36.908123+08');
INSERT INTO public.englishchat_question_bank VALUES (213, 'ai-toeic-coca-ad69eac6f40b546c', 'restaurant', 'translation', 'beginner', '', '[]', '[]', 'I would like to book a table for two tonight.', '主詞是 I，搭配常用動詞片語 would like to 表達委婉的請求。動詞 book 在此作「預訂」使用，後接受詞 a table（位子）。for two 是表示人數的簡潔用法。', 'I would like to + [動詞原型]', '我想要預訂兩個人今晚的位子。', 'I would like to book a table for two tonight.', '["句型：I would like to...", "動詞片語：book a table", "提示：for two (兩個人)"]', 100, true, '2026-05-07 08:34:43.278899+08', '2026-05-07 08:34:43.278899+08');
INSERT INTO public.englishchat_question_bank VALUES (214, 'ai-toeic-coca-0399692893f52cfd', 'restaurant', 'translation', 'intermediate', '', '[]', '[]', '', '這題考查餐廳訂位的常用表達方式。''Make a reservation'' 或 ''book a table'' 是非常道地的用法。''For [number]'' 用來表示人數。在詢問是否有位子時，''availability'' 是多益常見的正式單字，或是使用形容詞 ''available''。', 'make a reservation for [number] at [time]', '我們想預訂今天晚上七點四個人的位置，請問那時候還有桌位嗎？', 'We would like to make a reservation for four at 7:00 tonight. Is there any availability at that time?', '["make a reservation (預訂)", "for [number] (幾個人)", "availability (可用性/空位)"]', 100, true, '2026-05-07 08:34:49.73983+08', '2026-05-07 08:34:49.73983+08');
INSERT INTO public.englishchat_question_bank VALUES (125, 'ai-toeic-coca-fa24af024cd7815a', 'restaurant', 'translation', 'advanced', '', '[]', '[]', 'Given the surge in reservations for tonight, we are afraid we will be unable to accommodate you in a private room as scheduled unless there is a last-minute cancellation.', '此句展示了高階商務英文的用法。''Given'' 作為介係詞，表示「考慮到」或「鑑於」。''Surge'' 意指短時間內的激增。''Accommodate'' 在此情境下指「提供空間或座位」。''As scheduled'' 是常見的商務片語，指「按原定計畫」。最後使用 ''unless'' 引導條件子句，描述特定情況下的例外，這在 TOEIC 閱讀與寫作中非常常見。', 'Given + [Noun Phrase], [Clause] + unless + [Clause]', '鑑於今晚預約人數激增，我們恐怕無法如期為您安排私人包廂，除非有其他客人在最後一刻取消。', 'Given the surge in reservations for tonight, we are afraid we will be unable to accommodate you in a private room as scheduled unless there is a last-minute cancellation.', '["Given the surge in (鑑於...的激增)", "accommodate (提供空間/滿足需求)", "as scheduled (如期)", "last-minute cancellation (最後一刻的取消)"]', 100, false, '2026-05-06 10:56:04.957739+08', '2026-05-07 08:35:00.952432+08');
INSERT INTO public.englishchat_question_bank VALUES (216, 'ai-toeic-coca-48569dc17b19c9dc', 'travel', 'fill_blank', 'beginner', 'I would like to ____ a hotel room for two nights, please.', '["book", "read", "look", "talk"]', '[]', 'book', '在旅遊與商務情境中，book 作為動詞表示「預訂（房間、車票等）」。句意為「我想預訂一間飯店房間住兩個晚上」。', 'would like to + [動詞原形]', '', '', '[]', 100, true, '2026-05-07 08:35:06.317298+08', '2026-05-07 08:35:06.317298+08');
INSERT INTO public.englishchat_question_bank VALUES (217, 'ai-toeic-coca-c6439d1946095672', 'travel', 'fill_blank', 'intermediate', 'Travelers are encouraged to ____ their itineraries carefully to avoid any potential overlaps or missed connections.', '["review", "remind", "restore", "replace"]', '[]', 'review', '此題考查動詞詞義。根據句意「旅客被鼓勵仔細 ____ 他們的行程，以避免任何潛在的重疊或錯過轉機」，最符合語境的動詞是 review (審閱、檢查)。其他選項：remind (提醒)、restore (修復/恢復)、replace (替換) 在此語境下皆不恰當。', 'be encouraged to + V (被鼓勵去做某事)', '', '', '[]', 100, true, '2026-05-07 08:35:12.090382+08', '2026-05-07 08:35:12.090382+08');
INSERT INTO public.englishchat_question_bank VALUES (218, 'ai-toeic-coca-6c10a2818607020e', 'travel', 'fill_blank', 'advanced', 'Travelers are advised to review the cancellation policy thoroughly, as certain promotional fares are non-refundable and may ____ significant penalties if changes are made after the booking is confirmed.', '["incur", "entail", "solicit", "provoke"]', '[]', 'incur', '動詞 ''incur'' 常見於商務或法律情境，意為「遭受、招致（損失、罰款、費用）」。在此題中，「incur significant penalties」指的是「招致重大的罰金或處罰」。其他選項：(B) entail 意味著「使...成為必要、牽涉」，(C) solicit 為「請求、徵求」，(D) provoke 為「挑釁、激怒」，皆不符合語境。', 'incur + penalties/costs/debt', '', '', '[]', 100, true, '2026-05-07 08:35:19.867982+08', '2026-05-07 08:35:19.867982+08');
INSERT INTO public.englishchat_question_bank VALUES (219, 'ai-toeic-coca-e6c9c2c9f3af3db4', 'travel', 'reorder', 'beginner', 'Put the words in the correct order to make a sentence about travel.', '[]', '["to buy", "I", "ticket", "need", "a"]', 'I need to buy a ticket.', '這句話的意思是「我需要買一張票」。''need to'' 後面接原形動詞 ''buy''，表示『需要做某事』，是旅遊時非常實用的句型。', 'Subject + need to + verb', '我需要買一張票。', 'I need to buy a ticket.', '[]', 100, true, '2026-05-07 08:35:29.543883+08', '2026-05-07 08:35:29.543883+08');
INSERT INTO public.englishchat_question_bank VALUES (220, 'ai-toeic-coca-b4ca50df2e84c824', 'travel', 'reorder', 'intermediate', 'Rearrange the words to form a common question asked when inquiring about hotel amenities.', '[]', '["if", "Could you", "is", "complimentary", "please let me know", "the airport shuttle service"]', 'Could you please let me know if the airport shuttle service is complimentary?', '此題練習多益常見的禮貌詢問句型。''Could you please let me know'' 是常用的客氣請求，後方接 if 引導的名詞子句（意為「是否」），子句語序應為『主詞 (the airport shuttle service) + 動詞 (is) + 補語 (complimentary)』。''Complimentary'' 是多益高頻單字，意指「免費提供的」，常用於描述飯店的接駁、早餐或瓶裝水。', 'Could you please let me know if + Subject + Verb?', '', '', '[]', 100, true, '2026-05-07 08:35:40.191458+08', '2026-05-07 08:35:40.191458+08');
INSERT INTO public.englishchat_question_bank VALUES (40, 'ai-toeic-coca-9fdcf0cf2d75ae1d', 'travel', 'reorder', 'intermediate', 'To avoid any delays at the airport, please ____.', '[]', '["make", "sure", "to", "check", "in", "online", "before", "your", "flight"]', 'make sure to check in online before your flight', '此題測驗旅遊情境中常見的片語搭配。''make sure to'' 意為「務必、確保」，後面接原形動詞；''check in'' 是「辦理報到」；''online'' 在此作副詞使用，修飾報到動作。整句意為「為了避免在機場延誤，請務必在起飛前完成線上報到」。', 'make sure to + verb phrase', '', '', '[]', 100, false, '2026-05-06 10:44:06.910087+08', '2026-05-07 08:35:40.240712+08');
INSERT INTO public.englishchat_question_bank VALUES (221, 'ai-toeic-coca-82ff9c41303cf382', 'travel', 'reorder', 'advanced', 'Rearrange the following segments to form a grammatically correct sentence describing an unexpected travel situation:', '[]', '["Hardly", "had we", "checked into", "our hotel", "when", "we were", "informed that", "the tour", "had been rescheduled"]', 'Hardly had we checked into our hotel when we were informed that the tour had been rescheduled', '本題考查否定副詞 ''Hardly'' 置於句首的倒裝句型，結構為 ''Hardly + had + 主詞 + 過去分詞 + when + 主詞 + 過去式''，意為『一...就...』。這種句法常用於強調兩件事發生的時間間隔極短，在進階商務或正式旅遊情境中非常常見。''Rescheduled'' 意為『重新安排時間』，是多益常見的職場與旅遊單字。', 'Hardly + had + subject + past participle + when + subject + past tense', '', '', '[]', 100, true, '2026-05-07 08:35:49.60812+08', '2026-05-07 08:35:49.60812+08');
INSERT INTO public.englishchat_question_bank VALUES (222, 'ai-toeic-coca-96b2b95f28fdde4f', 'travel', 'translation', 'beginner', '', '[]', '[]', '', '這句話的主詞是 I（我），動詞使用 need to（需要）接原形動詞 buy（買）。目的地「去倫敦」使用介係詞 to 連接，關鍵字 train ticket 是火車票。', 'I need to + 原形動詞', '我需要買一張去倫敦的火車票。', 'I need to buy a train ticket to London.', '["句型：I need to + V", "動詞片語：buy a ticket", "單字：train (火車)"]', 100, true, '2026-05-07 08:35:57.529525+08', '2026-05-07 08:35:57.529525+08');
INSERT INTO public.englishchat_question_bank VALUES (223, 'ai-toeic-coca-ac05a2216d011fe5', 'travel', 'translation', 'intermediate', '', '[]', '[]', '', '此句使用了多益常見的委婉詢問句型 ''I would like to know if...''。''Extra charge'' 為商務與旅遊情境中常見的用法，意指「額外費用」。''Reservation'' 則是「預約/訂房」的標準單字。', 'I would like to know if it is possible to + [verb]...', '我想知道是否可以在不支付額外費用的情況下，將我的預約更改為較晚的日期。', 'I would like to know if it is possible to change my reservation to a later date without any extra charge.', '["I would like to know if...", "without any extra charge", "change one''s reservation to a later date"]', 100, true, '2026-05-07 08:36:03.145406+08', '2026-05-07 08:36:03.145406+08');
INSERT INTO public.englishchat_question_bank VALUES (238, 'ai-toeic-coca-dec4d19a741b03fa', 'school', 'reorder', 'intermediate', 'Please arrange the following words to form a complete sentence about school registration.', '[]', '["before the semester begins", "to register", "Students are", "required", "for their classes"]', 'Students are required to register for their classes before the semester begins.', '本句使用了「be required to + 原形動詞」的被動語態，表示「被要求做某事」。其中「register for」是常見的固定搭配，意為「註冊/報名...」。最後加上由 before 引導的時間副詞子句「before the semester begins」（在學期開始之前）。', 'be required to + V / register for something', '', '', '[]', 100, true, '2026-05-07 08:37:54.334247+08', '2026-05-07 08:37:54.334247+08');
INSERT INTO public.englishchat_question_bank VALUES (133, 'ai-toeic-coca-fca5d72989ba87e6', 'travel', 'translation', 'intermediate', '請將下列句子翻譯成英文：由於行程變更，我想要將我的預訂改期到下週五。', '[]', '[]', 'Due to a change in plans, I would like to reschedule my reservation to next Friday.', '本題測驗商務旅遊情境中的改期表達方式。''Due to'' 是多益常考介係詞，表示『由於』；''reschedule'' 是核心單字，意為『重新安排』；''reservation'' 則是『預訂』。''A change in plans'' 是 COCA 常用搭配詞，比 ''plan change'' 更道地。', 'Due to + noun phrase, I would like to + verb.', '由於行程變更，我想要將我的預訂改期到下週五。', 'Due to a change in plans, I would like to reschedule my reservation to next Friday.', '["Due to (由於...)", "reschedule my reservation (重新安排我的預訂)", "a change in plans (計畫變更)"]', 100, false, '2026-05-06 10:57:09.424909+08', '2026-05-07 08:36:03.194087+08');
INSERT INTO public.englishchat_question_bank VALUES (224, 'ai-toeic-coca-3484eda915140486', 'travel', 'translation', 'advanced', '', '[]', '[]', 'Given the unforeseen flight cancellation, the consultant had to revise the entire itinerary and make alternative lodging arrangements at the last minute.', '本題測驗進階商務旅遊字彙與介係詞用法。「Given」在此作為介係詞，表示「鑑於」或「考慮到」。此外，「unforeseen」（意料之外的）、「itinerary」（行程）與「lodging arrangements」（住宿安排）皆為多益高頻且專業的用法。最後一刻的變更通常使用「at the last minute」來表達。', 'Given + Noun Phrase, Subject + Verb', '鑑於航班意外取消，該顧問不得不修改整個行程，並在最後一刻對住宿做出替代安排。', 'Given the unforeseen flight cancellation, the consultant had to revise the entire itinerary and make alternative lodging arrangements at the last minute.', '["Given (prep.) 鑑於/考量到", "unforeseen (adj.) 意外的/無法預見的", "itinerary (n.) 行程", "lodging arrangements (n. phr.) 住宿安排"]', 100, true, '2026-05-07 08:36:13.146642+08', '2026-05-07 08:36:13.146642+08');
INSERT INTO public.englishchat_question_bank VALUES (225, 'ai-toeic-coca-d0fc219fd0104328', 'shopping', 'fill_blank', 'beginner', 'I like this red shirt. Do you have it ____ a larger size?', '["in", "on", "at"]', '[]', 'in', '在英文中，描述衣服的尺寸（size）或顏色（color）時，習慣搭配介係詞「in」。例如：in a larger size（大一點的尺寸）或 in blue（藍色的）。', 'have something in + size/color', '', '', '[]', 100, true, '2026-05-07 08:36:22.241323+08', '2026-05-07 08:36:22.241323+08');
INSERT INTO public.englishchat_question_bank VALUES (226, 'ai-toeic-coca-4d67f1d9048bb081', 'shopping', 'fill_blank', 'intermediate', 'Customers who sign up for our loyalty program are ____ to receive a 15% discount on their first purchase.', '["eligible", "available", "profitable", "convenient"]', '[]', 'eligible', '這題考查形容詞用法。''be eligible to'' 意為『有資格做某事』，在 TOEIC 購物與促銷情境中非常常見。''available'' (可得到的) 通常主詞為物；''profitable'' (有利潤的) 與 ''convenient'' (方便的) 則不符合此處語境。', 'be eligible to + verb', '', '', '[]', 100, true, '2026-05-07 08:36:27.928473+08', '2026-05-07 08:36:27.928473+08');
INSERT INTO public.englishchat_question_bank VALUES (227, 'ai-toeic-coca-4e4529c30a7a3950', 'shopping', 'fill_blank', 'advanced', 'The boutique''s strategic decision to offer exclusive membership perks has significantly ____ their customer retention rates, setting a new benchmark for the luxury retail sector.', '["bolstered", "stagnated", "diminished", "curtailed"]', '[]', 'bolstered', '這題考查動詞詞彙。''Bolster'' 意為「加強、提升」，在商業與零售情境中常用來形容數據、信心或績效的改善。句意為：該精品店提供專屬會員福利的策略性決定，顯著提升了其客戶留存率，為奢侈品零售業樹立了新基準。其他選項：stagnated（停滯）、diminished（減少）、curtailed（縮減）在語義上均與句中的正面成效不符。', 'bolster + noun (e.g., retention rates, economy, sales)', '', '', '[]', 100, true, '2026-05-07 08:36:35.04136+08', '2026-05-07 08:36:35.04136+08');
INSERT INTO public.englishchat_question_bank VALUES (228, 'ai-toeic-coca-551a733b2927b8b2', 'shopping', 'reorder', 'beginner', 'Put the words in the correct order to complete the sentence.', '[]', '["want to", "credit card", "by", "pay", "I"]', 'I want to pay by credit card', '這題考查購物時常用的支付表達方式。''want to'' 後面接原形動詞 ''pay''，而 ''by credit card'' 表示『使用信用卡付款』。', 'Subject + want to + verb', '我想要用信用卡付錢。', '', '[]', 100, true, '2026-05-07 08:36:41.802686+08', '2026-05-07 08:36:41.802686+08');
INSERT INTO public.englishchat_question_bank VALUES (229, 'ai-toeic-coca-270ae71d4742aa4a', 'shopping', 'reorder', 'intermediate', 'Rearrange the words to form a polite inquiry about a store''s return policy.', '[]', '["Could you please", "tell me", "if", "this item", "is eligible", "for", "a full refund?"]', 'Could you please tell me if this item is eligible for a full refund?', '這句話使用了間接問句的結構 ''Could you please tell me if...''，用來禮貌地詢問某事是否屬實。''be eligible for'' 是一個常用的商務與購物片語，表示「有資格獲得...」或「符合...的條件」。''Full refund'' 則是「全額退款」的意思，在多益購物情境中非常常見。', 'Could you please tell me if + Subject + Verb + ...', '', '', '[]', 100, true, '2026-05-07 08:36:47.026207+08', '2026-05-07 08:36:47.026207+08');
INSERT INTO public.englishchat_question_bank VALUES (230, 'ai-toeic-coca-27c13087c3a37236', 'shopping', 'reorder', 'advanced', 'Rearrange the following segments to form a coherent sentence regarding a store''s return policy.', '[]', '["the store manager", "was reluctant to", "issue a full refund,", "given that", "the promotional period", "had already lapsed"]', 'The store manager was reluctant to issue a full refund, given that the promotional period had already lapsed.', '這句話描述店經理不願意退還全額款項，因為促銷期間已經結束。''Reluctant to'' 表示不情願、勉強，是多益高階常用詞彙；''given that'' 是進階連接詞，表示「考慮到/鑒於...」；''lapse'' 在此指（權利、效期、合約等）失效或過期。', 'be reluctant to + V / given that + Clause', '', '', '[]', 100, true, '2026-05-07 08:36:53.748984+08', '2026-05-07 08:36:53.748984+08');
INSERT INTO public.englishchat_question_bank VALUES (50, 'ai-toeic-coca-d58e100e090028b5', 'shopping', 'reorder', 'advanced', 'Rearrange the following segments to form a logical sentence regarding a store''s announcement about shipping:', '[]', '["shoppers place their orders", "Given the current supply chain disruptions,", "well in advance", "it is highly recommended that", "to avoid any potential delivery delays."]', 'Given the current supply chain disruptions, it is highly recommended that shoppers place their orders well in advance to avoid any potential delivery delays.', '本題測驗「Given (考慮到/鑒於)」作為前置介係詞的用法，以及「It is recommended that + 主詞 + 原形動詞」的虛擬語氣結構（此處 place 為原形）。此外，''well in advance'' 是進階常用片語，表示『提早許多』，''supply chain disruptions'' 則反映了現代商業環境的常見情境。', 'Given + N (considering), and Subjunctive Mood (It is recommended that + S + V)', '', '', '[]', 100, false, '2026-05-06 10:45:36.153252+08', '2026-05-07 08:36:53.798032+08');
INSERT INTO public.englishchat_question_bank VALUES (231, 'ai-toeic-coca-6a4af81c4affaead', 'shopping', 'translation', 'beginner', '', '[]', '[]', 'I want to buy a new bag.', '本題主詞為 I，動詞使用 want to 表示「想要」，後接原形動詞 buy。關鍵單字 new (新的) 為形容詞，應置於名詞 bag 之前。', 'I want to + [verb]', '我想要買一個新包包。', 'I want to buy a new bag.', '["句型提示：I want to + 動詞 (我想要...)", "動詞片語：buy a bag (買一個包包)", "單字提示：new (新的) 為形容詞"]', 100, true, '2026-05-07 08:37:00.542611+08', '2026-05-07 08:37:00.542611+08');
INSERT INTO public.englishchat_question_bank VALUES (243, 'ai-toeic-coca-bef14696e390acea', 'fitness', 'fill_blank', 'beginner', 'Mike ____ to the gym three times a week to stay fit.', '["goes", "go", "going"]', '[]', 'goes', '主詞 Mike 為第三人稱單數，在描述規律的習慣（簡單現在式）時，動詞 go 必須加上 es 變為 goes。', 'Subject (3rd person singular) + Verb-s/es', '', '', '[]', 100, true, '2026-05-07 08:38:28.098823+08', '2026-05-07 08:38:28.098823+08');
INSERT INTO public.englishchat_question_bank VALUES (232, 'ai-toeic-coca-38e4d714012b43f5', 'shopping', 'translation', 'intermediate', '', '[]', '[]', 'If you are not completely satisfied with your purchase, you can request a full refund within 30 days as long as you keep the receipt.', '這句話使用了多益常見的購物與售後服務情境。''be satisfied with'' 是表達對事物滿意度的標準用法；''full refund'' 指的是『全額退款』；''as long as'' 是常用的連接詞，表示『只要...』；''receipt'' (收據) 是多益必考的核心單字，注意其字母 p 不發音。', 'be satisfied with / full refund / as long as', '如果您對購買的商品不完全滿意，只要保留收據，您可以在 30 天內要求全額退款。', 'If you are not completely satisfied with your purchase, you can request a full refund within 30 days as long as you keep the receipt.', '["be satisfied with (對...滿意)", "full refund (全額退款)", "as long as (只要...的話)", "keep the receipt (保留收據)"]', 100, true, '2026-05-07 08:37:09.257699+08', '2026-05-07 08:37:09.257699+08');
INSERT INTO public.englishchat_question_bank VALUES (142, 'ai-toeic-coca-778eab7de2ea13ca', 'shopping', 'translation', 'intermediate', '', '[]', '[]', '', '這句話常用於零售業的退換貨政策。''be satisfied with'' 表示對某事物感到滿意；''full refund'' 指的是全額退款；''within'' 用來表達在一段特定的時間範圍內，是多益（TOEIC）購物情境中極為常見的介系詞用法。', 'be satisfied with / full refund / within', '如果你對所購買的商品不滿意，可以在 30 天內退貨並獲得全額退款。', 'If you are not satisfied with your purchase, you can return the item for a full refund within 30 days.', '["be satisfied with (對...滿意)", "full refund (全額退款)", "within ... days (在...天之內)"]', 100, false, '2026-05-06 10:58:21.741348+08', '2026-05-07 08:37:09.306987+08');
INSERT INTO public.englishchat_question_bank VALUES (233, 'ai-toeic-coca-f8ce8d9a632c73af', 'shopping', 'translation', 'advanced', '', '[]', '[]', 'To maintain an edge in the highly competitive market, the retailer decided to curate its product collection and implement a loyalty program aimed at rewarding frequent shoppers.', '本題考查進階商務與購物情境詞彙。''maintain an edge'' 意為保持競爭優勢；''curate'' 在零售語境中指『精心挑選與策劃商品』；''implement a loyalty program'' 為實施忠誠度計畫的標準表達方式；''aimed at'' 後接動名詞，表示該計畫的目的或針對的對象。', 'To [verb phrase], the [subject] decided to [verb phrase] and [verb phrase] aimed at [verb-ing].', '為了在競爭激烈的市場中保持優勢，該零售商決定精心挑選其商品系列，並實施一項旨在獎勵常客的忠誠度計畫。', 'To maintain an edge in the highly competitive market, the retailer decided to curate its product collection and implement a loyalty program aimed at rewarding frequent shoppers.', '["maintain an edge (保持優勢)", "curate (精心挑選/策劃)", "implement a loyalty program (實施忠誠度計畫)", "aimed at (旨在...)"]', 100, true, '2026-05-07 08:37:17.507372+08', '2026-05-07 08:37:17.507372+08');
INSERT INTO public.englishchat_question_bank VALUES (53, 'ai-toeic-coca-a9b00c238f56daec', 'shopping', 'translation', 'advanced', '', '[]', '[]', '', '這題測驗進階商務購物與採購情境。''Given'' 在此作為介系詞，表示「考慮到」或「鑑於」；''fluctuations'' 指波動；''take advantage of'' 是商用英文中極常見的「利用（機會、優惠）」；''in advance of'' 等同於 before，但更具正式感；''stockouts'' 則是專業的「缺貨」術語。', 'Given + N, S + V + to avoid + N.', '考慮到最近供應鏈的波動，我們強烈建議客戶在旺季到來之前，利用目前的折扣提前下單，以避免潛在的缺貨情況。', 'Given the recent supply chain fluctuations, we strongly suggest that customers take advantage of current discounts and place their orders in advance of the peak season to avoid potential stockouts.', '["Given the recent fluctuations (考慮到最近的波動)", "take advantage of (利用)", "place orders in advance (提前下單)", "peak season (旺季)", "potential stockouts (潛在的缺貨)"]', 100, false, '2026-05-06 10:46:01.237241+08', '2026-05-07 08:37:17.557488+08');
INSERT INTO public.englishchat_question_bank VALUES (143, 'ai-toeic-coca-03b081339d6fc490', 'shopping', 'translation', 'advanced', '', '[]', '[]', '', '此題測驗進階購物相關詞彙與句型。''Hefty price tag'' 是道地描述「價格不菲」的用法；''much to the chagrin of someone'' 是一個進階片語，表示「令某人感到遺憾、懊惱或失望」；''queue'' 常用於描述排隊，在此使用過去完成進行式 ''had been queuing'' 強調在售罄之前的持續動作。', 'Despite [Noun Phrase], [Clause], much to the chagrin of [Someone].', '儘管價格高昂，這款限量版手提包在幾分鐘內就售罄了，這讓那些從黎明就開始排隊的忠實顧客感到非常遺憾。', 'Despite the hefty price tag, the limited edition handbag sold out within minutes, much to the chagrin of the loyal customers who had been queuing since dawn.', '["hefty price tag (高昂的價格)", "much to the chagrin of (令某人感到遺憾/懊惱)", "sell out (售罄)", "queue since dawn (從黎明起排隊)"]', 100, false, '2026-05-06 10:58:29.705245+08', '2026-05-07 08:37:17.557488+08');
INSERT INTO public.englishchat_question_bank VALUES (234, 'ai-toeic-coca-922d9f3e49fb6912', 'school', 'fill_blank', 'beginner', 'Please ____ your books to page 20.', '["open", "read", "write", "talk"]', '[]', 'open', '這是一句常用的課堂指令。「Please open your books to page...」意為「請把書翻到第...頁」。其他選項：read (閱讀)、write (寫)、talk (說話) 在此固定用法中較不常用或語意不合。', 'Please + 動詞原形 (祈使句)', '', '', '[]', 100, true, '2026-05-07 08:37:24.155923+08', '2026-05-07 08:37:24.155923+08');
INSERT INTO public.englishchat_question_bank VALUES (235, 'ai-toeic-coca-3f43aeb3c742c720', 'school', 'fill_blank', 'intermediate', 'The university administration has decided to ____ the deadline for the scholarship application due to technical issues with the website.', '["extend", "expand", "prolong", "stretch"]', '[]', 'extend', '在英文中，表示「延長」截止日期時，最常見且標準的動詞搭配是 extend (extend the deadline)。expand 通常指空間、規模或業務的「擴張」；prolong 雖然也是延長，但多指延長某種狀態、生命或過程（通常帶有負面或中性意味）；stretch 則是指物理上的「拉長」或資源的「攤平」。', 'extend the deadline', '', '', '[]', 100, true, '2026-05-07 08:37:31.590441+08', '2026-05-07 08:37:31.590441+08');
INSERT INTO public.englishchat_question_bank VALUES (236, 'ai-toeic-coca-ac52253b36dbe8f8', 'school', 'fill_blank', 'advanced', 'The board of directors is currently reviewing the proposal to ____ the existing curriculum to better align with the evolving demands of the job market.', '["overhaul", "overlook", "overrule", "overtake"]', '[]', 'overhaul', 'overhaul 意為「全面改革」或「徹底檢修」。在此情境中，學校董事會正在審查「全面改革」現有課程的提案，以使其更符合就業市場不斷變化的需求。其他選項：overlook (忽略)、overrule (駁回/否決)、overtake (追上/超過) 皆不符合句意。', 'proposal to + verb (infinitive)', '', '', '[]', 100, true, '2026-05-07 08:37:40.531717+08', '2026-05-07 08:37:40.531717+08');
INSERT INTO public.englishchat_question_bank VALUES (237, 'ai-toeic-coca-db8b44880d071c9d', 'school', 'reorder', 'beginner', 'Please reorder the following words to form a correct sentence: (我們今天有一場數學考試。)', '[]', '["have", "today", "We", "a math test"]', 'We have a math test today', '這是一個簡單的基礎句型。We (我們) 是主詞，have (有) 是動詞，a math test (一場數學考試) 是受詞。時間副詞 today (今天) 通常習慣放在句子的最後面。', 'Subject + Verb + Object + Time adverb', '', '', '[]', 100, true, '2026-05-07 08:37:48.750078+08', '2026-05-07 08:37:48.750078+08');
INSERT INTO public.englishchat_question_bank VALUES (261, 'ai-toeic-coca-199694c6e5cb1182', 'weather', 'fill_blank', 'beginner', 'It is very ____ today, so please bring an umbrella with you.', '["rainy", "sunny", "hot"]', '[]', 'rainy', '根據後半句的 ''bring an umbrella''（帶雨傘），可以推論天氣是下雨的。''rainy'' 是形容詞，表示『下雨的』，符合句意。', 'It is + [weather adjective].', '', '', '[]', 100, true, '2026-05-07 08:40:34.215575+08', '2026-05-07 08:40:34.215575+08');
INSERT INTO public.englishchat_question_bank VALUES (239, 'ai-toeic-coca-6b985681fcf150d2', 'school', 'reorder', 'advanced', 'Rearrange the following segments to form a grammatically correct sentence regarding a university''s strategic planning.', '[]', '["is considering", "the administration", "the application process", "to attract", "streamlining", "a more diverse student body"]', 'The administration is considering streamlining the application process to attract a more diverse student body.', '此句展示了進階的行政英文用法。''Consider'' 後接動名詞 (V-ing) ''streamlining''，意為『考慮簡化』。''Streamline'' 是 TOEIC 高頻單字，指使流程更有效率。''Student body'' 指全體學生。整句結構為：主詞 + 正在考慮 + 動名詞受詞 + 目的狀語（to-V）。', 'Subject + be considering + V-ing + Object + to-infinitive phrase', '', '', '[]', 100, true, '2026-05-07 08:38:03.925928+08', '2026-05-07 08:38:03.925928+08');
INSERT INTO public.englishchat_question_bank VALUES (59, 'ai-toeic-coca-7fbd5c44d206de3a', 'school', 'reorder', 'advanced', 'Rearrange the following segments to form a coherent sentence regarding academic policy updates.', '[]', '["the university administration", "is currently re-evaluating", "the prerequisites for", "the advanced seminar", "to ensure all participants", "have the necessary", "foundational knowledge"]', 'The university administration is currently re-evaluating the prerequisites for the advanced seminar to ensure all participants have the necessary foundational knowledge.', '此句描述大學行政部門正在重新評估進階研討會的先修條件，以確保所有參與者具備必要的基礎知識。句構採用「主詞 + be + currently + V-ing + 受詞」結構，並以不定詞片語 (to ensure...) 表達目的。關鍵詞彙包含 prerequisites (先修條件) 與 foundational knowledge (基礎知識)，皆為 TOEIC 與學術情境常見用法。', 'Subject + be + currently + V-ing + Object + to + infinitive (purpose)', '', '', '[]', 100, false, '2026-05-06 10:46:43.090148+08', '2026-05-07 08:38:04.086216+08');
INSERT INTO public.englishchat_question_bank VALUES (149, 'ai-toeic-coca-60de10e81506dd53', 'school', 'reorder', 'advanced', 'The university board recently announced a comprehensive curriculum overhaul. When questioned by the student union regarding potential quality issues,', '[]', '["the dean emphasized", "that", "under no circumstances", "will", "the core academic standards", "be compromised", "during this transition"]', 'the dean emphasized that under no circumstances will the core academic standards be compromised during this transition', '本題考查進階文法中的「否定倒裝句」。當否定意義的副詞片語「under no circumstances」（在任何情況下都不）置於子句開頭以示強調時，其後的子句須採用倒裝語序，即「助動詞 (will) + 主詞 (the core academic standards) + 動詞 (be compromised)」。此句型在 TOEIC 閱讀與正式商務/學術書信中相當常見，用以表達堅定的立場。', 'Negative inversion: under no circumstances + auxiliary verb + subject + main verb', '院長強調，在這次轉型期間，核心學術標準在任何情況下都不會受到妥協。', 'the dean emphasized that under no circumstances will the core academic standards be compromised during this transition', '["Under no circumstances 為否定起首的倒裝句型", "Compromise 在此作動詞，意為「損害、妥協」", "Transition 指「過渡時期、轉型期」"]', 100, false, '2026-05-06 10:59:15.385532+08', '2026-05-07 08:38:04.086216+08');
INSERT INTO public.englishchat_question_bank VALUES (240, 'ai-toeic-coca-5f47347ab4893650', 'school', 'translation', 'beginner', '', '[]', '[]', 'The students are studying in the library.', '本句使用現在進行式（be + V-ing）來描述正在發生的動作。主詞是複數名詞「students」，因此 be 動詞配合使用「are」。關鍵字「library」是圖書館的意思。', 'Present Continuous Tense (S + be + V-ing)', '學生們正在圖書館裡讀書。', 'The students are studying in the library.', '["句型提示：主詞 + be動詞 + V-ing", "關鍵片語：study in the library", "單字提示：students (學生)"]', 100, true, '2026-05-07 08:38:10.218029+08', '2026-05-07 08:38:10.218029+08');
INSERT INTO public.englishchat_question_bank VALUES (241, 'ai-toeic-coca-85a6924f682cc1b7', 'school', 'translation', 'intermediate', '', '[]', '[]', 'Please remember to submit your final assignment before the deadline on Friday.', '這句話使用了「remember to + 原形動詞」來表示『記得要做某事』。動詞 submit 是「繳交」的正式用法，在學校或職場情境中非常常見。deadline 意為「截止日期」，通常與介系詞 before（在...之前）連用來指明時限。', 'remember to + V / submit something before the deadline', '請記得在週五截止日期前繳交你的期末作業。', 'Please remember to submit your final assignment before the deadline on Friday.', '["remember to + V (記得要做...)", "submit (繳交)", "deadline (截止日期)"]', 100, true, '2026-05-07 08:38:16.064361+08', '2026-05-07 08:38:16.064361+08');
INSERT INTO public.englishchat_question_bank VALUES (61, 'ai-toeic-coca-1916f2c1943dcf97', 'school', 'translation', 'intermediate', '', '[]', '[]', 'In order to be eligible for the scholarship, students must submit all transcripts by the end of the month.', '這題測驗多益校園情境中常見的詞彙與用法。「be eligible for」表示「有資格獲得...」，「submit」是「提交」，而「transcript」在學術情境中指的是「成績單」。時間介系詞「by」用於表達「在某個時間點之前」。', 'In order to + VR, [Subject] + must + VR', '為了符合獎學金的申請資格，學生必須在月底前提交所有成績單。', 'In order to be eligible for the scholarship, students must submit all transcripts by the end of the month.', '["be eligible for (符合...的資格)", "submit (提交)", "transcript (成績單)"]', 100, false, '2026-05-06 10:46:58.882762+08', '2026-05-07 08:38:16.113344+08');
INSERT INTO public.englishchat_question_bank VALUES (242, 'ai-toeic-coca-1b420859ba95f034', 'school', 'translation', 'advanced', '', '[]', '[]', 'Given the recent budget cuts, the university administration has decided to prioritize funding for interdisciplinary research projects that demonstrate clear societal impact.', '這句話展現了高等教育行政中的常見情境。''Given'' 在此作介係詞，意為「鑑於」或「考慮到」，常用於說明決策背景。''Prioritize''（優先處理）是 TOEIC 高頻動詞。''Interdisciplinary''（跨領域的）與 ''societal impact''（社會影響力）則是學術與專業環境中的進階用法。', 'Given + N, S + V + O', '鑑於最近的預算削減，大學行政部門已決定優先資助那些展現出明確社會影響力的跨領域研究計畫。', 'Given the recent budget cuts, the university administration has decided to prioritize funding for interdisciplinary research projects that demonstrate clear societal impact.', '["Given the recent budget cuts (鑑於最近的預算削減)", "prioritize funding for (優先資助)", "interdisciplinary research projects (跨領域研究計畫)", "demonstrate clear societal impact (展現明確的社會影響力)"]', 100, true, '2026-05-07 08:38:23.184172+08', '2026-05-07 08:38:23.184172+08');
INSERT INTO public.englishchat_question_bank VALUES (152, 'ai-toeic-coca-df2eef6e18d1bf1e', 'school', 'translation', 'advanced', '', '[]', '[]', '', '此題測驗進階學術與行政相關詞彙。''Cultivate'' (培養) 與 ''well-rounded'' (全方位的/通才) 是描述教育目標的常用詞。''Undertake'' 表示著手進行某項任務。''Incorporate... into...'' 是常見的組合，意為將某物納入。''Interdisciplinary'' (跨學科) 則符合現代高等教育的趨勢。', 'To + V... (目的), [Subject] is undertaking [Action] to incorporate [A] into [B].', '為了將學生成長為具備批判性思考能力的通才，學校管理層正著手進行課程改革，將跨領域研究計畫納入教學大綱中。', 'To cultivate students into well-rounded individuals with critical thinking skills, the school administration is undertaking a curriculum reform to incorporate interdisciplinary research projects into the syllabus.', '["well-rounded individuals (通才/全方位的人才)", "undertake a reform (著手進行改革)", "incorporate something into something (將某物納入某物)", "interdisciplinary (跨學科的)"]', 100, false, '2026-05-06 10:59:36.161893+08', '2026-05-07 08:38:23.233251+08');
INSERT INTO public.englishchat_question_bank VALUES (244, 'ai-toeic-coca-34797fa7cef926d0', 'fitness', 'fill_blank', 'intermediate', 'To see significant results, experts recommend that you ____ a consistent workout routine rather than exercising only occasionally.', '["stick to", "give up", "look for", "put off"]', '[]', 'stick to', 'stick to 是一個常見的動詞片語，意為「堅持」或「遵循」。在健身情境中，stick to a routine（堅持規律運動）是符合 COCA 常用搭配的用法。其餘選項：give up（放棄）、look for（尋找）、put off（延期）皆不符合句意。', 'stick to + noun (routine/plan/diet)', '', '', '[]', 100, true, '2026-05-07 08:38:33.10149+08', '2026-05-07 08:38:33.10149+08');
INSERT INTO public.englishchat_question_bank VALUES (245, 'ai-toeic-coca-bfea8d51fb088bb6', 'fitness', 'fill_blank', 'advanced', 'To overcome his training ____, the athlete consulted a sports nutritionist to fine-tune his macronutrient intake and optimize his recovery schedule.', '["plateau", "pinnacle", "deficit", "momentum"]', '[]', 'plateau', '在健身與運動情境中，''plateau'' 指的是進步陷入停滯的「平台期」或「停滯期」。句意為：『為了克服訓練停滯期，該運動員諮詢了運動營養師，以微調其宏量營養素攝取並優化其恢復時程。』其餘選項：pinnacle (巔峰)、deficit (赤字/不足)、momentum (動力/勢頭) 皆不符合語境。', 'To overcome a training plateau', '', '', '[]', 100, true, '2026-05-07 08:38:38.540938+08', '2026-05-07 08:38:38.540938+08');
INSERT INTO public.englishchat_question_bank VALUES (246, 'ai-toeic-coca-762871bfa3ec896f', 'fitness', 'reorder', 'beginner', 'Please put the words in the correct order to describe a workout habit.', '[]', '["every morning", "the gym", "I", "go to"]', 'I go to the gym every morning.', '這句話描述的是日常運動習慣。主詞是 I (我)，接著使用動詞片語 go to (去)，受詞為地點 the gym (健身房)，最後放上時間副詞 every morning (每天早上)。', 'Subject + Verb + Place + Time', '', '', '[]', 100, true, '2026-05-07 08:38:45.609261+08', '2026-05-07 08:38:45.609261+08');
INSERT INTO public.englishchat_question_bank VALUES (247, 'ai-toeic-coca-bb34a902691c518a', 'fitness', 'reorder', 'intermediate', 'To maintain gym hygiene, please arrange the following words to form a complete sentence:', '[]', '["after you", "the equipment", "to wipe down", "finish your workout", "Please make sure"]', 'Please make sure to wipe down the equipment after you finish your workout.', '這句話常用於健身房提醒使用者在使用完器材後進行清潔。''Make sure to'' 後接原形動詞表示『務必/確保去做某事』，''wipe down'' 是常見動詞片語，意為『擦拭乾淨』，''after you finish your workout'' 為時間副詞子句，描述動作發生的時間點。', 'Make sure to + base verb + after + clause', '為了維持健身房衛生，請確保在完成運動後擦拭器材。', 'Please make sure to wipe down the equipment after you finish your workout.', '[]', 100, true, '2026-05-07 08:38:51.517281+08', '2026-05-07 08:38:51.517281+08');
INSERT INTO public.englishchat_question_bank VALUES (248, 'ai-toeic-coca-a356c53ac07e2e09', 'fitness', 'reorder', 'advanced', 'Rearrange the following phrases to form a grammatically correct sentence describing an effective fitness strategy.', '[]', '["can significantly boost", "Incorporating", "your metabolic rate", "into your routine", "high-intensity interval training", "even after the workout is over"]', 'Incorporating high-intensity interval training into your routine can significantly boost your metabolic rate even after the workout is over.', '本句主詞為動名詞片語 ''Incorporating high-intensity interval training into your routine''（將高強度間歇訓練納入你的日常健身計畫）。動詞為 ''can significantly boost''（能顯著提升），受詞為 ''your metabolic rate''（你的代謝率）。結尾加上時間副詞子句 ''even after the workout is over''（甚至在運動結束之後）。這種「動名詞片語當主詞」的結構在正式的健身或健康建議中非常常見，用來描述某種行為帶來的具體效益。', 'Incorporating [Activity] into [Routine] + can + [Verb] + [Object]', '', '', '[]', 100, true, '2026-05-07 08:39:01.231867+08', '2026-05-07 08:39:01.231867+08');
INSERT INTO public.englishchat_question_bank VALUES (68, 'ai-toeic-coca-ff5f8d4f5565cae2', 'fitness', 'reorder', 'advanced', 'Rearrange the following phrases to form a coherent sentence about advanced fitness strategies:', '[]', '["significantly enhances", "into your routine", "metabolic rate", "not only boosts cardiovascular health", "but also", "Incorporating high-intensity interval training"]', 'Incorporating high-intensity interval training into your routine not only boosts cardiovascular health but also significantly enhances metabolic rate.', '此句使用了動名詞片語 ''Incorporating... training'' 作為句子的主詞。接著使用 ''not only... but also...'' 的對等連接詞結構，連接兩個平行結構的動詞片語 ''boosts cardiovascular health'' 與 ''significantly enhances metabolic rate''。這類句型在多益（TOEIC）與專業健身文獻中常用於強調某項行動的多重正面效益。', 'Incorporating [Activity] into [Routine] not only [Benefit A] but also [Benefit B].', '將高強度間歇訓練納入你的日常健身計畫中，不僅能增進心血管健康，還能顯著提升代謝率。', 'Incorporating high-intensity interval training into your routine not only boosts cardiovascular health but also significantly enhances metabolic rate.', '["Not only... but also... (對等連接詞)", "Gerund as subject (動名詞當主詞)", "Collocation: metabolic rate (代謝率)"]', 100, false, '2026-05-06 10:47:46.123054+08', '2026-05-07 08:39:01.285713+08');
INSERT INTO public.englishchat_question_bank VALUES (158, 'ai-toeic-coca-850459b6f0a9da04', 'fitness', 'reorder', 'advanced', 'Rearrange the following phrases to form a grammatically correct and coherent sentence regarding modern fitness strategies.', '[]', '["To optimize cardiovascular health,", "fitness experts recommend", "incorporating", "high-intensity interval training", "into your weekly routine."]', 'To optimize cardiovascular health, fitness experts recommend incorporating high-intensity interval training into your weekly routine.', '本題考查「目的狀語」與「動詞用法」。句首以不定詞 ''To optimize...'' 表示目的（為了優化...）。主句動詞 ''recommend'' 後方習慣接動名詞 ''incorporating''（納入）。此外，''incorporate'' 常與介係詞 ''into'' 連用，指將某項活動併入既有的常規（routine）中。這類句型在多益健康講座或專業建議情境中非常常見。', 'To + V (purpose), [Subject] + recommend + V-ing + [Something] + into [Routine/System]', '為了優化心血管健康，健身專家建議將高強度間歇訓練納入你的每週例行運動中。', '', '[]', 100, false, '2026-05-06 11:00:30.732083+08', '2026-05-07 08:39:01.285713+08');
INSERT INTO public.englishchat_question_bank VALUES (249, 'ai-toeic-coca-7aa1c98df5624b12', 'fitness', 'translation', 'beginner', '', '[]', '[]', 'I go to the gym three times a week.', '主詞是 I，動詞使用現在簡單式 go。關鍵字 gym 是健身房的意思，而 three times a week 放在句尾表示頻率。', 'Subject + Verb + Place + Frequency', '我一星期去健身房三次。', 'I go to the gym three times a week.', '["句型提示：主詞 + 動詞 + 地點 + 頻率", "關鍵動詞片語：go to the gym", "單字提示：一星期三次是 three times a week"]', 100, true, '2026-05-07 08:39:08.339859+08', '2026-05-07 08:39:08.339859+08');
INSERT INTO public.englishchat_question_bank VALUES (250, 'ai-toeic-coca-afa6c79a7e3c31d9', 'fitness', 'translation', 'intermediate', '', '[]', '[]', 'To achieve your fitness goals, it is essential to exercise consistently and maintain a balanced diet.', '此題測驗「不定詞表示目的」與「虛主詞 it」的用法。句首使用 To achieve your fitness goals 表示『為了達成...』。主句使用 It is essential to... 結構來強調重要性。關鍵詞彙包含 achieve (達成)、consistently (規律地/持之以恆地) 以及 balanced diet (均衡飲食)。', 'To + V..., it is essential to + V...', '為了達到你的健身目標，持之以恆地運動並搭配均衡飲食是非常重要的。', 'To achieve your fitness goals, it is essential to exercise consistently and maintain a balanced diet.', '["achieve goals (達成目標)", "exercise consistently (持續運動)", "balanced diet (均衡飲食)"]', 100, true, '2026-05-07 08:39:14.412911+08', '2026-05-07 08:39:14.412911+08');
INSERT INTO public.englishchat_question_bank VALUES (160, 'ai-toeic-coca-0ca6e18899dfa17d', 'fitness', 'translation', 'intermediate', '請將下列句子翻譯成英文。', '[]', '[]', 'To stay in shape, many office workers choose to work out at the gym after work.', '本題測驗目的狀語與習慣表達。''To stay in shape'' 是『為了保持身材』，''office workers'' 指的是『上班族』，''work out'' 是描述健身或運動最道地的動詞片語。此外，''after work'' 為固定用法，不需加冠詞。', 'To + V (目的), [Subject] + choose to + V', '為了保持身材，許多上班族選擇在下班後去健身房運動。', 'To stay in shape, many office workers choose to work out at the gym after work.', '["保持身材: stay in shape", "上班族: office workers", "健身/運動: work out"]', 100, false, '2026-05-06 11:00:47.326929+08', '2026-05-07 08:39:14.464004+08');
INSERT INTO public.englishchat_question_bank VALUES (251, 'ai-toeic-coca-52c5e8b7f9f2959f', 'fitness', 'translation', 'advanced', '', '[]', '[]', 'To mitigate the health risks associated with a sedentary lifestyle, the company has implemented a holistic wellness program that incorporates tailored workout regimens.', '此句使用了進階職場與健身相關詞彙：''mitigate''（減輕/緩和）、''sedentary lifestyle''（久坐不動的生活方式）、''holistic''（全方位的/整體的）以及 ''tailored workout regimens''（量身定制的健身計畫）。''incorporate'' 意為納入或包含，是多益高頻動詞。', 'To mitigate..., the [organization] has implemented... that incorporates...', '為了減輕與久坐生活方式相關的健康風險，公司實施了一套包含客製化健身方案的全方位健康計畫。', 'To mitigate the health risks associated with a sedentary lifestyle, the company has implemented a holistic wellness program that incorporates tailored workout regimens.', '["mitigate (v.) 減輕/緩和", "sedentary lifestyle (n. phr.) 久坐的生活方式", "holistic wellness (n. phr.) 全方位健康/身心靈健康", "tailored workout regimens (n. phr.) 量身定制的健身方案"]', 100, true, '2026-05-07 08:39:21.943957+08', '2026-05-07 08:39:21.943957+08');
INSERT INTO public.englishchat_question_bank VALUES (161, 'ai-toeic-coca-bd82fb5764111f11', 'fitness', 'translation', 'advanced', '', '[]', '[]', '', '此句運用了進階詞彙如 ''optimize'' (優化) 及 ''tailored to'' (量身打造)。''Regimen'' 在健身與醫療情境中指「有系統的計畫」。''Well-being'' 是 COCA 高頻詞，指身心健康的整體狀態。''Tailored to'' 常用於描述根據特定需求而設計的專業服務，符合 TOEIC 高階商務與生活情境。', 'To optimize..., [Subject] will [Verb]... tailored to...', '為了優化您的心血管健康與整體福祉，我們的認證教練將根據您的具體目標和身體狀況，為您量身打造一套個人化的健身計畫。', 'To optimize your cardiovascular health and overall well-being, our certified trainers will design a personalized fitness regimen tailored to your specific goals and physical condition.', '["optimize (v.) 優化", "well-being (n.) 福祉/身心健康", "personalized fitness regimen (n.) 個人化健身計畫", "tailored to (adj. phr.) 為...量身定做的"]', 100, false, '2026-05-06 11:00:54.656459+08', '2026-05-07 08:39:21.992954+08');
INSERT INTO public.englishchat_question_bank VALUES (71, 'ai-toeic-coca-8719873987d84569', 'fitness', 'translation', 'advanced', '', '[]', '[]', 'Despite the initial rapid progress, he found that breaking through a fitness plateau and achieving his target body fat percentage required both a rigorous diet and consistent resistance training.', '這句話使用了多個進階健身詞彙。''Fitness plateau'' 指的是健身過程中體能或體重停滯不前的『瓶頸期』，''break through'' 意為『突破』。''Body fat percentage'' 是『體脂率』的標準用法。''Rigorous'' 形容飲食控制非常嚴格且周密。''Resistance training'' 則是『阻力訓練』的專業說法。句首使用 ''Despite'' 引導名詞短語，結構符合 TOEIC 高分段對複合句的要求。', 'Despite + [Noun Phrase], [Subject] found that [Gerund Phrase] required [Noun Phrase].', '儘管最初進展迅速，但他發現要突破健身瓶頸並達到理想的體脂率，需要嚴格的飲食控制與持之以恆的阻力訓練。', 'Despite the initial rapid progress, he found that breaking through a fitness plateau and achieving his target body fat percentage required both a rigorous diet and consistent resistance training.', '["break through a plateau (突破瓶頸)", "body fat percentage (體脂率)", "resistance training (阻力訓練)", "rigorous diet (嚴格飲食)"]', 100, false, '2026-05-06 10:48:06.121032+08', '2026-05-07 08:39:21.992954+08');
INSERT INTO public.englishchat_question_bank VALUES (252, 'ai-toeic-coca-645001fa4bf2de9b', 'hospital', 'fill_blank', 'beginner', 'Please call the hospital to ____ an appointment with the doctor.', '["make", "do", "take"]', '[]', 'make', '在英文中，「預約」固定使用動詞 make，形成片語 make an appointment。do 或 take 在此語境下不符合慣用法。', 'make an appointment', '', '', '[]', 100, true, '2026-05-07 08:39:29.519916+08', '2026-05-07 08:39:29.519916+08');
INSERT INTO public.englishchat_question_bank VALUES (253, 'ai-toeic-coca-ff51ea940c2a772b', 'hospital', 'fill_blank', 'intermediate', 'Patients are advised to arrive at least fifteen minutes before their scheduled ____ to complete the necessary paperwork.', '["appointment", "treatment", "prescription", "admission"]', '[]', 'appointment', '此題測驗名詞字彙。''scheduled appointment'' 指的是『預約好的門診/面談』。在醫院或診所情境中，病人通常需要在預約時間前抵達以辦理報到或填寫相關文件。其他選項：treatment（治療）、prescription（處方）、admission（住院）雖然都與醫療相關，但與 scheduled 搭配並要求提前抵達填寫文件的最常見情境是 appointment。', 'scheduled appointment', '', '', '[]', 100, true, '2026-05-07 08:39:34.589962+08', '2026-05-07 08:39:34.589962+08');
INSERT INTO public.englishchat_question_bank VALUES (254, 'ai-toeic-coca-a9216469d5ec2d1d', 'hospital', 'fill_blank', 'advanced', 'In light of the recent surge in admissions, the hospital''s administrative board is considering a temporary ____ of elective surgeries to prioritize emergency care.', '["suspension", "consultation", "prescription", "observation"]', '[]', 'suspension', '這題考查名詞的語義與用法。''suspension'' 意為「暫停」或「中止」。句意為：鑑於最近住院人數激增，醫院行政委員會正考慮暫時中止非緊急（選擇性）手術，以優先處理急診護理。''In light of'' 是常見的正式用語，意為「鑑於」。其他選項：(B) consultation（諮詢/會診）、(C) prescription（處方）、(D) observation（觀察），皆不符合上下文邏輯。', 'In light of something, [subject] + [verb] + a temporary suspension of [activity].', '', '', '[]', 100, true, '2026-05-07 08:39:42.324685+08', '2026-05-07 08:39:42.324685+08');
INSERT INTO public.englishchat_question_bank VALUES (255, 'ai-toeic-coca-859ad105e712795f', 'hospital', 'reorder', 'beginner', 'Rearrange the following words to form a correct sentence.', '[]', '["wait", "the", "doctor", "Please", "for"]', 'Please wait for the doctor.', '這是一個簡單的祈使句，用來禮貌地請他人稍候。Please 置於句首，後接動詞原形 wait。wait for 是常見的動詞片語，表示『等待某人』。', 'Please + 動詞原形 (祈使句)', '請等候醫生。', 'Please wait for the doctor.', '["Please + V", "wait for someone"]', 100, true, '2026-05-07 08:39:52.380471+08', '2026-05-07 08:39:52.380471+08');
INSERT INTO public.englishchat_question_bank VALUES (256, 'ai-toeic-coca-9bf693cecfee7e7f', 'hospital', 'reorder', 'intermediate', 'Rearrange the following words to form a grammatically correct sentence about hospital discharge procedures.', '[]', '["to settle", "at the front desk", "before you leave", "Please make sure", "the bill"]', 'Please make sure to settle the bill at the front desk before you leave.', '這句話的意思是「在您離開之前，請務必到櫃檯結帳」。''Make sure to'' 是「確保/務必」的意思，後面接原形動詞；''settle the bill'' 是在醫院或飯店情境中常用的「結帳、付清款項」道地表達方式。', 'Make sure to + V (do something)', '', '', '[]', 100, true, '2026-05-07 08:39:57.76869+08', '2026-05-07 08:39:57.76869+08');
INSERT INTO public.englishchat_question_bank VALUES (166, 'ai-toeic-coca-5519e5a2bf63da0d', 'hospital', 'reorder', 'intermediate', 'Rearrange the words to form a natural sentence commonly heard at a hospital reception desk.', '[]', '["Please", "fill out", "these medical forms", "before the doctor", "sees you."]', 'Please fill out these medical forms before the doctor sees you.', '這句話常用於醫院櫃檯，提醒病患在看診前填寫相關表格。''fill out'' 是常見動詞片語，意為「填寫」；''medical forms'' 指「醫療表單」。此句型呈現了常見的祈使句加上時間副詞子句的結構。', 'Please + verb phrase + object + before + subject + verb', '請在醫生看診前填寫這些醫療表格。', 'Please fill out these medical forms before the doctor sees you.', '["fill out (填寫)", "medical forms (醫療表格)", "before the doctor sees you (在醫生見你之前)"]', 100, false, '2026-05-06 11:01:28.182365+08', '2026-05-07 08:39:57.817469+08');
INSERT INTO public.englishchat_question_bank VALUES (257, 'ai-toeic-coca-ba23ab6abdf5518d', 'hospital', 'reorder', 'advanced', 'Please arrange the following words/phrases to form a grammatically correct and meaningful sentence regarding hospital policy.', '[]', '["The hospital administration", "requires that", "all visiting hours", "be strictly adhered to", "in order to maintain", "a quiet environment", "for patient recovery"]', 'The hospital administration requires that all visiting hours be strictly adhered to in order to maintain a quiet environment for patient recovery.', '此句展示了進階語法中的虛擬語氣（Subjunctive Mood）。在表示要求、建議或命令的動詞（如 require, suggest, insist）之後的 that 子句中，助動詞 should 通常被省略，動詞必須使用原形（此處為 be strictly adhered to）。''Adhere to'' 是 COCA 高頻商務與法律用語，意為「遵守、堅持」。''In order to'' 用於表達目的。', 'Subject + require + that + Subject + (should) + be + p.p.', '', '', '[]', 100, true, '2026-05-07 08:40:05.138576+08', '2026-05-07 08:40:05.138576+08');
INSERT INTO public.englishchat_question_bank VALUES (258, 'ai-toeic-coca-faf5444cf4271fbe', 'hospital', 'translation', 'beginner', '', '[]', '[]', 'I need to see a doctor.', '這題的主詞是 I（我），動詞型態為現在式 need（需要）。關鍵片語 see a doctor 是英文中表達「看醫生」最自然、高頻的用法，注意 need 後方要接 to 加原形動詞。', 'S + need to + V', '我需要看醫生。', 'I need to see a doctor.', '["句型：S + need to + 原形動詞", "片語：see a doctor (看醫生)", "提示：need 是初級常用動詞，表示需要"]', 100, true, '2026-05-07 08:40:12.712281+08', '2026-05-07 08:40:12.712281+08');
INSERT INTO public.englishchat_question_bank VALUES (259, 'ai-toeic-coca-6afcb330da635ba4', 'hospital', 'translation', 'intermediate', '', '[]', '[]', 'To reduce waiting times, it is recommended that you make an appointment online before arriving at the hospital.', '本題測驗『為了...』的表達方式 (To + V) 以及『建議某人做某事』的虛擬語氣句型 (It is recommended that...)。在醫療情境中，reduce waiting times (減少等待時間) 與 make an appointment (預約掛號) 是極為常見且實用的商務及日常表達。', 'It is recommended that + S + (should) + V', '為了減少等待時間，建議您在到達醫院前先在網上預約掛號。', 'To reduce waiting times, it is recommended that you make an appointment online before arriving at the hospital.', '["To reduce...", "it is recommended that...", "make an appointment online"]', 100, true, '2026-05-07 08:40:18.26117+08', '2026-05-07 08:40:18.26117+08');
INSERT INTO public.englishchat_question_bank VALUES (169, 'ai-toeic-coca-89c630b006691e49', 'hospital', 'translation', 'intermediate', '', '[]', '[]', '', '句中「severely understaffed」指的是「嚴重的人手不足」，這是醫療與職場環境中常見的用法。「Due to」用來引導原因，是多益中常見的介係詞用法，用以連結名詞片語。', 'Subject + be + (adv.) + understaffed + due to + N.', '由於流感季節，這家醫院目前的人手嚴重不足。', 'The hospital is currently severely understaffed due to the flu season.', '["understaffed (adj.) 人手不足的", "due to (prep.) 由於", "flu season (n.) 流感季節"]', 100, false, '2026-05-06 11:01:50.289586+08', '2026-05-07 08:40:18.309708+08');
INSERT INTO public.englishchat_question_bank VALUES (260, 'ai-toeic-coca-d879ee0d42ec09b3', 'hospital', 'translation', 'advanced', '', '[]', '[]', '', '此句展現了進階醫療行政與法律情境的用語。「In compliance with」意指「遵守（法規、準則）」；「stipulate」是正式動詞，常用於合約或政策中表示「規定」；「explicit written consent」指「明確的書面同意」。這類正式句構與法律合規性詞彙常出現在 TOEIC 的規章說明或政策公告中。', 'In compliance with [regulations], [subject] stipulates that [action] is prohibited without [condition].', '為了遵守病患隱私規範，本院規定在未經當事人明確書面同意的情況下，嚴禁洩漏任何醫療記錄。', 'In compliance with patient privacy regulations, the hospital stipulates that disclosing any medical records is strictly prohibited without the explicit written consent of the individual concerned.', '["in compliance with (遵守/符合)", "stipulate that (規定/明訂)", "explicit written consent (明確的書面同意)"]', 100, true, '2026-05-07 08:40:26.597611+08', '2026-05-07 08:40:26.597611+08');
INSERT INTO public.englishchat_question_bank VALUES (170, 'ai-toeic-coca-07188b1e366bb39a', 'hospital', 'translation', 'advanced', '', '[]', '[]', 'In light of patient confidentiality, the hospital is prohibited from disclosing any medical records to third parties unless prior written consent has been obtained from the individual concerned.', '此題測驗高級醫療行政與法律相關詞彙。''In light of'' 為常見片語，意為「考量到」或「鑒於」。''Patient confidentiality''（病患隱私/保密）是醫療場景的核心術語。''Prohibit from + V-ing'' 表示「禁止做某事」。''Prior written consent''（事先書面同意）則是多益與商務法律文件中極高頻的固定搭配。最後，''the individual concerned'' 用來指代「相關當事人」。', 'In light of [Noun], [Subject] is prohibited from [V-ing] unless [Condition].', '考量到病患隱私，除非事先獲得當事人的書面同意，否則院方不得向第三方揭露任何醫療紀錄。', 'In light of patient confidentiality, the hospital is prohibited from disclosing any medical records to third parties unless prior written consent has been obtained from the individual concerned.', '["In light of (考量到/鑒於)", "patient confidentiality (病患隱私保密)", "prior written consent (事先書面同意)", "disclose... to third parties (向第三方揭露...)"]', 100, false, '2026-05-06 11:01:56.657789+08', '2026-05-07 08:40:26.645333+08');
INSERT INTO public.englishchat_question_bank VALUES (80, 'ai-toeic-coca-83742d0f5eab5780', 'hospital', 'translation', 'advanced', '', '[]', '[]', 'The hospital administration has implemented a stringent triage protocol to ensure that patients with life-threatening conditions receive immediate medical intervention, thereby optimizing overall clinical outcomes.', '此句包含多個多益高階與醫療行政詞彙：''stringent'' 表示嚴格的，常用於法規或協定；''triage protocol'' 為檢傷分類協定，是醫院標準用語；''medical intervention'' 指醫療干預或處置。後半部使用 ''thereby + V-ing'' 結構，表示「從而...」，是高階寫作中展現因果關係的常用句型。', 'Subject + has implemented + NP + to ensure that + clause, thereby + V-ing', '醫院管理部門已實施嚴格的檢傷分類協定，以確保患有危及生命病症的患者能獲得即時的醫療干預，從而優化整體的臨床成效。', 'The hospital administration has implemented a stringent triage protocol to ensure that patients with life-threatening conditions receive immediate medical intervention, thereby optimizing overall clinical outcomes.', '["stringent (adj.) 嚴格的/嚴厲的", "triage protocol (n.) 檢傷分類協定", "life-threatening conditions (n.) 危及生命的病症", "thereby optimizing (adv. + v-ing) 從而優化"]', 100, false, '2026-05-06 10:49:16.026676+08', '2026-05-07 08:40:26.645333+08');
INSERT INTO public.englishchat_question_bank VALUES (262, 'ai-toeic-coca-77cea7e686f415da', 'weather', 'fill_blank', 'intermediate', 'Due to the severe thunderstorm warning, the outdoor corporate event has been ____ until next Friday.', '["postponed", "cancelled", "remained", "scheduled"]', '[]', 'postponed', '根據句中 ''until next Friday''（直到下週五）可知，活動並非被取消，而是延後舉行。''Postpone'' 意為「延期」，在商務與日常情境中常用於因天氣因素改變行程。''Cancelled'' 為取消，通常不接 until 指向新日期；''Remained'' 為保持；''Scheduled'' 為預定，皆不符合此處被動語態且接續特定延期時間點的語意。', 'be postponed until + [時間點]', '', '', '[]', 100, true, '2026-05-07 08:40:40.303841+08', '2026-05-07 08:40:40.303841+08');
INSERT INTO public.englishchat_question_bank VALUES (263, 'ai-toeic-coca-4cc24f3f6d12ec4f', 'weather', 'fill_blank', 'advanced', 'Given the forecast for ____ weather conditions, the outdoor corporate gala has been rescheduled to next weekend to ensure the safety of all attendees.', '["inclement", "transient", "stagnant", "temperate"]', '[]', 'inclement', 'inclement 指天氣「惡劣的」，是 TOEIC 常見的高階正式字彙，常用於商務公告中描述強風、暴雨等不佳天候。此句意為：『鑑於預測會有惡劣的天候狀況，戶外公司晚會已改期至下週末，以確保所有與會者的安全。』其餘選項：(B) transient 轉瞬即逝的、(C) stagnant 停滯不前的、(D) temperate 溫和的，皆不符合語境。', 'Given the forecast for [Adjective] weather conditions', '', '', '[]', 100, true, '2026-05-07 08:40:46.558394+08', '2026-05-07 08:40:46.558394+08');
INSERT INTO public.englishchat_question_bank VALUES (264, 'ai-toeic-coca-cf5b1242046aaf32', 'weather', 'reorder', 'beginner', 'Please put the words in the correct order to describe the weather.', '[]', '["very", "hot", "is", "today", "It"]', 'It is very hot today.', '在英文中描述天氣時，習慣使用 ''It'' 作為主詞。本句結構為：主詞 (It) + be 動詞 (is) + 程度副詞 (very) + 形容詞 (hot) + 時間 (today)。', 'It is + adjective + (time).', '今天天氣非常熱。', '', '[]', 100, true, '2026-05-07 08:40:54.154644+08', '2026-05-07 08:40:54.154644+08');
INSERT INTO public.englishchat_question_bank VALUES (265, 'ai-toeic-coca-69de529146f96f9b', 'weather', 'reorder', 'intermediate', 'Rearrange the words below to form a logical sentence regarding a change in event plans due to weather conditions.', '[]', '["Due to", "the unpredictable weather,", "the outdoor company picnic", "has been", "rescheduled", "for next Friday"]', 'Due to the unpredictable weather, the outdoor company picnic has been rescheduled for next Friday.', '本題考查原因引導詞 ''Due to'' 的用法，後接名詞短語 ''the unpredictable weather''（不可預測的天氣）。主詞為 ''the outdoor company picnic''（戶外公司野餐），動詞部分採用現在完成式的被動語態 ''has been rescheduled''（已被重新安排），並搭配介系詞 ''for'' 來接新的時間點。', 'Due to + [Noun Phrase], [Subject] + has been + [Past Participle] + for [Time].', '', '', '[]', 100, true, '2026-05-07 08:41:02.269114+08', '2026-05-07 08:41:02.269114+08');
INSERT INTO public.englishchat_question_bank VALUES (266, 'ai-toeic-coca-195e514bc082f5a1', 'weather', 'reorder', 'advanced', 'Rearrange the segments to form a formal announcement regarding a schedule change due to weather conditions.', '[]', '["the outdoor corporate retreat", "until further notice", "forecasted for this weekend,", "Given the inclement weather conditions", "has been postponed"]', 'Given the inclement weather conditions forecasted for this weekend, the outdoor corporate retreat has been postponed until further notice.', '此句展示了商務英文中處理突發狀況的正式用法。''inclement weather'' 是形容天氣惡劣的高階詞彙；''Given'' 在句首作為介係詞，表示『考慮到』或『鑑於』；''postponed until further notice'' 則是多益常見片語，意為『無限期延期，直到另行通知』。', 'Given + [Noun Phrase], [Subject] + [Passive Verb] + [Prepositional Phrase].', '', '', '[]', 100, true, '2026-05-07 08:41:14.157966+08', '2026-05-07 08:41:14.157966+08');
INSERT INTO public.englishchat_question_bank VALUES (267, 'ai-toeic-coca-feff973f99c6db3e', 'weather', 'translation', 'beginner', '', '[]', '[]', '', '這句話使用 ''It will be'' 來預測未來的天氣。主詞使用虛主詞 ''It'' 指代天氣，動詞型態為助動詞 ''will'' 加上原形動詞 ''be''。關鍵字 ''jacket'' 指的是外套或夾克。', 'It will be + [adjective]', '今天下午天氣會變冷，所以請帶一件外套。', 'It will be cold this afternoon, so please bring a jacket.', '["句型：It will be + 形容詞 (表示天氣將會...)", "動詞片語：bring a jacket (帶一件外套)", "單字：cold (寒冷的)"]', 100, true, '2026-05-07 08:41:19.752948+08', '2026-05-07 08:41:19.752948+08');
INSERT INTO public.englishchat_question_bank VALUES (177, 'ai-toeic-coca-f880138a5ae78d2c', 'weather', 'translation', 'beginner', '今天的天氣怎麼樣？', '[]', '[]', 'How is the weather today?', '這句話的主詞是 the weather，動詞使用單數 be 動詞 is。關鍵字 weather（天氣）在英文中是不可數名詞，在此情境通常與定冠詞 the 連用。', 'How is the weather...?', '今天的天氣怎麼樣？', 'How is the weather today?', '["句型提示：How is + 名詞?", "關鍵動詞：is (be動詞單數型)", "單字提示：weather (天氣)"]', 100, false, '2026-05-06 11:02:59.231688+08', '2026-05-07 08:41:19.800544+08');
INSERT INTO public.englishchat_question_bank VALUES (268, 'ai-toeic-coca-0a9b38feb39ac0e0', 'weather', 'translation', 'intermediate', '', '[]', '[]', '', '此句測驗「由於」的表達方式（Due to）以及商務情境中常見的「延期」（postpone）。在多益中，天氣因素經常是導致行程或活動變動的原因。''Heavy rain'' 是描述大雨最道地的用法，而非 ''big rain''。', 'Due to + Noun Phrase, [Subject] + [Verb]...', '由於天氣預報預測會有強降雨，我們決定將戶外產品發表會延期。', 'Due to the weather forecast predicting heavy rain, we have decided to postpone the outdoor product launch.', '["Due to... (由於...)", "weather forecast (天氣預報)", "heavy rain (強降雨)", "postpone (延期)"]', 100, true, '2026-05-07 08:41:25.089796+08', '2026-05-07 08:41:25.089796+08');
INSERT INTO public.englishchat_question_bank VALUES (178, 'ai-toeic-coca-bd6dbe7fe31150c7', 'weather', 'translation', 'intermediate', '', '[]', '[]', '', '本題測驗多益常見的商務與交通情境。''Due to'' 是正式表達「由於」的方式，後接名詞短語；''high winds'' 是描述強風的標準說法；''until further notice'' 則是商務英文中極其常見的固定片語，意指「直到另行通知」。', 'Due to + noun phrase, [subject] + [verb]...', '由於預期會有強風，這班前往芝加哥的航班已被取消，直到另行通知。', 'Due to expected high winds, the flight to Chicago has been cancelled until further notice.', '["due to (由於)", "high winds (強風)", "until further notice (直到另行通知)"]', 100, false, '2026-05-06 11:03:08.684163+08', '2026-05-07 08:41:25.137898+08');
INSERT INTO public.englishchat_question_bank VALUES (269, 'ai-toeic-coca-ea5bfb3718859d9a', 'weather', 'translation', 'advanced', '', '[]', '[]', '', '本題測驗進階商務氣象詞彙與句型。''Given'' 在句首作為介係詞，表示『鑒於/考量到』；''adverse weather conditions'' 是 COCA 高頻正式用語，指『惡劣天氣』；''flash flooding'' 指『突發性洪水/暴雨洪災』；''postpone... until further notice'' 是多益常考片語，意為『延期直至另行通知』。', 'Given + [Noun Phrase], [Subject] + [Verb]...', '鑒於惡劣的天候狀況以及潛在的暴雨洪災，管理階層已決定將戶外企業員工旅遊延期，直至另行通知。', 'Given the adverse weather conditions and potential flash flooding, the management has decided to postpone the outdoor corporate retreat until further notice.', '["adverse weather conditions (惡劣天候)", "flash flooding (暴雨洪災)", "until further notice (直到另行通知)"]', 100, true, '2026-05-07 08:41:31.642879+08', '2026-05-07 08:41:31.642879+08');
INSERT INTO public.englishchat_question_bank VALUES (89, 'ai-toeic-coca-398b0d2d71b1e183', 'weather', 'translation', 'advanced', '', '[]', '[]', '', '此句使用了 ''inclement weather''（惡劣天氣）這一正式且常見於商務及氣象報告的詞彙。''Given'' 作為介係詞表示『鑑於』或『考量到』。''Corporate retreat'' 指的是公司的員工旅遊或研習營。''Postponed indefinitely'' 則是商務情境中常見的表達方式，意指『無限期延期』。', 'Given + N/phrase, [Subject] + [Passive Voice Verb] + indefinitely.', '鑑於週末惡劣的天氣預報，為了確保所有參與者的安全，戶外企業員工旅遊已無限期推遲。', 'Given the inclement weather forecast for the weekend, the outdoor corporate retreat has been postponed indefinitely to ensure the safety of all participants.', '["inclement weather (惡劣天氣)", "corporate retreat (企業員工旅遊/研習)", "postpone indefinitely (無限期延期)", "given (考量到/鑑於)"]', 100, false, '2026-05-06 10:50:34.369801+08', '2026-05-07 08:41:31.690139+08');
INSERT INTO public.englishchat_question_bank VALUES (270, 'ai-toeic-coca-1034b3ed1a4a5b20', 'self_intro', 'fill_blank', 'beginner', 'Nice to meet you. My ____ is John, and I am the new sales assistant.', '["name", "job", "city"]', '[]', 'name', '這是一句常用的自我介紹開場白。''My name is...'' 用來介紹自己的姓名。後方接 John（人名），因此空格應填入 ''name''。', 'My name is [Name].', '', '', '[]', 100, true, '2026-05-07 08:41:39.586143+08', '2026-05-07 08:41:39.586143+08');
INSERT INTO public.englishchat_question_bank VALUES (271, 'ai-toeic-coca-61b1842a2d80512e', 'self_intro', 'fill_blank', 'intermediate', 'I am really looking forward to ____ with all of you on this upcoming project.', '["collaborate", "collaborating", "collaboration", "collaborated"]', '[]', 'collaborating', '片語 ''look forward to''（期待）之後必須接動名詞 (V-ing) 或名詞。在此情境下，''collaborating'' 為動名詞，表示『合作』的動作。這是職場自我介紹中表達積極態度與熱忱的常用句型。', 'look forward to + V-ing/Noun', '', '', '[]', 100, true, '2026-05-07 08:41:44.331769+08', '2026-05-07 08:41:44.331769+08');
INSERT INTO public.englishchat_question_bank VALUES (272, 'ai-toeic-coca-7cbdf74af6484216', 'self_intro', 'fill_blank', 'advanced', 'Having spent over a decade in the fintech sector, I have developed a keen ability to ____ emerging market trends and translate them into actionable business strategies.', '["anticipate", "fabricate", "reiterate", "procrastinate"]', '[]', 'anticipate', '這題考查動詞與受詞的語意搭配。在專業自我介紹中，''anticipate emerging market trends'' 意為「預見新興市場趨勢」，與後文提到的將其轉化為「可執行的商業策略（actionable business strategies）」在邏輯上最為吻合。其他選項：fabricate (捏造)、reiterate (重申)、procrastinate (拖延) 均不符合語境。', 'have a keen ability to + V (具備做某事的敏銳能力)', '', '', '[]', 100, true, '2026-05-07 08:41:50.639487+08', '2026-05-07 08:41:50.639487+08');
INSERT INTO public.englishchat_question_bank VALUES (273, 'ai-toeic-coca-2b16d55d3d78ac5f', 'self_intro', 'reorder', 'beginner', 'Reorder the words to introduce where you work.', '[]', '["work", "department.", "the", "I", "sales", "in"]', 'I work in the sales department.', '這句話的意思是「我在業務部門工作」。在自我介紹時，可以使用『I work in the + 部門名稱』來向他人介紹自己的職務單位。', 'I work in the [department]', '', '', '[]', 100, true, '2026-05-07 08:41:59.13992+08', '2026-05-07 08:41:59.13992+08');
INSERT INTO public.englishchat_question_bank VALUES (274, 'ai-toeic-coca-c93f2ea0c6b79fc8', 'self_intro', 'reorder', 'intermediate', 'Rearrange the following words to create a professional sentence used to introduce your career background.', '[]', '["have been", "a marketing specialist", "I", "working as", "five years", "for over"]', 'I have been working as a marketing specialist for over five years.', '此句使用現在完成進行式 (have been + V-ing) 來描述從過去某個時間點開始，一直持續到現在的職業狀態。''work as'' 後接具體的職稱，而 ''for over'' 則用來表示「超過」一段時間。這是多益考試與商務社交場合中，介紹工作資歷最常用的句型之一。', 'I have been working as [job title] for [time period].', '我擔任行銷專員已經超過五年了。', 'I have been working as a marketing specialist for over five years.', '["現在完成進行式 (have been + V-ing)", "work as + 職位名稱", "for over + 時間長度"]', 100, true, '2026-05-07 08:42:06.30745+08', '2026-05-07 08:42:06.30745+08');
INSERT INTO public.englishchat_question_bank VALUES (275, 'ai-toeic-coca-2acbe8c2c264e474', 'self_intro', 'reorder', 'advanced', 'During the executive networking session, Mr. Henderson introduces himself by highlighting his unique expertise. Rearrange the following words to complete his statement: ''____________________________________________________________________''', '[]', '["Having spent over a decade", "in the fintech sector,", "I pride myself on", "my ability to bridge the gap", "between technical constraints", "and business objectives."]', 'Having spent over a decade in the fintech sector, I pride myself on my ability to bridge the gap between technical constraints and business objectives.', '這句話展示了高級的自我介紹技巧。''Having spent...'' 為分詞構句，用以簡潔地交代資深背景。''Pride oneself on'' 是高階商務表達，意為『以...自豪』。''Bridge the gap'' 是職場常用片語，指『彌合差距』或『協調』，在此指協調技術限制與業務目標，是高階管理職位中常見的實力描述。', 'Having + p.p. (分詞構句), Subject + pride oneself on + ability to...', '', '', '[]', 100, true, '2026-05-07 08:42:13.794491+08', '2026-05-07 08:42:13.794491+08');
INSERT INTO public.englishchat_question_bank VALUES (185, 'ai-toeic-coca-bfdb921db221d853', 'self_intro', 'reorder', 'advanced', 'Please reorder the following segments to form a professional self-introduction sentence that highlights leadership experience and value proposition.', '[]', '["several cross-functional initiatives,", "to leverage my expertise", "I am eager", "to drive growth for your organization.", "Having spearheaded", "in strategic planning"]', 'Having spearheaded several cross-functional initiatives, I am eager to leverage my expertise in strategic planning to drive growth for your organization.', '本句使用了完成分詞構句 ''Having spearheaded...'' 來表示過去已完成的成就，並作為背景引出後續的主句。''Spearhead'' 意為『帶領/帶頭』，是商務職場中非常強而有力的動詞。''Cross-functional'' 指『跨部門的』。''Leverage'' 是多益高頻單字，意為『利用/發揮』。''Drive growth'' 則是商務英文中常見的搭配詞，指『推動成長』。整句語氣積極且專業，展現出具備領導力且準備好貢獻價值的形象。', 'Having + p.p. (Participle Clause), [Subject] + [Verb] + to leverage [Noun] to [Verb].', '請重新排列下列片段，組成一句專業的自我介紹，強調領導經驗與價值主張。', 'Having spearheaded several cross-functional initiatives, I am eager to leverage my expertise in strategic planning to drive growth for your organization.', '["Having + p.p. (分詞構句表示先前經驗)", "leverage expertise (發揮/利用專業知識)", "drive growth (推動成長)"]', 100, false, '2026-05-06 11:04:06.309364+08', '2026-05-07 08:42:13.843002+08');
INSERT INTO public.englishchat_question_bank VALUES (95, 'ai-toeic-coca-aea75a588ca14c9c', 'self_intro', 'reorder', 'advanced', 'Rearrange the following segments to form a coherent and professional self-introduction sentence suitable for a senior-level networking event.', '[]', '["to leverage", "in the tech industry,", "I am looking", "in project management", "Having spent", "within your team.", "my expertise", "over a decade", "to drive innovation"]', 'Having spent over a decade in the tech industry, I am looking to leverage my expertise in project management to drive innovation within your team.', '此句使用了完成分詞構句（Having spent...）來開頭，這在正式場合中是交代背景資歷的高階表達方式。''Leverage''（利用、發揮優勢）與 ''Drive innovation''（推動創新）是 TOEIC 高階商務情境中極為常見且具專業感的動詞搭配。''Over a decade'' 則精確地描述了工作年資。', 'Having + past participle (background), S + be looking to + leverage (expertise) + to + verb (objective).', '請重組單字：在科技產業待了超過十年後，我正尋求利用我在專案管理方面的專業知識，來推動貴團隊的創新。', '', '[]', 100, false, '2026-05-06 10:51:37.51859+08', '2026-05-07 08:42:13.843002+08');
INSERT INTO public.englishchat_question_bank VALUES (276, 'ai-toeic-coca-a7146085f98c0f8d', 'self_intro', 'translation', 'beginner', '', '[]', '[]', 'Hello, my name is David, and I work for this company.', '這句話由兩個簡單句組成。主詞 ''I'' 搭配動詞 ''work''。在英文中，表達「在某公司工作」最常用 ''work for'' 或 ''work at''。這是一個非常實用的初級自我介紹句型。', 'I work for + [company name]', '你好，我叫 David，我在這家公司工作。', 'Hello, my name is David, and I work for this company.', '["句型：My name is [name]", "動詞片語：work for (在...工作)", "單字：company (公司)"]', 100, true, '2026-05-07 08:42:20.882093+08', '2026-05-07 08:42:20.882093+08');
INSERT INTO public.englishchat_question_bank VALUES (277, 'ai-toeic-coca-39f29633b5d11396', 'self_intro', 'translation', 'intermediate', '', '[]', '[]', 'I am honored to join the team and look forward to working closely with all of you on future projects.', '這句話常用於新進員工的自我介紹。''be honored to'' 表示「很榮幸能...」，''look forward to'' 後面接動名詞 (V-ing)，表示「期待...」，''work closely with'' 則是職場常見片語，意指「密切合作」。', 'be honored to + V / look forward to + V-ing', '我很榮幸能加入這個團隊，並期待在未來的專案中與大家密切合作。', 'I am honored to join the team and look forward to working closely with all of you on future projects.', '["be honored to (很榮幸...)", "look forward to + V-ing (期待...)", "work closely with (與...密切合作)"]', 100, true, '2026-05-07 08:42:26.785409+08', '2026-05-07 08:42:26.785409+08');
INSERT INTO public.englishchat_question_bank VALUES (278, 'ai-toeic-coca-8d4171151a992ff8', 'self_intro', 'translation', 'advanced', '', '[]', '[]', 'With a solid background of over a decade in data analytics, I specialize in translating complex datasets into forward-looking strategic insights that optimize business performance.', '這是一個典型的進階職場自我介紹句型。''With a solid background of...'' 用於強調資歷的紮實程度；''specialize in'' 後接動名詞，說明核心專業；''translate... into...'' 在商業語境中常用於描述將抽象資料轉化為具體行動或見解；''forward-looking'' (前瞻性的) 與 ''strategic insights'' (策略建議/洞察) 是 COCA 高頻且具備專業感的詞彙。', 'With a solid background in [Field], I specialize in [Action] to [Outcome].', '憑藉在數據分析領域超過十年的深厚背景，我擅長將複雜的數據集轉化為具備前瞻性的策略建議，從而優化業務績效。', 'With a solid background of over a decade in data analytics, I specialize in translating complex datasets into forward-looking strategic insights that optimize business performance.', '["With a solid background of... (具備...的深厚背景)", "specialize in + V-ing (專精於...)", "translate... into... (將...轉化為...)", "forward-looking strategic insights (具前瞻性的策略建議)"]', 100, true, '2026-05-07 08:42:33.718929+08', '2026-05-07 08:42:33.718929+08');
